INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Joana","last_name":"Orlindo","nickname":"Joana","email":"Joanaorlindoescola@gmail.com","phone":"937550940","age":"18-24","gender":"Female","nationality":"Portuguese","country_of_residence":"Portugal","languages":"English, Spanish, Portuguese","current_occupation":"Student","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Technical Scuba diving","Freediving","Snorkeling"],"certification_level":"Open Water, Advanced Open Water","number_of_dives":"0-50","last_dive_date":"02.04.2026","diving_environments":["Tropical Reefs"],"buoyancy_skill":8,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)"],"filming_equipment":"Dji action 6\n2x Leton power sealion 12000\nInon gr140 wide lens","planning_to_invest":"Yes, within the near future","years_experience":"Less than 1 year","skill_camera_settings":7,"skill_lighting":7,"skill_post_production":7,"skill_color_correction":7,"skill_storytelling":7,"skill_drone":7,"skill_over_water":8,"content_created":["Personal vacation videos","Scientific/Research documentation"],"btm_category":"OCEAN STEWARD (NGO/scientific focus, conservation-driven)","involvement_level":"Conservation/Scientific work","online_presence":"None of the above","income_from_filming":"No, not yet.","primary_goal":"Transform hobby into professional career","secondary_goal":"Document marine conservation/research","learning_aspects":["Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Documentary style films","Scientific/research documentation","Conservation stories"],"learning_approach":["Group workshops (within a group of approx. 10 persons)","Small group workshop (within a group of approx. 4 persons)","Project-based learning (within a BTM project)"],"marine_subjects":["Big marine life (sharks, whales, etc.)","Marine behavior","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","budget":"Small budget (under 1,000 €/USD)","start_timeline":"Within next 3 months","ultimate_vision":"I have so many documentaries that i dream to create.\nIm Starting Now but im gonna go far,this is What i see when i go to sleep,the amount of amazing things i can capture and create stories that bring awareness about the current issues the marine life is going trought","inspiration_to_apply":"Its a dream of mine since was a little girl,cant even explain its someting you just feel,i want to be the voice of the ocean,the ocean is screaming at us and nobody seems to care.\nIt needs our help and it has so much to teach us.","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"What is the price of the program?"}'::jsonb, '{}', '[]'::jsonb, '2026-04-02T17:30:30+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Jonas","last_name":"Hofses","email":"jonas@firedev.tech","phone":"+4915201326406","age":"18-24","gender":"Male","nationality":"German","country_of_residence":"Lüneburg","languages":"English, German","current_occupation":"Software engineer","physical_fitness":"Average - Some physical activity, manageable health conditions","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving"],"certification_level":"Advanced Open Water, Rescue Diver","number_of_dives":"51-250","last_dive_date":"05.12.2025","diving_environments":["Tropical Reefs","Night diving"],"buoyancy_skill":5,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","Professional video camera"],"filming_equipment":"Osmo Action 5 Pro, Want to Buy an housing for my sony a7 iv","planning_to_invest":"Yes, within the near future","years_experience":"1-3 years","skill_camera_settings":6,"skill_lighting":1,"skill_post_production":5,"skill_color_correction":4,"skill_storytelling":3,"skill_drone":2,"skill_over_water":7,"content_created":["Personal vacation videos","Social media content"],"btm_category":"INDEPENDENT CREATOR (Experienced hobbyist/influencer seeking improvement)","involvement_level":"Hobby only","online_presence":"Active social media, Personal website","income_from_filming":"No, not yet.","primary_goal":"Transform hobby into professional career","secondary_goal":"Document marine conservation/research","learning_aspects":["Basic equipment setup and operation","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Personal/travel memories","Social media content","Documentary style films","Scientific/research documentation","Conservation stories"],"learning_approach":["Group workshops (within a group of approx. 10 persons)","Small group workshop (within a group of approx. 4 persons)","Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Marine behavior","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","budget":"Advanced budget (3,000 - 6,000 €/USD)","start_timeline":"Within next 3 months","ultimate_vision":"Show people the beatiness of the underwater world","inspiration_to_apply":"Saw you on YouTube","referral_source":["Social Media (Instagram, Facebook, etc.)"]}'::jsonb, '{}', '[]'::jsonb, '2026-04-02T12:18:19+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Rosa","last_name":"Tuiran","nickname":"Rosa","email":"tuiran.ra@gmail.com","phone":"+19172164365","age":"35-44","gender":"Female","nationality":"Mexico/United States","country_of_residence":"United States","languages":"English, Spanish, French","current_occupation":"Journalist/Producer/Filmmaker","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving"],"certification_level":"Divemaster","number_of_dives":"51-250","last_dive_date":"26.01.2026","diving_environments":["Tropical Reefs","Cold water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":8,"equipment_owned":["DSLR/Mirrorless with housing"],"filming_equipment":"Sony A7siii with Nauticam Housing, 90mm Lens w/Macro port, Sony FE 28-60mm f/4-5.6 Lens Nauticam WWL-1B Wet Wide Lens, strobes and video lights","planning_to_invest":"No immediate plans","years_experience":"Less than 1 year","skill_camera_settings":5,"skill_lighting":3,"skill_post_production":7,"skill_color_correction":3,"skill_storytelling":9,"skill_drone":2,"skill_over_water":7,"content_created":["Personal vacation videos","Scientific/Research documentation"],"btm_category":"ASPIRING PROFESSIONAL (Part-time professional aiming for full-time career)","involvement_level":"I am a filmmaker and journalist and do underwater storytelling but I don''t film the stories myself, just a couple. Mostly it is a hobby that I am trying to make into a career.","online_presence":"Personal website","online_links":"@rosaamandatuiran (instagram) www.rosaamandatuiran.com (website)","income_from_filming":"No, not yet.","primary_goal":"Transform hobby into professional career","secondary_goal":"Document marine conservation/research","learning_aspects":["Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Documentary style films","Commercial/advertising content","Scientific/research documentation","Conservation stories"],"learning_approach":["Small group workshop (within a group of approx. 4 persons)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","budget":"Moderate budget (1,000 - 3,000 €/USD)","start_timeline":"Ready to start immediately","ultimate_vision":"My vision is to direct and film short films and work with outlets like PBS Nature, the BBC Natural History Unit, National Geographic, The New York Times, etc, or emerging platforms where I can pitch, film, and produce stories about the intersection of people and the ocean. \n\nI also want to build a career as a freelance underwater cinematographer and photographer, with a particular focus on elevating stories from Mexico and Latin America and supporting Spanish-speaking filmmakers trying to find their footing in this space.\n\nAt the heart of it all is the ocean, the animals that inhabit it, and the relationship between people and the sea. My goal is to produce visually incredible work that communicates the urgent need for ocean conservation while showing how we are all connected to it. The ocean gave me my sense of purpose as a storyteller and I think this program would help me build the skills to continue to pursue it.","inspiration_to_apply":"As a filmmaker and journalist, I’ve learned that storytelling is one of the most powerful tools we have to connect people to places, ideas, and information. \n\nMy journey as a journalist began in the ocean. I remember being underwater for the first time when all of a sudden it all clicked for me. In that moment, I realized the immense privilege of experiencing a world so few ever get to see and how this incredible world needed to be seen, appreciated and protected. And from acknowledging that privilege, I’ve brought my passion to shine a light on the ocean and the people who depend on it. \n\nTo so many, the ocean is a distant, almost otherworldly place, a place that hides its most fascinating stories beneath. The ocean is our nourishment, protection, livelihood, and the air we breathe. \n\nAfter graduating from my bachelors degree, I pursued my passion for underwater photography in South Africa where I learned how to photograph marine life. Capturing marine life taught me not only about its beauty but also its vulnerability. Later, as a graduate student at UC Berkeley Graduate School of Journalism, I focused my work on ocean conservation, covering everything from sustainable fishing practices in the Bay Area to following a group of women in the Philippines working to protect a marine protected area on the island of Siquijor. Since then, I’ve reported and produced short digital films for different outlets but never been able to film them underwater. \n\nLast year, I was able to buy my underwater housing but I feel I still need better skills, learn the business side of things, how to really make a niche for myself and the stories I produce. I feel like its a world where its hard to access and the skills required are extremely important, so I would value the time and space to practice those skills, in an out of the water with mentors in the industry.","referral_source":["Word of mouth"],"questions_or_concerns":"What does a typical day or week of training look like, and how is the balance structured between in the water and out of the water (classroom/technical instruction?) \nAre there opportunities to build a portfolio or produce work during the program? \nWhat happens after the program is over?"}'::jsonb, '{}', '[]'::jsonb, '2026-03-25T18:45:42+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Tatiana","last_name":"McCabe","nickname":"Tati","email":"tatiana.mccabe@gmail.com","phone":"+1-718-710-8872","age":"35-44","gender":"Female","nationality":"USA / PANAMA","country_of_residence":"UK","languages":"English, Spanish","current_occupation":"Freelance filmmaker","physical_fitness":"Good - Moderately active, no major health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Advanced Open Water","number_of_dives":"51-250","last_dive_date":"20.01.2026","diving_environments":["Tropical Reefs","Cold water"],"buoyancy_skill":7,"equipment_owned":["DSLR/Mirrorless with housing"],"filming_equipment":"Sony A7SIII with Nauticam Housing and Ninja V Atomos monitor with Nauticam housing","planning_to_invest":"No immediate plans","years_experience":"1-3 years","skill_camera_settings":7,"skill_lighting":5,"skill_post_production":6,"skill_color_correction":6,"skill_storytelling":9,"skill_drone":6,"skill_over_water":8,"content_created":["Documentary style"],"btm_category":"ASPIRING PROFESSIONAL (Part-time professional aiming for full-time career)","involvement_level":"Hobby only","online_presence":"Active social media, Personal website","online_links":"https://www.instagram.com/tatianamccabe/\n\nRough draft of an underwater reel: https://vimeo.com/966143514?share=copy&fl=sv&fe=ci\n\nAnimation/Documentary work:  https://secondheart.tv/","income_from_filming":"No, not yet.","primary_goal":"Document marine conservation/research","secondary_goal":"Transform hobby into professional career","learning_aspects":["Basic equipment setup and operation","Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Documentary style films"],"learning_approach":["Small group workshop (within a group of approx. 4 persons)","One-on-one mentorship","Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Big marine life (sharks, whales, etc.)","Marine behavior","Conservation stories"],"time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Yes, willing to travel internationally","budget":"Moderate budget (1,000 - 3,000 €/USD)","start_timeline":"Flexible/Not sure yet","ultimate_vision":"I''d like to be more confident operating the camera settings UW and how to move better with big rigs in the water.","inspiration_to_apply":"This was my first ever attempt to make a short film that included filming underwater and I thought it came out quite nicely, so have been inspired to keep going. I do love filming underwater but doing it beyond a hobby is also intimidating. I''m eager to meet like minded UW filmmakers and think BTM Academy might be a good starting point. \n\nhttps://vimeo.com/secondheart/insearchofgiants?share=copy&fl=sv&fe=ci","referral_source":["My friend David Serradell has worked with BTM."],"questions_or_concerns":"I''m curious to know how the courses are structured. Are they done on liveaboard trips? or are any land based anywhere in the world?","anything_else":"I won an Academy Award last year =) (best student documentary!) I''d like to share it with you: https://vimeo.com/secondheart/tidesoflife?share=copy&fl=sv&fe=ci"}'::jsonb, '{}', '[]'::jsonb, '2026-03-25T07:29:41+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Logan","last_name":"Schmideler","nickname":"Logs/Lou/any word staring with L","email":"loganschmideler@gmail.com","phone":"407-925-3269","age":"18-24","gender":"Male","nationality":"American","country_of_residence":"United States","languages":"English, Learning Sign Language","current_occupation":"Video Editor","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Freediving","Snorkeling","Neither","but interested in learning"],"certification_level":"No certification yet","number_of_dives":"0-50","last_dive_date":"13.03.2026","diving_environments":["Cold water","Cave/Wreck diving"],"buoyancy_skill":10,"equipment_owned":["No equipment yet"],"filming_equipment":"N/a","planning_to_invest":"Yes, within the near future","years_experience":"None","skill_camera_settings":10,"skill_lighting":1,"skill_post_production":10,"skill_color_correction":10,"skill_storytelling":10,"skill_drone":7,"skill_over_water":5,"content_created":["None yet","excited to start"],"btm_category":"BEGINNER - Creative Explorer (Just starting, hobby-focused, seeking basic skills)","involvement_level":"Complete beginner","online_presence":"Active social media, Professional portfolio","online_links":"Portfolio: https://www.behance.net/loganschmideler\n\nYoutube: https://youtube.com/@loganfilms?si=dYl33dUA6_iTXWoC\n\nLinkedIn: https://www.linkedin.com/in/logan-schmideler","income_from_filming":"No, not yet.","primary_goal":"Document marine conservation/research","secondary_goal":"Learn basics of underwater filming as a hobby","learning_aspects":["Basic equipment setup and operation","Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Documentary style films","Commercial/advertising content","Scientific/research documentation","Conservation stories","I have experience in videography","editing","producing","and some conditioned reptile + mammal photography and handling (alligators, crocodiles, capybaras, small snakes, some dolphin) + high-speed photography and marine sport videography/documentary work."],"learning_approach":["Group workshops (within a group of approx. 10 persons)","Small group workshop (within a group of approx. 4 persons)","One-on-one mentorship","Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)","Primarily project-based"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories","Marine life > Macro > Conservation > Marine Behavior > Reefs"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","budget":"Advanced budget (3,000 - 6,000 €/USD)","start_timeline":"Within next 3 months","ultimate_vision":"I am just starting out, but have a strong interest in cetaceans, sharks/rays, and seals, most prominently type D killer whale inbreeding/behavior and dwarf Minke behavior.","inspiration_to_apply":"I learned about BTM on Instagram, but I have always wanted to travel below the surface to capture nature in its most raw and unforgiving domain. It is one of the last frontiers on the planet, and one I hope remains that way. Still, I can''t help but want to document even a small portion of it for greater human understanding. I grew up in Florida and was present for the rise and fall of captive killer whales, and I want to see these animals thrive in the wild, free from human intervention.","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"N/a","anything_else":"I hold a Boating Safety ID card to operate motorboats with 10+ horsepower.\n\nReptile and mammal handling experience is with alligators, crocodiles, snakes, capybaras, and some dolphin experience."}'::jsonb, '{}', '[]'::jsonb, '2026-03-25T07:14:34+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Antony","last_name":"Pieters","nickname":"Tony","email":"antony.pieters@imbrsea.eu","phone":"32471848228","age":"25-34","gender":"Male","nationality":"Belgian","country_of_residence":"Belgium","languages":"English, French, Dutch","current_occupation":"Marine mammal researcher","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving"],"certification_level":"Open Water","number_of_dives":"0-50","last_dive_date":"15.09.2025","diving_environments":["Cold water"],"buoyancy_skill":5,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","Compact camera with housing","DSLR/Mirrorless with housing"],"filming_equipment":"GoPro Hero 12, I still want to get a underwater housing for my sony a6700 but financially not able to do so yet","planning_to_invest":"Yes, within the next years","years_experience":"Less than 1 year","skill_camera_settings":9,"skill_lighting":2,"skill_post_production":8,"skill_color_correction":8,"skill_storytelling":8,"skill_drone":7,"skill_over_water":8,"content_created":["Documentary style","Scientific/Research documentation"],"btm_category":"OCEAN STEWARD (NGO/scientific focus, conservation-driven)","involvement_level":"Conservation/Scientific work","online_presence":"Active social media, None of the above","online_links":"https://www.youtube.com/watch?v=pz3k9oTfhPY&feature=youtu.be \n- This was my first science communication project, where I filmed, edited, and wrote a documentary aimed at taking my first steps into wildlife filmmaking focused on translating science for a broader audience.\n\nhttps://youtu.be/aT3Lx5ZQIJc\n- This is a short 3 min highlight reel of the documentary","income_from_filming":"No, not yet.","primary_goal":"Document marine conservation/research","secondary_goal":"Transform hobby into professional career","learning_aspects":["Camera settings and techniques","Marine life behavior understanding","Storytelling and content planning","Conservation documentation"],"content_to_create":["Scientific/research documentation","Conservation stories"],"learning_approach":["Mixed approach (combination of group and individual)"],"marine_subjects":["Big marine life (sharks, whales, etc.)","marine mammal culture"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Depends on duration and location","budget":"Small budget (under 1,000 €/USD)","start_timeline":"Flexible/Not sure yet","ultimate_vision":"As a behavioral ecologist studying cetaceans, I want to futher implement filmmaking and storytelling as a tool to showcase  the complex and the fascinating social and foraging behavior of marine mammals. I aim to capture the social transmission of culture and how it can provide resilience to rapid, human-driven environmental change.  By highlighting the parallels between humans and these charismatic animals, I also hope to reconnect audiences with them and promote human–wildlife coexistence.","inspiration_to_apply":"It offers a rare glimpse into a hidden world, creating a powerful and emotional connection between marine life and us terrestrial humans. Through my own work, I have experienced how underwater footage can reveal new perspectives and insights, particularly from a scientific point of view. \n\nThe first BTM video I watched was the sardine run. The rapid succession of dynamic shots capturing the interdependent communities surrounding the bait ball perfectly conveyed what it truly feels like to witness such an event. It transported me into that moment underwater. The professionalism, thoughtful shot selection, and the genuine joy and passion of the people involved inspired me and further motivated me to apply to the BTM Academy","referral_source":["Word of mouth"],"questions_or_concerns":"I understand that finances can sometimes limit opportunities and interfere with the creative work we hope to share with others. As an early career researcher, I currently do not have the funds required for long voyages to remote locations.  If accepted to the academy, I will of course do everything I can to make it on site. However, if that isn''t possible, I was wondering whether there might be opportunities to still learn remotely through webinars or other online sessions.","anything_else":"Coming from two generations of professional photographers, I grew up surrounded by cameras and have been filming, editing, and color grading for over eight years. I gradually began incorporating these skills into my work as a tool for scientific communication, building a solid foundation that I aim to continue developing.\n\nI would also like to address my limited diving experience. However, I hope this will not interfere too much with my chances of participating in the academy, as I am fully willing to take all the necessary lessons and training to furhter improve these skills."}'::jsonb, '{}', '[]'::jsonb, '2026-03-24T17:00:42+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Kasi Viswanadh","last_name":"Palli","email":"viswanadhpalli143@gmail.com","phone":"+91 9391814234","age":"25-34","gender":"Male","nationality":"India","country_of_residence":"India","languages":"English, Telugu","current_occupation":"Marine Naturalist Photographer and storyteller","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Technical Scuba diving","Rebreather diving","Snorkeling"],"certification_level":"Rescue Diver","number_of_dives":"0-50","last_dive_date":"10.03.2025","diving_environments":["Tropical Reefs","Cold water","Deep diving","Cave/Wreck diving"],"buoyancy_skill":8,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","DSLR/Mirrorless with housing"],"filming_equipment":"Sony alpha 6000 16mm-50mm","planning_to_invest":"Yes, within the near future","years_experience":"3-5 years","skill_camera_settings":10,"skill_lighting":10,"skill_post_production":7,"skill_color_correction":10,"skill_storytelling":10,"skill_drone":8,"skill_over_water":10,"content_created":["Documentary style"],"btm_category":"ASPIRING PROFESSIONAL (Part-time professional aiming for full-time career)","involvement_level":"Full-time professional","online_presence":"Professional portfolio","online_links":"https://drive.google.com/drive/folders/14XrnCxX5wjYJR7k3OXHhhfDNkBcTim84","income_from_filming":"No, not yet.","primary_goal":"Enhance existing professional skills","secondary_goal":"Document marine conservation/research","learning_aspects":["Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Documentary style films","Commercial/advertising content","Scientific/research documentation","Conservation stories"],"learning_approach":["Group workshops (within a group of approx. 10 persons)","Small group workshop (within a group of approx. 4 persons)","One-on-one mentorship","Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","budget":"Very limited budget. I basically have no financial means to be spent on this.","start_timeline":"Ready to start immediately","ultimate_vision":"I wanna explore ocean and raise awareness about ocean and it''s vital role in our lives","inspiration_to_apply":"Giving opportunities to passionate people and helping aspirants to develop skills","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"No","anything_else":"I financially poor to improve my equipment and Diving\nIn India no opportunities for me, please give me a chance to explore ocean \nProvide Food, Accommodation, Medical and Travel expenses, I will work freely no need pay, until you want to pay me i will not ask money.\n Thank you"}'::jsonb, '{}', '[]'::jsonb, '2026-03-17T10:42:05+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Ibrahim","last_name":"Rafhaan","nickname":"Raphh","email":"rappe982@gmail.com","phone":"+960 9825917","age":"18-24","gender":"Male","nationality":"Maldivian","country_of_residence":"- adh maamigili southariatoll maldives","languages":"English","current_occupation":"Dive master (the standard huruvalhi raa atoll maldives","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving"],"certification_level":"Divemaster","number_of_dives":"250+","last_dive_date":"12.03.2026","diving_environments":["Tropical Reefs","Night diving","Cave/Wreck diving"],"buoyancy_skill":7,"equipment_owned":["DSLR/Mirrorless with housing"],"filming_equipment":"Sony fx3 with 16-35 f2. 8 Gm2 lens/ seafrog aluminum alloy housing with 10inch domeport /xtar d3500 4000 lm lights","planning_to_invest":"No immediate plans","years_experience":"1-3 years","skill_camera_settings":2,"skill_lighting":2,"skill_post_production":3,"skill_color_correction":3,"skill_storytelling":2,"skill_drone":1,"skill_over_water":1,"content_created":["Personal vacation videos","Social media content","Documentary style","Commercial work"],"btm_category":"ASPIRING PROFESSIONAL (Part-time professional aiming for full-time career)","involvement_level":"Hobby only","online_presence":"Active social media","online_links":"https://www.instagram.com/raphh.mv?igsh=eHZjcHJhZnNiNzM1","income_from_filming":"No, not yet.","primary_goal":"Enhance existing professional skills","secondary_goal":"Document marine conservation/research","learning_aspects":["Basic equipment setup and operation","Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Documentary style films","Scientific/research documentation","Conservation stories"],"learning_approach":["Group workshops (within a group of approx. 10 persons)","Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories"],"time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Yes, but within my region only","budget":"Small budget (under 1,000 €/USD)","start_timeline":"Within next 3 months","ultimate_vision":"Hi, my name is Raphh. I am from an island called Maamigili in the Maldives, located in South Ari Atoll, which is known as one of the homes of whale sharks.\nMy passion for the ocean, underwater wildlife, and scuba diving began through my uncle, who has been a scuba instructor for many years. Watching him and hearing his stories made me curious about the underwater world and inspired me to explore it myself.\nI still remember a moment from my childhood that changed my life. My mom was having a hard time feeding me, and my grandpa turned on Nat Geo TV. The moment I saw the underwater scenery on the screen, I was completely amazed. Even as a child, I remember thinking that the person who captured those shots must be a genius. From that moment, I wanted to create those kinds of images and videos and share them with the world, so people could see the beauty of the underwater environment, fall in love with it, and help protect these fragile ecosystems.\nLater, I saw someone using underwater camera equipment with a scuba tank that allowed him to stay underwater for hours. Seeing that made me even more fascinated by scuba diving and underwater videography.\nThe person who truly inspired me to start diving was my uncle and instructor naseem. When I was very young, he used to bring beautiful photographs of sea fans and hang them on the walls as decorations. I would stare at those photographs for hours. From that moment on, I knew that I wanted to try scuba diving.\nI got the opportunity to try my first Discover Scuba Diving experience when I was around 13 years old at a nearby resort, which is currently called Villa Haven, under Dive Oceanus. The day I took my first breath underwater truly changed my life.\nAs soon as I returned to my island, I met my uncle and told him that I didn’t even want to continue studying—I wanted to start diving immediately. He smiled and told me, “Finish your school first, and then come to my dive center. I will make it happen.” At that time, he was running his own dive center on our island.\nI remember asking my dad to buy me an underwater camera because I saw the GoPro coming out, and I was already passionate about underwater videography. Since it was too expensive for us at the time, my dad bought me a small action camera called Apeman. Even though it was simple, it meant the world to me.\nThe day I finished school, I called my uncle and told him that I was ready. He told me to join the dive center the next day. I was around 15–16 years old when I joined Shamar Guesthouse and Dive.\nAt the dive center, I worked in many roles: receptionist, room boy, waiter, compressor boy, and almost every job related to running a guesthouse and dive center—except guiding certified divers. Eventually, I was allowed to start my Open Water course, which deepened my connection with the ocean.\nMy instructor at the time would not allow me to dive unless I worked very hard. If I wanted to dive, I had to earn it through hard work. During this time, I also saw many divers with large professional camera setups, which pushed me even more toward underwater filmmaking.\nUnfortunately, I had to take a break because of back problems. The doctor advised me to avoid lifting heavy equipment so that my back could recover properly. At the same time, like many teenagers, I had many ambitions in my mind, but half of my heart was always dedicated to my dream of becoming an underwater wildlife filmmaker.\nDuring that period, I worked in many different jobs: as an artist, in local shops, as a delivery boy, an IT technician, and a graphic designer. But even then, I continued diving every weekend—sometimes 4 to 5 dives per week.\nEventually, I decided to pursue my Divemaster certification. To be honest, I did not start diving with the goal of becoming like most instructors. My goal was to invest in my gear, travel, learn, and document the underwater world.\nWhile working at my island’s airport as a graphic designer and IT technician, I saved money to buy my first proper gear: a GoPro Hero 10, lights, dome ports, and other accessories. From there, I began to dive deeper into the world of underwater videography, constantly experimenting and learning.\nI continued diving as an Advanced Nitrox Diver, focusing on improving my filming skills while minding my own work.\nA few years later, after completing my Divemaster, I moved away from my home island to pursue my dream. Slowly, I saved money for my dream camera setup, and a few months ago, I finally managed to buy it.\nMy dream is to become an underwater wildlife cinematographer—to work, travel, inspire people, and spread awareness about the beauty and importance of our oceans. I want to film in extreme environments alongside experienced professionals around the world.\nOne of my biggest dreams is to document the underwater life of the entire Maldives—from the far north to the deep south—and publish it on my own YouTube channel.\nIt is also my dream to one day participate in major documentary productions such as Blue Planet, Ocean with David Attenborough, or Our Oceans.\nAnother important goal for me is to raise awareness among Maldivians, encouraging people to stop damaging our fragile marine environment through human activities. Through my lens, I hope to inspire people to protect and respect the underwater world that surrounds us","inspiration_to_apply":"Since i started to research about underwater filming i use to watch videos of behind the mask  from YouTube. And few days ago i was asking some questions to venisa. She recommended me to join behind the mask academy which is goin to help me to improve my skills. And its always a dream to gain experience from a team  such as behind the mask.","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"Currently working as a dive master which is goin to be a little difficult to get my leave. Which i couldn''t join the last workshop with scubaspa. I would appreciate to know in advanced if conducting a workshop in the maldives with next 3 months or further. To be added i am planning to get my instructor in September.","anything_else":"I would be so grateful if you are goin to conduct and underwater filmaking workshop in the maldives. It is really goin to help me to achieve my goals and to learn about the field."}'::jsonb, '{}', '[]'::jsonb, '2026-03-15T16:30:31+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Mohamed","last_name":"Azmey","nickname":"Azmey","email":"mohamedazmey307@gmail.com","phone":"+971585226889","age":"35-44","gender":"Male","nationality":"Egypt","country_of_residence":"United Arab Emirates","languages":"English, Arabic","current_occupation":"IT project manager","physical_fitness":"Good - Moderately active, no major health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving"],"certification_level":"Open Water, Advanced Open Water, Rescue Diver, Divemaster","number_of_dives":"250+","last_dive_date":"27.02.2026","diving_environments":["Tropical Reefs","Deep diving","Night diving"],"buoyancy_skill":9,"equipment_owned":["DSLR/Mirrorless with housing"],"filming_equipment":"Canon R5II , 14-35 mm lens , 24-105mm lens, 100mm lens","planning_to_invest":"No immediate plans","years_experience":"1-3 years","skill_camera_settings":5,"skill_lighting":6,"skill_post_production":5,"skill_color_correction":5,"skill_storytelling":5,"skill_drone":1,"skill_over_water":2,"content_created":["Social media content","Documentary style","Commercial work"],"btm_category":"INDEPENDENT CREATOR (Experienced hobbyist/influencer seeking improvement)","involvement_level":"Hobby only","online_presence":"Active social media","online_links":"https://www.instagram.com/moh_azmey?igsh=amZ0dWIwMmVvOXF0&utm_source=qr","income_from_filming":"Occasionally (few projects per year)","primary_goal":"Improve content creation for social media","secondary_goal":"Transform hobby into professional career","learning_aspects":["Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Business aspects of underwater filming","Client relations and project management"],"content_to_create":["Social media content","Documentary style films","Commercial/advertising content","Scientific/research documentation","Conservation stories"],"learning_approach":["Group workshops (within a group of approx. 10 persons)","Small group workshop (within a group of approx. 4 persons)","One-on-one mentorship","Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories"],"time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Depends on duration and location","budget":"Moderate budget (1,000 - 3,000 €/USD)","start_timeline":"Within next 3 months","ultimate_vision":"My ultimate vision is being 1 of the biggest UW storyteller and documentary producing , so i would be able to work with big entities like BTM, natgeo etc, and to work the thing I do love the most","inspiration_to_apply":"I have seen your work guys over youtube and instagram and it''s really professional and inspiring","referral_source":["Social Media (Instagram, Facebook, etc.)"]}'::jsonb, '{}', '[]'::jsonb, '2026-03-13T11:53:44+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Sarah","last_name":"Bennett","email":"ssarahbennett8@hotmail.com","phone":"9059267322","age":"25-34","gender":"Female","nationality":"Canadian","country_of_residence":"Canada","languages":"English","current_occupation":"Canadian tree planter, trying to shift into Sci Comm and full time photography and videography","physical_fitness":"Good - Moderately active, no major health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving"],"certification_level":"Advanced Open Water","number_of_dives":"0-50","last_dive_date":"12.02.2026","diving_environments":["Tropical Reefs","Cold water","Cold water Freediving"],"buoyancy_skill":8,"equipment_owned":["DSLR/Mirrorless with housing","I also have a monitor"],"filming_equipment":"Canon Mark 5D IV Aquatica housing with dome port (wide angle 16-35 mm) and monitor","planning_to_invest":"No immediate plans","years_experience":"Less than 1 year","skill_camera_settings":5,"skill_lighting":1,"skill_post_production":2,"skill_color_correction":1,"skill_storytelling":8,"skill_drone":1,"skill_over_water":2,"content_created":["Social media content","Scientific/Research documentation"],"btm_category":"INDEPENDENT CREATOR (Experienced hobbyist/influencer seeking improvement)","involvement_level":"Hobby only","online_presence":"Active social media, Personal website","online_links":"www.sarahbennettcreative.com\n@ssarahbennett","income_from_filming":"No, not yet.","primary_goal":"Transform hobby into professional career","secondary_goal":"Document marine conservation/research","learning_aspects":["Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Conservation documentation"],"content_to_create":["Scientific/research documentation","Conservation stories"],"learning_approach":["Mixed approach (combination of group and individual)"],"marine_subjects":["Big marine life (sharks, whales, etc.)","Conservation stories"],"time_availability":"now and then for online classes","travel_willingness":"Depends on duration and location","budget":"Moderate budget (1,000 - 3,000 €/USD)","start_timeline":"Flexible/Not sure yet","ultimate_vision":"I’ve been at this for six years now. I’m primarily an underwater photographer who also wants to add video skills to what I can offer. I’m trying to find more opportunities in the conservation and environmental photography and videography world, but it’s been very hard.\n\nI’m also trying to transition into a different career path. I’ve been a tree planter for almost 11 years and want to find a more stable job in science communication while offering photography and videography. I don’t think I’ll ever be able to go fully freelance, as I still need a somewhat stable income, but I do want to keep learning and growing.\n\nI’m a hands-on learner and have been looking for online classes that will teach me what settings to use and how to post-edit properly. I’ve been experimenting on my own, but I have questions as I go and find it challenging when I don’t have anyone to ask.\n\nI want to work with local organizations on and around Vancouver Island, documenting important stories both above and below the water. I’m hoping that through this course, I’ll also gain valuable networking connections that could lead to hands-on opportunities.","inspiration_to_apply":"I feel as if I already have a good handle on underwater photography and want to gain a good handle on underwater video as well. \n\nI recently visited Gili Air, and did some dives with Coral Catch and documented some of their efforts, I saw a shared post you had with them and did some more digging and thought I’d inquire / fill out an application as I’ve been looking to up my skills.","referral_source":["Conservation organisation"],"questions_or_concerns":"How long are the programs?","anything_else":"I am a remote worker I tree plant from March - October (working 3 and 1s) I will be available on my days off to be at my computer so I’m wondering if this is “self paced” or how the course works. Thank you so much !"}'::jsonb, '{}', '[]'::jsonb, '2026-02-28T16:36:10+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Mathias","last_name":"STAVUN","email":"mathias.stavun@hotmail.com","phone":"+33(0)6.46.85.57.87","age":"25-34","gender":"Male","nationality":"french","country_of_residence":"France","languages":"English, French, German","current_occupation":"cameraman","physical_fitness":"Good - Moderately active, no major health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Technical Scuba diving"],"certification_level":"Advanced Open Water","number_of_dives":"0-50","last_dive_date":"15.02.2026","diving_environments":["Cold water","Deep diving","Diving pool (20m)"],"buoyancy_skill":7,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","DSLR/Mirrorless with housing"],"filming_equipment":"Sony FDR-AX33 + Seafrog Housing  / Gorpo 10 + housing + red filter","planning_to_invest":"Yes, within the near future","years_experience":"Less than 1 year","skill_camera_settings":9,"skill_lighting":3,"skill_post_production":7,"skill_color_correction":7,"skill_storytelling":5,"skill_drone":6,"skill_over_water":2,"content_created":["One test shooting with the FDR-AX33  + diving filming with gopro 10"],"btm_category":"ASPIRING PROFESSIONAL (Part-time professional aiming for full-time career)","involvement_level":"Hobby only","online_presence":"Active social media, Personal website","online_links":"https://www.instagram.com/mathias.stavun/","income_from_filming":"No, not yet.","primary_goal":"Transform hobby into professional career","secondary_goal":"Learn basics of underwater filming as a hobby","learning_aspects":["Basic equipment setup and operation","Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management"],"content_to_create":["Personal/travel memories","Social media content","Documentary style films","Commercial/advertising content","Conservation stories"],"learning_approach":["Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Big marine life (sharks, whales, etc.)","Macro subjects","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Depends on duration and location","budget":"Very limited budget. I basically have no financial means to be spent on this.","start_timeline":"Flexible/Not sure yet","ultimate_vision":"Graduated as cameraman in 2022, worked to pass my 2 Padi/french diving level to have the bare minimum for \"personal\" diving skills (passed the Advanced O.W level 2 weeks ago). Now, trying to figure where to start, so I could become an underwater filmmaker. Vielen Dank.","inspiration_to_apply":"I could find better formation and guidance with you, more than in my area.","referral_source":["Your Youtube channel"],"questions_or_concerns":"Would love to exchange with you by phone/video call, to understand yours ways and sees what can be done.","anything_else":"Out of a job, so not sure about the financial parts. That''s why I need to understand first before taking any decision for a possible internship. Danke"}'::jsonb, '{}', '[]'::jsonb, '2026-02-24T18:14:12+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Lewis","last_name":"Johnstone","nickname":"Lew","email":"Lewisjohnstonefilms@gmail.com","phone":"+971585710996","age":"25-34","gender":"Male","nationality":"United Kingdom","country_of_residence":"United Arab Emirates","languages":"English","current_occupation":"Freelance Photographer","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Open Water","number_of_dives":"0-50","last_dive_date":"04.01.2026","diving_environments":["Tropical Reefs","Night diving"],"buoyancy_skill":8,"equipment_owned":["Professional video camera"],"filming_equipment":"Sea frogs A7IV underwater housing, go pro","planning_to_invest":"Yes, within the near future","years_experience":"1-3 years","skill_camera_settings":8,"skill_lighting":4,"skill_post_production":8,"skill_color_correction":10,"skill_storytelling":7,"skill_drone":7,"skill_over_water":8,"content_created":["Personal vacation videos","Social media content","Documentary style"],"btm_category":"ASPIRING PROFESSIONAL (Part-time professional aiming for full-time career)","involvement_level":"Part-time professional","online_presence":"Active social media","online_links":"https://www.instagram.com/lewjohnstone?igsh=MTBtdXluYWxjbGpxag%3D%3D&utm_source=qr","income_from_filming":"Occasionally (few projects per year)","primary_goal":"Document marine conservation/research","secondary_goal":"Enhance existing professional skills","learning_aspects":["Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Documentary style films","Commercial/advertising content","Scientific/research documentation","Conservation stories"],"learning_approach":["Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","budget":"Advanced budget (3,000 - 6,000 €/USD)","start_timeline":"Ready to start immediately","ultimate_vision":"I want to capture the essence of adventure in my trips and inspire generations about developing there skllls to travel, explore and be adventurous. I want them to protect and preserve nature and prevent any future damage to our environment. I am very passionate about developing skills and being the best version of myself and convincing other to do the same.","inspiration_to_apply":"A friend of mine Lana recommended me to you through multiple of our diving trips where I have been taking photos of her and using her as my model. The BTM academy came very highly recommended and I’m very excited to join a community and program which helps me to develop professionally even futher.","referral_source":["Word of mouth"],"questions_or_concerns":"I would like to have a call and find out more and speak to someone in person.","anything_else":"I’m very excited to see what comes from this opportunity."}'::jsonb, '{}', '[]'::jsonb, '2026-02-21T10:14:25+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Anna","last_name":"Scholz","nickname":"Anna","email":"annalena.scholz98@web.de","phone":"01626283584","age":"25-34","gender":"Female","nationality":"German","country_of_residence":"Germany","languages":"English, German","current_occupation":"Student/editor","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Advanced Open Water","number_of_dives":"51-250","last_dive_date":"20.06.2025","diving_environments":["Tropical Reefs","Cold water","Night diving","Cave/Wreck diving"],"buoyancy_skill":8,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","DSLR/Mirrorless with housing"],"filming_equipment":"Canon eos r5c + nauticam housing","planning_to_invest":"Yes, within the near future","years_experience":"1-3 years","skill_camera_settings":7,"skill_lighting":4,"skill_post_production":8,"skill_color_correction":7,"skill_storytelling":8,"skill_drone":6,"skill_over_water":8,"content_created":["Personal vacation videos","Social media content","Documentary style"],"btm_category":"ASPIRING PROFESSIONAL (Part-time professional aiming for full-time career)","involvement_level":"Hobby only","online_presence":"Active social media, Personal website, Professional portfolio","online_links":"annascholz.de https://drive.google.com/drive/folders/1h9b16mAr9cu05IVc0xMcQ8trPzCy7mE8?usp=share_link","income_from_filming":"Occasionally (few projects per year)","primary_goal":"Transform hobby into professional career","secondary_goal":"Document marine conservation/research","learning_aspects":["Basic equipment setup and operation","Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Documentary style films","Commercial/advertising content"],"learning_approach":["Small group workshop (within a group of approx. 4 persons)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Conservation stories"],"time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Yes, willing to travel internationally","budget":"Small budget (under 1,000 €/USD)","start_timeline":"Flexible/Not sure yet","ultimate_vision":"I am highly motivated to deepen my skills in underwater filmmaking because it combines two of my greatest passions: storytelling and the ocean. Being underwater has always felt natural and inspiring to me, and capturing those moments visually adds an entirely new dimension to the experience. I want to continue learning how to document marine life and environmental challenges in a way that is both visually compelling and emotionally powerful.\n\nUnderwater filmmaking requires technical precision, patience, and a deep understanding of the environment, and I am eager to further develop these skills. The more I learn, the better I can contribute to raising awareness about ocean conservation and give marine ecosystems a stronger visual voice.","inspiration_to_apply":"I am motivated to join Behind the Mask because I want to further develop my skills in underwater filmmaking and combine my experience as a documentary filmmaker with my long-standing passion for diving. Being underwater has shaped my perspective for many years, and I want to refine my technical and storytelling abilities to capture marine environments in a more powerful and professional way.\n\nI am especially interested in deepening my understanding of underwater cinematography, lighting, and narrative structure in order to create stronger visual stories that raise awareness for ocean conservation. Learning from experienced professionals and being part of a community that shares the same passion for the ocean would be a valuable step in my creative and professional growth.","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"Could you please let me know how the program works in detail and what the participation costs are?"}'::jsonb, '{}', '[]'::jsonb, '2026-02-20T20:15:21+00:00');
