INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Alexander","last_name":"Helff","nickname":"Alex","email":"mail@alexanderhelff.de","phone":"+4917660945587","age":"25-34","gender":"Male","nationality":"German","country_of_residence":"Germany","languages":"English, German","current_occupation":"Fotograf & Filmemacher","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Divemaster","number_of_dives":"250+","last_dive_date":"13.12.2025","diving_environments":["Tropical Reefs","Cold water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":9,"equipment_owned":["DSLR/Mirrorless with housing","Lighting equipment"],"filming_equipment":"Sony a1 with Nauticam housing & Dome Port, 16-35mm & Macro, Weefine solar flare pro lights","planning_to_invest":"No immediate plans","years_experience":"Less than 1 year","skill_camera_settings":8,"skill_lighting":6,"skill_post_production":7,"skill_color_correction":6,"skill_storytelling":6,"skill_drone":9,"skill_over_water":9,"content_created":["Documentary style","Scientific/Research documentation"],"btm_category":"ASPIRING PROFESSIONAL (Part-time professional aiming for full-time career)","involvement_level":"Part-time professional","online_presence":"Personal website","online_links":"www.alexanderhelff.de   www.instagram.com/alexanderhelff/","income_from_filming":"No, not yet.","primary_goal":"Enhance existing professional skills","secondary_goal":"Improve content creation for social media","learning_aspects":["Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management"],"content_to_create":["Social media content","Documentary style films","Commercial/advertising content","Scientific/research documentation","Conservation stories"],"learning_approach":["Small group workshop (within a group of approx. 4 persons)","One-on-one mentorship","Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","budget":"Small budget (under 1,000 €/USD)","start_timeline":"Flexible/Not sure yet","ultimate_vision":"Ich habe keinen konkreten Plan, in welche Richtung genau ich gehen möchte, aber ich würde gerne vom (Unterwasser) Filmen leben können. Ob das jetzt für destination filme, ocean conservation docs, Expeditionen, Werbung/ Image film oder branded content ist, ist mir eigentlich egal, bzw. ich weis es noch nicht.","inspiration_to_apply":"Ich liebe das Meer und tauchen und habe an Land bereits in der film Branche gearbeitet und mich dazu entschieden beides zu kombinieren. Zum ersten mal habe ich BTM vor ein paar Jahren auf YouTube gesehen, seit dem haben wir uns schon ein paar mal life getroffen.","referral_source":["Social Media (Instagram, Facebook, etc.)"],"anything_else":"Aktuell plane ich März - Mai in Thailand für Tauchschulen und Touristen Social Media Content zu erstellen um viel zu tauchen und besser zu werden ohne viel Geld ausgeben zu müssen. Danach bin ich ziemlich frei. Neben dem Tauchen skipper ich auch und kenne mich mit booten gut aus, weil ich Yacht Design studiert habe und könnte mir auch gut vorstellen das für Projekte zu kombinieren."}'::jsonb, '{}', '[]'::jsonb, '2026-01-27T10:02:08+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Meaghan","last_name":"Ogilvie","email":"info@meaghanogilvie.com","phone":"+1-647-881-5471","age":"35-44","gender":"Female","nationality":"Canadian","country_of_residence":"Canada","languages":"English","current_occupation":"Photographer / Underwater Photographer","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Advanced Open Water, Certified Freediver, please specify level below:","number_of_dives":"51-250","last_dive_date":"26.03.2025","diving_environments":["Tropical Reefs","Cold water","Night diving"],"buoyancy_skill":6,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","DSLR/Mirrorless with housing","Lighting equipment"],"filming_equipment":"Current is 5D Mark II, Ikelite Housing with DS232 strobe lights. Upgrading to mirrorless in near future.","planning_to_invest":"Yes, within the near future","years_experience":"1-3 years","skill_camera_settings":9,"skill_lighting":7,"skill_post_production":7,"skill_color_correction":5,"skill_storytelling":7,"skill_drone":3,"skill_over_water":4,"content_created":["Documentary style","I''ve created a music video"],"btm_category":"ASPIRING PROFESSIONAL (Part-time professional aiming for full-time career)","involvement_level":"Am self-taught with a short course done on a red and nauticam","online_presence":"Active social media, Personal website, Professional portfolio, Client base","online_links":"Instagram:  @meaghan_ogilvie , Website: www.meaghanogilvie.com","income_from_filming":"Occasionally (few projects per year)","primary_goal":"Enhance existing professional skills","secondary_goal":"Document marine conservation/research","learning_aspects":["Basic equipment setup and operation","Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Documentary style films","Commercial/advertising content","Scientific/research documentation","Conservation stories"],"learning_approach":["Small group workshop (within a group of approx. 4 persons)","One-on-one mentorship","Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories"],"time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Depends on duration and location","budget":"Moderate budget (1,000 - 3,000 €/USD)","start_timeline":"Within next 6 months","ultimate_vision":"I''d love to use filmmaking as a tool to tell important stories about water through documentaries, art projects / installations and commercial projects. I would love to use different ways of connecting people to water. I''ve been wanting to create a documentary and art piece about the decline of kelp forests and the ambitious restoration projects that are taking place on the pacific northwest coast of Canada. There are so many important stories to share. My background is also in doing art exhibitions and I would love to incorporate video and projections of video as installations into my exhibitions. I also live in Toronto where tv shows and films are made and I would love to be able to be considered for filming.","inspiration_to_apply":"I''ve been an underwater photographer for over ten years and want to tell more impactful stories about water. As a photographer, I sometimes feel limited in what I can share. I want to expand my skillset to connect with people more deeply.  I''ve been following BTM for years on instagram and have been inspired by a lot of the content.","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"Hi! I''m really happy you''re offering this. Would I be required to supply my own equipment? Would there be opportunities to use larger cameras? I would have a smaller DSLR or mirrorless. I have had underwater cinematography training before that I funded with a grant that I received in 2023. The training was great and we shot on a RED with a Nauticam housing, but it was for one week and I didn''t have access to the camera and housing after. Without the ongoing support and continued hands-on experience I felt discouraged and have forgotten what I learnt. My concern is that would happen again, so I''m hoping I could learn on my own camera so I could continue practicing and filming after the course. But it would be nice to try larger cameras if possible to get the experience."}'::jsonb, '{}', '[]'::jsonb, '2026-01-26T21:56:23+00:00');
