INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Yazid","last_name":"Shaari","nickname":"Yazid","email":"yazid.shaari@outlook.com","phone":"+968-96231449","age":"54+","gender":"Male","nationality":"Libyan","country_of_residence":"Oman","languages":"English, Arabic","current_occupation":"Corrosion Engineer","physical_fitness":"Average - Some physical activity, manageable health conditions","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Snorkeling"],"certification_level":"Rescue Diver","number_of_dives":"250+","last_dive_date":"04.01.2026","diving_environments":["Tropical Reefs","Night diving"],"buoyancy_skill":8,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","DSLR/Mirrorless with housing","Lighting equipment"],"filming_equipment":"Currently I shoot Nikon Z9 and Sony A7RV but stills only. I do not take videos","planning_to_invest":"No immediate plans","years_experience":"None","skill_camera_settings":9,"skill_lighting":4,"skill_post_production":2,"skill_color_correction":1,"skill_storytelling":1,"skill_drone":1,"skill_over_water":1,"content_created":["None yet","excited to start","As I mentioned before","I am mainly a photographer"],"btm_category":"BEGINNER - Creative Explorer (Just starting, hobby-focused, seeking basic skills)","involvement_level":"Complete beginner","online_presence":"Active social media","online_links":"Instagram : @yazid.shaari","income_from_filming":"No, not yet.","primary_goal":"Learn basics of underwater filming as a hobby","secondary_goal":"Transform hobby into professional career","learning_aspects":["Camera settings and techniques","Lighting techniques","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming"],"content_to_create":["Personal/travel memories","Social media content","Documentary style films","Commercial/advertising content","Scientific/research documentation"],"learning_approach":["Small group workshop (within a group of approx. 4 persons)","One-on-one mentorship","Mixed approach (combination of group and individual)"],"marine_subjects":["Coral reefs","Macro subjects","Marine behavior"],"time_availability":"now and then for online classes","travel_willingness":"Depends on duration and location","budget":"Advanced budget (3,000 - 6,000 €/USD)","start_timeline":"Within next 3 months","ultimate_vision":"I have started diving relatively recently (2017), and started to take photos UW 2019. currently I am in a job, location, and state of health that allows to follow this passion and I want to take advantage of that as much as I can. quite intrigued by filming, had some modest attempts but did not follow up seriously. In photography i had some very good mentors but not the same in filming. I am 62 years and approaching retirement maybe in 4-6 years. when i go back to my country my travel will probably be very limited, and I don''t think the diving will be as exciting as the destinations i travel to now. Can do with skills of telling stories even in situations like that.","inspiration_to_apply":"Behind the mask team and videos speak for themselves, I have been a big fan for a while.\nAlso I just saw this by chance and I want to explore more at this stage.\nJust curios for now and looking forward to feedback on possibilities and potential.","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"I think i have included this in above submission.","anything_else":"When I travel, and because of my Libyan passport, I find it it easy to go to places like Indonesia, Philippines, Thailand, Jordan, and Maldives. Other locations in the world are challenging logistically"}'::jsonb, '{}', '[]'::jsonb, '2026-01-24T15:15:07+00:00');
