entation"],"content_to_create":["Personal/travel memories","Social media content","Documentary style films","Conservation stories"],"learning_approach":["Small group workshop (within a group of approx. 4 persons)","One-on-one mentorship"],"marine_subjects":["Big marine life (sharks, whales, etc.)"],"time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Yes, willing to travel internationally","budget":"Small budget (under 1,000 €/USD)","start_timeline":"Within next 6 months","ultimate_vision":"I prefer not to say this point plus i am new to this","inspiration_to_apply":"As social media review i think you guys are the best","referral_source":["Social Media (Instagram, Facebook, etc.)"]}'::jsonb, '{}', '[]'::jsonb, '2026-01-24T13:38:24+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Stephanie","last_name":"Weiser","nickname":"Steph","email":"stephanie.weiser@hotmail.com","phone":"0428248151","age":"35-44","gender":"Female","nationality":"German","country_of_residence":"Australia","languages":"English, German","current_occupation":"Communications and Brand Professional","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving"],"certification_level":"Advanced Open Water, Nitrox and Drysuit","number_of_dives":"250+","last_dive_date":"08.01.2026","diving_environments":["Tropical Reefs","Cold water","Night diving"],"buoyancy_skill":8,"equipment_owned":["iPhone"],"filming_equipment":"I‘m on my Phone, used to have an Olympus OMD EM mk3, my husband shoots on a Sony A7C mk 2 with a 28-60 and uses a wet wide angle and various diopters for macro. I have a 10k lumen Kraken and my husband has  two of them.","planning_to_invest":"No immediate plans","years_experience":"3-5 years","skill_camera_settings":1,"skill_lighting":4,"skill_post_production":5,"skill_color_correction":1,"skill_storytelling":6,"skill_drone":3,"skill_over_water":4,"content_created":["Personal vacation videos"],"btm_category":"INDEPENDENT CREATOR (Experienced hobbyist/influencer seeking improvement)","involvement_level":"Hobby only","online_presence":"Active social media","online_links":"https://youtube.com/@stephandburim?si=L8_3QHRljTg-a92H Insta: @stephweiser9 and @burimboonwirat","income_from_filming":"No, not yet.","primary_goal":"Improve content creation for social media","secondary_goal":"Transform hobby into professional career","learning_aspects":["Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Conservation documentation"],"content_to_create":["Personal/travel memories","Social media content","Documentary style films","Conservation stories"],"learning_approach":["Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Depends on duration and location","budget":"Advanced budget (3,000 - 6,000 €/USD)","start_timeline":"Flexible/Not sure yet","ultimate_vision":"I want our content to level up in storytelling, pos production and image quality. We are just hobbyists with a lot to lean. BTM videos are the ultimate inspiration, being able to inch even a little closer to that production value would be amazing.","inspiration_to_apply":"Your videos are our inspiration to become good content creators. Our friends reactions to our videos are the motivation to keep sharing underwater adventures to audiences that don’t dive. We want to create magic, impact and memories.Burim has always been into photography and that morphed into video in 2013 with his first go pro. I picked my phone to capture moments and bring them to the surface proving the best camera is the one you know as I am not as technical.","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"It would be great to know of the team would even consider hobbyists like us.","anything_else":"Like so many we do have full time jobs and try and go on as many holidays as possible. We’re not quite game to “quit” full time just yet. But chip away at our little YouTube channel where we can. I think we have the potential to improve a lot with the right guidance. I don’t think we will ever become professionals, but I aspire to become better."}'::jsonb, '{}', '[]'::jsonb, '2026-01-22T10:25:13+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Francisco","last_name":"Neves Amorim","nickname":"Chico","email":"francisco.n.amorim.9@gmail.com","phone":"+1 (250) 615-9732","age":"25-34","gender":"Male","nationality":"Portuguese","country_of_residence":"Canada","languages":"English, Spanish, Portuguese","current_occupation":"Educational Assistant/ Scuba Instructor","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving"],"certification_level":"Instructor","number_of_dives":"250+","last_dive_date":"15.05.2025","diving_environments":["Tropical Reefs","Cold water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":10,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)"],"filming_equipment":"GoPro Hero 11 Black\n(Ready to invest in something much better)","planning_to_invest":"Yes, within the near future","years_experience":"3-5 years","skill_camera_settings":6,"skill_lighting":2,"skill_post_production":2,"skill_color_correction":1,"skill_storytelling":2,"skill_drone":8,"skill_over_water":3,"content_created":["Personal vacation videos","Social media content"],"btm_category":"INDEPENDENT CREATOR (Experienced hobbyist/influencer seeking improvement)","involvement_level":"Hobby only","online_presence":"None of the above","online_links":"instagram.com/francisco_n_amorim\ninstagram.com/oceandumplings","income_from_filming":"No, not yet.","primary_goal":"Transform hobby into professional career","secondary_goal":"Document marine conservation/research","learning_aspects":["Basic equipment setup and operation","Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Conservation documentation"],"content_to_create":["Documentary style films","Scientific/research documentation","Conservation stories"],"learning_approach":["Small group workshop (within a group of approx. 4 persons)","Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Big marine life (sharks, whales, etc.)","Marine behavior","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","budget":"Advanced budget (3,000 - 6,000 €/USD)","start_timeline":"Within next 6 months","ultimate_vision":"My ultimate goal would be to step away from PADI and SSI and dedicate myself entirely to filming underwater. Documenting the magical underwater world and inspiring people to protect it. Filming pelagic creatures would be the dream (probably some kind of complex, since I''m pretty short). Working for BBC or NatGeo, may be dreaming to big, but that''s the goal. Turning my hobby into a career. I have LOTS to learn when it comes to filming though.\nMy girlfriend, Bella is also very much an underwater lover. A diver, filming enthusiast, who has currently applied for a masters in Science Communication in one of the best universities in the world. Our goal would be to one day work together, sharing our passion and educating people about conservation. We''re very serious about turning this into our careers.","inspiration_to_apply":"I  have been thinking about investing in proper training to learn underwater filming, for a while now. The moment never seemed right and the funds were low. Last year I decided to take a step back from the diving industry, to really think about what I would love to do with my life. The conclusion was always the same. I grew up watching wildlife documentaries and have always been fascinated by them. A few years after I started scuba diving, I randomly found an action camera during a dive and since then, every time I go fun diving, I take my camera with me. I just love trying to get close to marine life and capture their soul (without disturbing them too much of course). \nAbout 4 years ago, I heard a talk from Nuno Sá (Portuguese underwater videographer), that really inspired me and made me realise that with some effort and luck I could potentially turn this hobby into a dream job. Since then I''ve been practicing and I think now is the right time for me to seriously invest some time and money into this. Why BTM Academy? I''d been trying to find underwater filming courses for a few weeks but somehow I hadn''t realised BTM had their own courses. Today my girlfriend (who also applied) sent me a link for this page. I have been watching your videos for years now. You guys are sensational. \"This is it\". I''m ready to make my dream reality.","referral_source":["YouTube"],"questions_or_concerns":"I''m currently under a working contract in Canada that will finish in May 2026. Afterwards, I''m heading to the Maldives on a diving trip for 8 days. After that, I''m ready to work hard and learn. Just so you know my time frame...","anything_else":"Becoming an underwater videographer, isn´t just something I''m interested in learning as a hobby. I''m seriously going to try to turn it into a career. Learning from you would incredible and I really hope this works out :)"}'::jsonb, '{}', '[]'::jsonb, '2026-01-22T07:26:19+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Isabella","last_name":"Rooney","nickname":"Bella","email":"booneyrooney@gmail.com","phone":"12506417831","age":"25-34","gender":"Female","nationality":"Caymanian/ Canadian/ United Kingdom","country_of_residence":"Canada currently","languages":"English","current_occupation":"1. Communications for Kitselas Development corp 2. blue dot studio, communications & storytelling","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving"],"certification_level":"Rescue Diver","number_of_dives":"51-250","last_dive_date":"13.08.2025","diving_environments":["Tropical Reefs","Cold water","Night diving","Cave/Wreck diving"],"buoyancy_skill":9,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","Professional video camera"],"filming_equipment":"Currently just a go pro - in the process of acquiring an ikelite for my gh5 and 8-18mm. I’m not sure what lights to get just yet","planning_to_invest":"Yes, within the near future","years_experience":"1-3 years","skill_camera_settings":5,"skill_lighting":2,"skill_post_production":3,"skill_color_correction":2,"skill_storytelling":6,"skill_drone":4,"skill_over_water":4,"content_created":["Personal vacation videos","Social media content"],"btm_category":"OCEAN STEWARD (NGO/scientific focus, conservation-driven)","involvement_level":"Hobby only","online_presence":"Active social media, Personal website","online_links":"Instagram: @bellzaroo and website: bluedotstudio.co","income_from_filming":"No, that''s not my goal.","primary_goal":"Transform hobby into professional career","secondary_goal":"Document marine conservation/research","learning_aspects":["Basic equipment setup and operation","Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Personal/travel memories","Social media content","Documentary style films","Conservation stories"],"learning_approach":["Group workshops (within a group of approx. 10 persons)","Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","budget":"Moderate budget (1,000 - 3,000 €/USD)","start_timeline":"Within next 3 months","ultimate_vision":"I’m deeply passionate about creating communication that brings people into closer relationship with the ocean. I want to support NGOs, sustainable small businesses, Indigenous communities, and research teams whose livelihoods and work are rooted in ocean literacy and conservation—helping them convey their stories, findings, and lived connections to the sea in ways that truly resonate. Through thoughtful storytelling, my goal is to foster understanding, care, and long-term awareness for the ocean.","inspiration_to_apply":"I feel like sometimes I don’t know where to start. I feel I have instinct for storytelling, for setting up a shot, but I lack experience in the gear fundamentals and tech side.","referral_source":["Mads Ocean"],"questions_or_concerns":"My partner is also very interested in this. I will encourage him to apply also, I am hoping do my masters in Science Communications via Media Production this fall, I would love to be able to have experience before this so I might be able to have my thesis based around the ocean. I’m not sure how this might work but I’d love insight into the opportunities for that!","anything_else":"None - only that we will be in and around Indonesia and the Pacific in May, June and July this year. Any opportunities in these parts we would love to be apart of to learn!"}'::jsonb, '{}', '[]'::jsonb, '2026-01-21T18:51:52+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Rahul","last_name":"Thattan Sukumaran","email":"tsrahul@rocketmail.com","phone":"+919745184422","age":"35-44","gender":"Male","nationality":"Indian","country_of_residence":"Indonasia","languages":"English","current_occupation":"Scuba instructor","physical_fitness":"Good - Moderately active, no major health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving"],"certification_level":"Instructor","number_of_dives":"250+","last_dive_date":"28.12.2025","diving_environments":["Tropical Reefs"],"buoyancy_skill":8,"equipment_owned":["DSLR/Mirrorless with housing"],"filming_equipment":"Sony 7iii / seafrog case/ kraken 12000 lumen hydra","planning_to_invest":"Yes, within the near future","years_experience":"5+ years","skill_camera_settings":6,"skill_lighting":4,"skill_post_production":3,"skill_color_correction":4,"skill_storytelling":5,"skill_drone":6,"skill_over_water":4,"content_created":["Social media content","Documentary style","Scientific/Research documentation"],"btm_category":"OCEAN STEWARD (NGO/scientific focus, conservation-driven)","involvement_level":"Conservation/Scientific work","online_presence":"None of the above","online_links":"The.oceansaga","income_from_filming":"Occasionally (few projects per year)","primary_goal":"Document marine conservation/research","secondary_goal":"Enhance existing professional skills","learning_aspects":["Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Conservation documentation"],"content_to_create":["Social media content","Documentary style films","Scientific/research documentation","Conservation stories"],"learning_approach":["Group workshops (within a group of approx. 10 persons)","Small group workshop (within a group of approx. 4 persons)","Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Marine behavior","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","budget":"Moderate budget (1,000 - 3,000 €/USD)","start_timeline":"Ready to start immediately","ultimate_vision":"Ultimate vision is to become an underwater filmmaker whose work is rooted in authentic storytelling from the ground reality to visual story. Aiming just to create films beyond visual appeal than into communicate real ecological stories—highlighting marine life, human impact.","inspiration_to_apply":"Changing my career from engineering to underwater conservation filmmaking , it''s  transition period into marine conservation. Could understand that powerful visual storytelling can be easier for connecting people to the ocean and its challenges. Making people understand better. \n\nBehind the Mask Academy , because of its strong focus on story-driven, ethical underwater filmmaking and technical discipline","referral_source":["Diving community"],"questions_or_concerns":"INterested in knowing how BTM Academy supports students in transitioning from training into real-world conservation or documentary projects after completion.","anything_else":"Have dedicated rest of life into marine conservation story telling.  Would love really looking ahead to learn from the best in this field."}'::jsonb, '{}', '[]'::jsonb, '2026-01-20T20:33:20+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Chris","last_name":"Viljoen","nickname":"Chris","email":"cviloen@gmail.com","phone":"+31631942467","age":"35-44","gender":"Male","nationality":"Dutch","country_of_residence":"South Africa","languages":"English, Dutch; Afrikaans","current_occupation":"None","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Instructor, Certified Freediver, please specify level below:, PADI Freediver","number_of_dives":"250+","last_dive_date":"18.01.2026","diving_environments":["Tropical Reefs","Cold water","Deep diving","Night diving"],"buoyancy_skill":9,"equipment_owned":["DSLR/Mirrorless with housing","Lighting equipment"],"filming_equipment":"Panasonic GH5, Seafrogs Housing with dome; Sealife seadragon video lights","planning_to_invest":"Yes, within the near future","years_experience":"Less than 1 year","skill_camera_settings":3,"skill_lighting":3,"skill_post_production":2,"skill_color_correction":2,"skill_storytelling":3,"skill_drone":4,"skill_over_water":3,"content_created":["Personal vacation videos"],"btm_category":"BEGINNER - Creative Explorer (Just starting, hobby-focused, seeking basic skills)","involvement_level":"Hobby only","online_presence":"None of the above","income_from_filming":"No, not yet.","primary_goal":"Transform hobby into professional career","secondary_goal":"Improve content creation for social media","learning_aspects":["Basic equipment setup and operation","Camera settings and techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Conservation documentation"],"content_to_create":["Documentary style films","Commercial/advertising content","Scientific/research documentation"],"learning_approach":["Small group workshop (within a group of approx. 4 persons)","One-on-one mentorship","Project-based learning (within a BTM project)"],"marine_subjects":["Big marine life (sharks, whales, etc.)","Macro subjects","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","budget":"Advanced budget (3,000 - 6,000 €/USD)","start_timeline":"Ready to start immediately","ultimate_vision":"I would love to become a real professional underwater photographer. I have been working a corporate job for most my life, but my passion is diving and i wish to showcase the underwater world to others. I would like to take people diving with me, and also help them improve in their storytelling.","inspiration_to_apply":"I have been following BTM for a long time, i am familiar with your work. I am looking to change careers and while becoming an underwater photographer was always just a dream, I feel like now is the best time to make that a reality. I have the opportunity now, to truly pursue this dream","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"Not yet, but im sure something will come up :)","anything_else":"Not at the moment"}'::jsonb, '{}', '[]'::jsonb, '2026-01-19T18:13:55+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Robin","last_name":"Knapp","email":"Robin.Knapp@web.de","phone":"+4915785803381","age":"25-34","gender":"Male","nationality":"German","country_of_residence":"Germany","languages":"English","current_occupation":"Executive & Strategy Assistant","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving"],"certification_level":"Advanced Open Water, Certified Freediver, please specify level below:, AIDA2 > Freediving","number_of_dives":"0-50","last_dive_date":"05.12.2025","diving_environments":["Tropical Reefs","Night diving","Cave/Wreck diving"],"buoyancy_skill":7,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","DSLR/Mirrorless with housing","Lighting equipment"],"filming_equipment":"Sony Alpha 7rII with Seafrog Housing + small light + GoPro Hero 13","planning_to_invest":"No immediate plans","years_experience":"1-3 years","skill_camera_settings":8,"skill_lighting":5,"skill_post_production":8,"skill_color_correction":3,"skill_storytelling":9,"skill_drone":7,"skill_over_water":9,"content_created":["Personal vacation videos","Social media content"],"btm_category":"INDEPENDENT CREATOR (Experienced hobbyist/influencer seeking improvement)","involvement_level":"Hobby only","online_presence":"Active social media","online_links":"https://www.instagram.com/robins_ocean/","income_from_filming":"No, not yet.","primary_goal":"Improve content creation for social media","secondary_goal":"Document marine conservation/research","learning_aspects":["Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming"],"content_to_create":["Personal/travel memories","Social media content","Documentary style films","Scientific/research documentation"],"learning_approach":["Group workshops (within a group of approx. 10 persons)","Mixed approach (combination of group and individual)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories"],"time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Depends on duration and location","budget":"Small budget (under 1,000 €/USD)","start_timeline":"Flexible/Not sure yet","ultimate_vision":"I was touched, inspired and awe-struck when I first saw the documentaries of \"our blue planet II\". The visual appealing shots and the storytelling triggered my emotions - be it from seeing big whales to the smallest of creatures. It opened my eyes for a world that some people do not have the privilege to experience. On the other hand it showed me what is worth protecting and what is already lost due to our human hybris. With my underwater filming journey, I would love to trigger these emotions in others so that they understand that life beyond the surface is a miraculous and precious one and that we have to protect it at all costs to preserve the beauty and simply our lives as well.","inspiration_to_apply":"I already gained some experience in filmmaking and photography \"on land\". Before and during my studies, I did videography for my own films, travel films and some small client projects. This got a bit lost over the years due to my job and other hobbies. But since I discovered life underwater and put my camera in a waterproof housing, I fell in love with filmmaking again and want to improve my skills under water as well as in general. BTM Academy has such a nice approach to that and the visuals I saw on your website convinced me that I want to become a voice for the ocean to those who do not have the ability or emotional connection to it.","referral_source":["Boot Düsseldorf - thanks so much for he nice conversation! :)"],"questions_or_concerns":"I am curious and open-minded to what awaits me.","anything_else":"When I take my camera under water, I always have those in mind who are closest to me like family or friends. Currently, I am not planning to do client projects. But I am open to it as soon as I reach a professional level that could help that - as long as the fun of my hobby does not evolve into a liability. And I cannot wait to make those experiences with you!"}'::jsonb, '{}', '[]'::jsonb, '2026-01-19T17:54:51+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Hattan","last_name":"Al Sine","nickname":"Tona","email":"hattan911@icloud.com","phone":"+966566668830","age":"45-54","gender":"Male","nationality":"Saudi","country_of_residence":"Saudi Arabia","languages":"English, Arabic","current_occupation":"Underwater Videographer","physical_fitness":"Good - Moderately active, no major health concerns","health_conditions":"Yes, but cleared by doctor for diving","diving_types":["Recreational Scuba diving","Snorkeling"],"certification_level":"Divemaster","number_of_dives":"250+","last_dive_date":"16.01.2026","diving_environments":["Tropical Reefs","Deep diving","Cave/Wreck diving"],"buoyancy_skill":10,"equipment_owned":["DSLR/Mirrorless with housing"],"filming_equipment":"Sony A7s mark 3 with nauticam housing\nAtomos Ninja v with nauticam housing\nWacp 1\n90mm macro\nsmc-1\nMF0-3\n2x keldan lights\n2x keldan spectrun red filters\n2x keldan ambient filters\nXit04 tripod\ndji minipro","planning_to_invest":"Yes, within the near future","years_experience":"5+ years","skill_camera_settings":5,"skill_lighting":4,"skill_post_production":3,"skill_color_correction":3,"skill_storytelling":3,"skill_drone":5,"skill_over_water":6,"content_created":["Personal vacation videos","Social media content","Commercial work","Scientific/Research documentation"],"btm_category":"ASPIRING PROFESSIONAL (Part-time professional aiming for full-time career)","involvement_level":"Part-time professional","online_presence":"Active social media, Personal website","online_links":"https://www.instagram.com/hattan_alsine/","income_from_filming":"Occasionally (few projects per year)","primary_goal":"Transform hobby into professional career","secondary_goal":"Enhance existing professional skills","learning_aspects":["Basic equipment setup and operation","Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Personal/travel memories","Social media content","Documentary style films","Commercial/advertising content","Scientific/research documentation","Conservation stories"],"learning_approach":["Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories"],"time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Depends on duration and location","budget":"Moderate budget (1,000 - 3,000 €/USD)","start_timeline":"Ready to start immediately","ultimate_vision":"My journey in underwater filming began with a deep passion for the ocean and a genuine desire to document its beauty and the behavior of its marine life in a professional and responsible way.\n I aspire to further develop my technical and storytelling skills to produce high-quality visual content that combines artistic beauty with educational value with a particular focus on environmental stories and ocean conservation\n My ultimate goal is to work on impactful documentary and commercial projects and to build a sustainable professional career in underwater filming at both regional and international levels.","inspiration_to_apply":"I chose BTM Academy because it focuses on hands-on practice storytelling and real professional work rather than theory alone\nIts strong reputation project-based approach and direct mentorship make it the right environment to develop my skills and turn my passion for underwater filming into a clear professional path","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"non","anything_else":"Underwater filming has been my true passion for many years.\n\nMy long-term goal has always been to develop my skills to the highest possible level not as a casual hobby but as a lifelong professional path. \n\nThis passion led me to make a difficult but deliberate decision to leave my previous job and fully dedicate myself to underwater filmmaking believing that serious creative work requires full commitment and focus.\n\nI live with ulcerative colitis however it does not prevent me from pursuing my goals or practicing diving professionally. \n\nI have proven this through extensive field experience having dived across the entire Red Sea on both the eastern and western coasts from the far north to the far south.\n\nThis experience has given me a deep hands-on understanding of the Red Sea’s marine environment. \n\nI do prefer diving in temperate waters as cold water can increase the severity of my condition and this is a factor I responsibly consider when planning long-term projects.\n\nI have previously taken a training course with Luca who knows me personally and is familiar with my work my commitment and my long standing passion for underwater filmmaking. \n\nThis experience further strengthened my motivation to pursue structured high-level professional development.\n\nDespite my experience opportunities for advanced professional development in my country remain limited particularly in specialized underwater filmmaking and documentary storytelling.\n\nMy ultimate vision is to produce a high-quality documentary film that documents the eastern coastline of the Red Sea, highlighting its ecological value marine biodiversity and global significance.\n\nI believe the timing is ideal especially with the strong governmental support for tourism and the growing international focus on the Red Sea as a major destination and strategic project.\n\nMy goal is to contribute to this transformation through authentic impactful and professional visual storytelling that reflects the importance of this moment"}'::jsonb, '{}', '[]'::jsonb, '2026-01-18T05:22:59+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Menna","email":"mennakhater11@hotmail.com","age":"35-44","budget":"Moderate budget (1,000 - 3,000 €/USD)","phone":"(+020)01116039888","gender":"Female","nationality":"Egyptian","country_of_residence":"Egypt","languages":"English, Arabic","current_occupation":"General Manager & Head of Operations","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving"],"certification_level":"Advanced Open Water, Nitrox","number_of_dives":"51-250","last_dive_date":"01.08.2025","diving_environments":["Tropical Reefs","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":7,"equipment_owned":["No equipment yet"],"filming_equipment":"I don''t have any so far","planning_to_invest":"Yes, within the near future","years_experience":"None","skill_camera_settings":1,"skill_lighting":1,"skill_post_production":1,"skill_color_correction":1,"skill_storytelling":1,"skill_drone":1,"skill_over_water":1,"content_created":["None yet","excited to start"],"btm_category":"BEGINNER - Creative Explorer (Just starting, hobby-focused, seeking basic skills)","involvement_level":"Complete beginner","online_presence":"Active social media","income_from_filming":"No, thats not my goal.","primary_goal":"Document marine conservation/research","secondary_goal":"Learn basics of underwater filming as a hobby","learning_aspects":["Basic equipment setup and operation","Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Personal/travel memories","Social media content","Documentary style films","Scientific/research documentation","Conservation stories"],"learning_approach":["Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","start_timeline":"Within next 3 months","ultimate_vision":"I wish I can translate what it feels like under water to the whole universe and how precious and rare marine life is. I want to do all that I can to save marine life and keep it alive. It''s simply where I belong.","inspiration_to_apply":"Your work is so inspiring and genuine. You love and passionate about everything you do and it shows. I would be delighted to learn and experience life with you.","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"I want not to just join the academy, I would love to be part of the team and travel with you diving the world and gain more experience in diving. In other words, not just filming but living here and now.","anything_else":"I''m starting to explore different aspects of diving and would love to expand my knowledge and skills passionately and consistently","last_name":"Khater"}'::jsonb, '{}', '[]'::jsonb, '2026-01-17T17:52:45+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Rahul","nickname":"Rahul","email":"tsrahul@rocketmail.com","online_links":"the.oceansaga ( instagram)","age":"35-44","budget":"Small budget (under 1,000 €/USD)","phone":"+919745184422","gender":"Male","nationality":"Indian","country_of_residence":"INDONASIA","languages":"English","current_occupation":"Diving instructor and underwater videographer","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Instructor, Certified Freediver","number_of_dives":"250+","last_dive_date":"16.12.2025","diving_environments":["Tropical Reefs","Night diving"],"buoyancy_skill":8,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","Compact camera with housing","DSLR/Mirrorless with housing"],"filming_equipment":"Sony A7III with sigms 24-70f 2.8 lens. Using a seafrog casing and kraken video 12000 lumen lights.","planning_to_invest":"Yes, within the next years","years_experience":"1-3 years","skill_camera_settings":5,"skill_lighting":4,"skill_post_production":5,"skill_color_correction":6,"skill_storytelling":6,"skill_drone":8,"skill_over_water":6,"content_created":["Social media content","Documentary style","Scientific/Research documentation"],"btm_category":"OCEAN STEWARD (NGO/scientific focus, conservation-driven)","involvement_level":"Full-time professional","online_presence":"Active social media","income_from_filming":"Occasionally (few projects per year)","primary_goal":"Document marine conservation/research","secondary_goal":"Transform hobby into professional career","learning_aspects":["Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Documentary style films","Scientific/research documentation","Conservation stories"],"learning_approach":["Group workshops (within a group of approx. 10 persons)","Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Big marine life (sharks, whales, etc.)","Marine behavior","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","start_timeline":"Within next 3 months","ultimate_vision":"The easiest way to convey a message to mass is through storytelling. For me its all about Ocean storytelling, the more ocean storytellers we have the more we will be able go spread the need and urgency in marine conservation. My goal and Ikigai is to create and educate about ocean dos and donts, as much people i could in the remaining years of my life.","inspiration_to_apply":"The learning curve will be huge in this academy. It matches with what i have been looking for a mentor and team to learn or even work along with","referral_source":["Word of mouth"],"questions_or_concerns":"Will we be also working with Marine biologist during the project for learning about animal behaviours ?","anything_else":"Nothing else.","last_name":"Thattan Sukumaran"}'::jsonb, '{}', '[]'::jsonb, '2025-12-22T03:53:43+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"olga","email":"olgavideo@gmail.com","online_links":"https://www.instagram.com/sarloppia/ https://www.instagram.com/base1_sardinia/ https://www.youtube.com/@olghinavideo","age":"45-54","budget":"Moderate budget (1,000 - 3,000 €/USD)","phone":"+393272939100","gender":"Female","nationality":"Italian","country_of_residence":"Italy","languages":"English, Italian","current_occupation":"Operation manager at Base1 Sardinia dive center","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Technical Scuba diving","Snorkeling","cave diving"],"certification_level":"Instructor","number_of_dives":"250+","last_dive_date":"10.12.2025","diving_environments":["Tropical Reefs","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":10,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","Compact camera with housing","DSLR/Mirrorless with housing","Lighting equipment"],"filming_equipment":"Gopro 13, Intsa360 Onex5, Sony rx100 4 with housing and I do ot own but I use a Sony A7 with Nauticam housing. I have two Sea and Sea strobes and few Big Blue dive lights","planning_to_invest":"Yes, within the near future","years_experience":"5+ years","skill_camera_settings":7,"skill_lighting":5,"skill_post_production":5,"skill_color_correction":4,"skill_storytelling":5,"skill_drone":4,"skill_over_water":6,"content_created":["Social media content","Documentary style","Scientific/Research documentation"],"btm_category":"ASPIRING PROFESSIONAL (Part-time professional aiming for full-time career)","involvement_level":"Part-time professional","online_presence":"Active social media","income_from_filming":"Regular part-time income","primary_goal":"Transform hobby into professional career","secondary_goal":"Document marine conservation/research","learning_aspects":["Lighting techniques","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Conservation documentation"],"content_to_create":["Social media content","Documentary style films","Conservation stories"],"learning_approach":["Small group workshop (within a group of approx. 4 persons)","Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories","anything underwater really"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","start_timeline":"Flexible/Not sure yet","ultimate_vision":"My vision is to become an underwater storyteller capable of creating images and films that genuinely move people — the kind that give goosebumps, spark a wow moment, or stay with someone long after they’ve watched them.\nI want to capture the ocean with depth and emotion, revealing its beauty and fragility in a way that inspires connection and protection.\nUltimately, I hope my work can make people feel something real and leave a lasting trace. It might sound ambitious but I love the Sea and want to give somethnig back in the best way","inspiration_to_apply":"I chose the BTM Academy because your work represents the highest standard of underwater storytelling — visually stunning, emotionally powerful, and deeply connected to the ocean. Your ability to blend beauty, meaning, and authenticity is exactly what I aspire to learn. In short. you''re the fu*ing best out there","referral_source":["Online search"],"questions_or_concerns":"teach me and then ill be part of your team and we will save the seas","anything_else":"i love u","last_name":"martinelli"}'::jsonb, '{}', '[]'::jsonb, '2025-12-12T17:12:22+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Harsh","nickname":"Harsh","email":"shekhawatharshofficial@gmail.com","online_links":"instagram.com/shekhawatharshofficial","age":"25-34","budget":"Advanced budget (3,000 - 6,000 €/USD)","phone":"+91 8450965562","gender":"Male","nationality":"INDIAN","country_of_residence":"India","languages":"English","current_occupation":"Business Man","physical_fitness":"Good - Moderately active, no major health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving"],"certification_level":"Master Diver (SSI)","number_of_dives":"51-250","last_dive_date":"06.11.2025","diving_environments":["Tropical Reefs","Deep diving","Night diving","Cave/Wreck diving","Low visibility diving"],"buoyancy_skill":7,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)"],"filming_equipment":"I have Ace Pro 2 Dive Bundle with the following accessories:\n\n- \"+15 macromate mini lens from backscatter along with the lens adapter\"\n\n- AOI QRS-02 base mount for Ace Pro 2\n\n- AOI UWL03 Wide Angle Lens\n\n- Dual Handle Tray, and \n\n- Lens Holder.","planning_to_invest":"Yes, within the next years","years_experience":"1-3 years","skill_camera_settings":5,"skill_lighting":5,"skill_post_production":6,"skill_color_correction":6,"skill_storytelling":4,"skill_drone":1,"skill_over_water":1,"content_created":["Personal vacation videos","Social media content"],"btm_category":"BEGINNER - Creative Explorer (Just starting, hobby-focused, seeking basic skills)","involvement_level":"Hobby only","online_presence":"Active social media","income_from_filming":"No, thats not my goal.","primary_goal":"Learn basics of underwater filming as a hobby","secondary_goal":"Document marine conservation/research","learning_aspects":["Basic equipment setup and operation","Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Conservation documentation"],"content_to_create":["Social media content","Conservation stories"],"learning_approach":["Group workshops (within a group of approx. 10 persons)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories"],"time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Yes, willing to travel internationally","start_timeline":"Flexible/Not sure yet","ultimate_vision":"I''m a Master Diver with 106 logged dives as of November 2025. \n\nI genuinely love ocean, have a strong calling towards conservation, so aim is to become a Scientific Diver by 2027 - 2028 so to become an even better diver and contribute more 💙🌊🧿\n\nDived at following places:\n\nAndamans (India) 🇮🇳 - 3 times \n\nMaldives 🇲🇻 - 3 times (central atolls and Ukulhas) \n\nSipadan 🇲🇾 (Malaysia)\n\nRed Sea 🇪🇬 (North)\n\nSurin & Similan Islands 🇹🇭\n\n--------------\n\nI have Ace Pro 2 Dive Bundle with the following accessories:\n\n- \"+15 macromate mini lens from backscatter along with the lens adapter\"\n\n- AOI QRS-02 base mount for Ace Pro 2\n\n- AOI UWL03 Wide Angle Lens\n\n- Dual Handle Tray, and \n\n- Lens Holder. \n\nWould genuinely love to learn from the best on how to better use my setup to spread more awareness for Ocean Conservation through the dive trips I''ve planned 💙🌊🧿","inspiration_to_apply":"Your way of sharing things with people, that aligned with my goal of first starting with it as a hobby and then combining it with once I''m a Scientific Diver by 2027 - 2028. BTM seems genuine and reliable.","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"Nope.","anything_else":"Nope.","last_name":"Shekhawat"}'::jsonb, '{}', '[]'::jsonb, '2025-12-12T02:42:00+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Fadil","nickname":"Fadil","email":"tallyfadil@gmail.com","online_links":"https://www.instagram.com/fadiltallyphotography?igsh=dWMzM3ZpcHNjNGJ5","age":"35-44","budget":"Small budget (under 1,000 €/USD)","phone":"+23057706676","gender":"Male","nationality":"Mauritian","country_of_residence":"Mauritius","languages":"English, French","current_occupation":"Medical representative","physical_fitness":"Good - Moderately active, no major health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving"],"certification_level":"Advanced Open Water, Training in padi tec 40 at the moment.","number_of_dives":"250+","last_dive_date":"11.11.2025","diving_environments":["Tropical Reefs","Deep diving","Night diving"],"buoyancy_skill":9,"equipment_owned":["DSLR/Mirrorless with housing","Lighting equipment"],"filming_equipment":"Nikon z8, 105mm F2.8, nikon 16 35 f4, uw housing, 230mm dome port, Flat port for macro, 2x kraken hydra 18000","planning_to_invest":"Yes, within the next years","years_experience":"Less than 1 year","skill_camera_settings":9,"skill_lighting":7,"skill_post_production":5,"skill_color_correction":5,"skill_storytelling":3,"skill_drone":1,"skill_over_water":2,"content_created":["Social media content","Mostly reels to Post on ig and fb"],"btm_category":"INDEPENDENT CREATOR (Experienced hobbyist/influencer seeking improvement)","involvement_level":"Hobby only","online_presence":"Active social media","income_from_filming":"No, not yet.","primary_goal":"Document marine conservation/research","secondary_goal":"Transform hobby into professional career","learning_aspects":["Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Social media content","Documentary style films","Commercial/advertising content","Scientific/research documentation","Conservation stories"],"learning_approach":["Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories"],"time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Depends on duration and location","start_timeline":"Within next 3 months","ultimate_vision":"I''ve been doing uw videography for the past year. Everything was self taught. Technically sound but I have difficulties creating a compelling story, documentary style. I want to go that route. Learn filmmaking and documentary filming, piecing the footages together to create a coherent story.","inspiration_to_apply":"I enjoy nature and since a young age realised it''s importance. Started diving in 2019 and was amazed by all the little critters the ocean hides. I want to show more people what''s underwater so they can better protect it. I live on an island and mose people have never heard or seen a nudibranch.\nBTM Academy have nice projects and you are good with story telling and all. Learning from people who know what they are doing can make me improve my skills where I''m lacking.","referral_source":["Social Media (Instagram, Facebook, etc.)"],"last_name":"Tally"}'::jsonb, '{}', '[]'::jsonb, '2025-11-13T16:14:58+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Tom","email":"tom@oceanexplorertom.com","online_links":"Instagram.com/Oceanexplorertom","age":"35-44","budget":"Advanced budget (3,000 - 6,000 €/USD)","phone":"+447837387328","gender":"Male","nationality":"British","country_of_residence":"United Kingdom","languages":"English","current_occupation":"Sailor","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Technical Scuba diving","Snorkeling","Octopush (Underwater Hockey)"],"certification_level":"Instructor, Technical Diving certification","number_of_dives":"250+","last_dive_date":"10.11.2025","diving_environments":["Tropical Reefs","Cold water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":9,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","DSLR/Mirrorless with housing","Lighting equipment"],"filming_equipment":"Canon R5C, Nauticam Housing, Pair of X-Adventurer Lights, Snoot Light, GoPro11","planning_to_invest":"No immediate plans","years_experience":"1-3 years","skill_camera_settings":6,"skill_lighting":6,"skill_post_production":2,"skill_color_correction":2,"skill_storytelling":4,"skill_drone":5,"skill_over_water":4,"content_created":["Social media content"],"btm_category":"INDEPENDENT CREATOR (Experienced hobbyist/influencer seeking improvement)","involvement_level":"Hobby only","online_presence":"Active social media","income_from_filming":"No, not yet.","primary_goal":"Transform hobby into professional career","secondary_goal":"Document marine conservation/research","learning_aspects":["Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management","Conservation documentation","I''m keen to learn lots!"],"content_to_create":["Documentary style films","Scientific/research documentation","Conservation stories"],"learning_approach":["Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Marine behavior","All","but if I had to choose only one: Marine Behavior"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","start_timeline":"Ready to start immediately","ultimate_vision":"I’ve been mostly filming and taking photos of whatever the ocean sends my way underwater. My ultimate goal is to learn how to create a film that matters and the whole process that’s involved, from idea to storyboarding, filming, editing and publishing.","inspiration_to_apply":"I feel most at home in/on/under the ocean, being underwater feels like a privilege that not everybody gets to experience. I’ve always been passionate about protecting wildlife and the environment, the first step towards protection is understanding. Capturing photos and footage of the environment above & below the water, how creatures interact and being able to share and explain the interconnectedness of our natural world is important to me. What inspired me to apply for the academy, having planned to spend three months in Bali honing my underwater camera skills, I discover that you are running a project/workshop in the same country, at the same time! This seemed like too much a coincidence to ignore. Especially, having watched and learned from your videos online, it is an amazing opportunity to join a project with the team.","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"I''''m interested to understand how the training approach is conducted, what a day with the team looks like. (Probably very different each day.) What are the different roles within the team or is there a lot of overlap. All things that I assume will become clear through discussion.","anything_else":"I just made the scariest decision of my life and quit my corporate job, sold everything I own, and moved onto a sailboat. It felt impossible not to follow the pull. There is only one thing I want to be when I grow up and that is an underwater filmmaker and now I’m all in, learning, exploring, and hoping to tell ocean stories!","last_name":"Hardwick"}'::jsonb, '{}', '[]'::jsonb, '2025-11-10T16:43:15+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Natalia","nickname":"Nat","email":"hola@nataliavilches.com","online_links":"@ungravity.studio (instagram), www.ungravitystudio.com, www.nataliavilches.com (personal website)","age":"35-44","budget":"Moderate budget (1,000 - 3,000 €/USD)","phone":"+34656376682","gender":"Female","nationality":"Spanish","country_of_residence":"Spain","languages":"English, Spanish","current_occupation":"Freelance Filmmaker and Motion grapher","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving"],"certification_level":"Divemaster","number_of_dives":"51-250","last_dive_date":"28.09.2025","diving_environments":["Tropical Reefs","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":9,"equipment_owned":["DSLR/Mirrorless with housing"],"filming_equipment":"Sony Alpha 7sII + Ikelite housing (Dome and Macro port) + Bigblue VL10000 Lights","planning_to_invest":"Yes, within the near future","years_experience":"1-3 years","skill_camera_settings":10,"skill_lighting":7,"skill_post_production":9,"skill_color_correction":7,"skill_storytelling":7,"skill_drone":7,"skill_over_water":9,"content_created":["Social media content","Documentary style","Commercial work"],"btm_category":"DEDICATED ACHIEVER (Business-focused, seeking intensive mentorship)","involvement_level":"Part-time professional","online_presence":"Active social media, Personal website, Professional portfolio","income_from_filming":"Occasionally (few projects per year)","primary_goal":"Enhance existing professional skills","secondary_goal":"Transform hobby into professional career","learning_aspects":["Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming"],"content_to_create":["Documentary style films","Commercial/advertising content","Scientific/research documentation","Conservation stories"],"learning_approach":["Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Big marine life (sharks, whales, etc.)","Macro subjects","Conservation stories"],"time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Yes, willing to travel internationally","start_timeline":"Flexible/Not sure yet","ultimate_vision":"I’ve been a professional filmmaker for over 15 years, and my current goal is to expand my career into underwater filmmaking. I aspire to make underwater projects an integral part of my daily creative work.","inspiration_to_apply":"I’ve been following your work and using your tutorials to improve my underwater filmmaking skills. I believe this opportunity aligns perfectly with my professional goals. Collaborating with a team of experienced underwater filmmakers would have a significant impact on my career and greatly influence the way I approach my projects and creative process.","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"After talking with Flo, everything''s pretty clear at the moment.","anything_else":"I’d like to be completely honest with you. As excited as I am about the possibility of joining the BTM Academy, the high cost of the program is making me reconsider whether I can commit to this mentorship at the moment. If there are any other projects or opportunities you think might be a better fit for me, I’d be very happy to hear about them.","last_name":"Vilches"}'::jsonb, '{}', '[]'::jsonb, '2025-11-10T14:13:05+00:00');
