INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Harper","nickname":"n/a","email":"harperaltschul@icloud.com","online_links":"https://www.instagram.com/harperaltschul/\nhttps://www.youtube.com/@HarperAltschul","age":"18-24","budget":"Advanced budget (3,000 - 6,000 €/USD)","phone":"+1 9293665400","gender":"Male","nationality":"American","country_of_residence":"USA","languages":"English, Spanish, Bahasa (not fluent, but can have conversation)","current_occupation":"Full time busser at a resturant, parkour instructor, and freelance camera operator","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Currently","just freediving and recreational scuba","but I planning to get my dry suit and rebreather in the upcoming months"],"certification_level":"Divemaster","number_of_dives":"250+","last_dive_date":"10.08.2025","diving_environments":["Tropical Reefs","Cold water","Night diving","Cave/Wreck diving"],"buoyancy_skill":9,"equipment_owned":["Professional video camera","Lighting equipment"],"filming_equipment":"Sony a7siii, Nauticam Housing, Backscatter Hybrid Flashes","planning_to_invest":"Yes, within the next years","years_experience":"1-3 years","skill_camera_settings":8,"skill_lighting":7,"skill_post_production":8,"skill_color_correction":7,"skill_storytelling":7,"skill_drone":8,"skill_over_water":7,"content_created":["Personal vacation videos","Social media content","Documentary style","Scientific/Research documentation"],"btm_category":"ASPIRING PROFESSIONAL (Part-time professional aiming for full-time career)","involvement_level":"Mix of conservation/scientific work and part-time profesional. I worked in Maldives for a few months as a underwater filmmaker documenting the different research projects going on (Maldives Underwater Initative at Six Senses Laamu). And I have also done projects with different dive companies.","online_presence":"Active social media","income_from_filming":"Occasionally (few projects per year)","primary_goal":"Transform hobby into professional career","secondary_goal":"Enhance existing professional skills","learning_aspects":["Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Personal/travel memories","Documentary style films","Conservation stories"],"learning_approach":["Mixed approach (combination of group and individual)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories","All of the above"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","start_timeline":"Flexible/Not sure yet","ultimate_vision":"Orignally, I wanted to just be a underwater camera operator shooting different stories for National Geographic or BBC Earth. That is still a dream of mine, but rather than having that as the main goal, I would love to find a way to use my passion of wildlife cinematography to create and spread awareness changing the hearts and mind of people across the world. Hoping to create a larger percentage or MPA''s throughout our oceans.","inspiration_to_apply":"I have been watching all the BTM videos for years and I am always so eager to see new videos when they come out. I will find a way to make this my full-time career one way or another, but one of the best ways to do that (in my opinion) is surrounding myself with people with much more knowledge and experience than me.","referral_source":["Mix of social media and the diving community"],"questions_or_concerns":"n/a","anything_else":"As I mentioned before, I will find a way to change the world for the better with wildlife cinematography + storytelling one way or another. I strongly believe that I have already accomplished all my dreams and more than I can comprehend. The time from this present moment, to then just has not caught up yet.","last_name":"Altschul"}'::jsonb, '{}', '[]'::jsonb, '2025-09-11T19:33:30+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Shahar","nickname":"Shaqi","email":"shalom.shahar18@gmail.com","online_links":"https://www.instagram.com/wildshalom?igsh=YXEzZDZvcTNmOG5t&utm_source=qr \n\nhttps://youtube.com/@wildshalom?si=dFm47qMWDVJ1aufE","age":"25-34","budget":"Advanced budget (3,000 - 6,000 €/USD)","phone":"+972584260722","gender":"Male","nationality":"Israeli, American","country_of_residence":"Israel","languages":"English, Hebrew","current_occupation":"Dive instructor","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Instructor","number_of_dives":"250+","last_dive_date":"30.08.2025","diving_environments":["Tropical Reefs","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":9,"equipment_owned":["DSLR/Mirrorless with housing"],"filming_equipment":"Sony a7RV, 16-35mm lens, DJI mini 4K (drone)","planning_to_invest":"Yes, within the near future","years_experience":"Less than 1 year","skill_camera_settings":7,"skill_lighting":5,"skill_post_production":4,"skill_color_correction":3,"skill_storytelling":7,"skill_drone":7,"skill_over_water":4,"content_created":["Social media content","Documentary style"],"btm_category":"INDEPENDENT CREATOR (Experienced hobbyist/influencer seeking improvement)","involvement_level":"Hobby only","online_presence":"Active social media","income_from_filming":"No, not yet.","primary_goal":"Transform hobby into professional career","secondary_goal":"Document marine conservation/research","learning_aspects":["Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Social media content","Documentary style films","Conservation stories"],"learning_approach":["Small group workshop (within a group of approx. 4 persons)","Mixed approach (combination of group and individual)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Marine behavior","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","start_timeline":"Ready to start immediately","ultimate_vision":"My dream is to create and tell content about the oceans so that people can be exposed to the underwater world and learn about it in order to preserve our wonderful nature. In addition, my dream is to work in the conservation and rescue of animals and nature.","inspiration_to_apply":"What made me try to contact you is the content and the level you raise your products. In addition, I really connect with the conservation work you do. I immediately understood that your professionalism and experience in the field is rich and diverse and can give me a lot of experience in the field of photography, its distribution and conservation.","referral_source":["Online search"],"last_name":"Shalom"}'::jsonb, '{}', '[]'::jsonb, '2025-09-07T19:17:49+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Jonathan","nickname":"Jon","email":"jonkanevsky@gmail.com","online_links":"@love.is.the.mission @drjon.k","age":"35-44","budget":"Professional budget (6,000 - 12,000 €/USD)","phone":"4243739629","gender":"Male","nationality":"USA","country_of_residence":"USA","languages":"English, Spanish, French, Russian","current_occupation":"Surgeon","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Open Water, Advanced Open Water, Certified Freediver","number_of_dives":"0-50","last_dive_date":"08.08.2025","diving_environments":["Tropical Reefs","Deep diving","Cave/Wreck diving"],"buoyancy_skill":4,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","Compact camera with housing"],"filming_equipment":"Fujifilm x100vi","planning_to_invest":"Yes, within the next years","years_experience":"Less than 1 year","skill_camera_settings":3,"skill_lighting":3,"skill_post_production":3,"skill_color_correction":3,"skill_storytelling":5,"skill_drone":6,"skill_over_water":4,"content_created":["Personal vacation videos","Social media content"],"btm_category":"BEGINNER - Creative Explorer (Just starting, hobby-focused, seeking basic skills)","involvement_level":"Hobby only","online_presence":"Active social media","income_from_filming":"No, thats not my goal.","primary_goal":"Learn basics of underwater filming as a hobby","secondary_goal":"Improve content creation for social media","learning_aspects":["Basic equipment setup and operation","Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Conservation documentation"],"content_to_create":["Personal/travel memories","Social media content","Documentary style films"],"learning_approach":["Small group workshop (within a group of approx. 4 persons)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Mermaids:)"],"time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Yes, willing to travel internationally","start_timeline":"Ready to start immediately","ultimate_vision":"I’m drawn to underwater filming not only to capture the beauty of the ocean but also to tell human stories within it. My dream is to master the craft, learning how to work with light, movement, and gear underwater. I would like to create films that balance documentary realism with cinematic artistry, while also advocating for conservation and connection to the sea.\n\nInspired by my girlfriend Ella, I especially want to film her grace and art as a free divers. To me, these movements are like poetry, a form of meditation and dance beneath the surface. My aspiration is to capture that elegance on film, collaborating to create evocative pieces that show diving as both an art form and a deep expression of our relationship with the ocean.","inspiration_to_apply":"I’ve always been fascinated by the ocean, it feels like stepping into another world full of mystery, silence, and beauty. What drew me to underwater filming is the chance to capture that world and share it with others, not just through images of marine life, but by telling deeper stories of our connection to the sea. I’m especially inspired by the stories that are told filming the elegance and art of diving, turning it into visual poetry.\n\nI chose BTM Academy because I want to learn from people who truly understand both the technical craft and the artistic side of underwater storytelling. The structured training, expert guidance, and community of like-minded creatives make it the perfect place to develop the skills I need not just to document the ocean, but to bring out its emotion, artistry, and human connection.","referral_source":["Andre Musgrove"],"anything_else":"Would be happy to offer my services as a doctor during the trip","last_name":"Kanevsky"}'::jsonb, '{}', '[]'::jsonb, '2025-08-19T19:02:58+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Richard","nickname":"RJ","email":"rmorante15@gmail.com","online_links":"IG:@rj_morante \nhttps://www.instagram.com/rj_morante?igsh=MTNrNnNzZzdzNXZ0cw%3D%3D&utm_source=qr\n\nYouTube:@divewithRJ, https://youtube.com/@divewithrj?si=FFOqaBmLN2kj__gd","age":"35-44","budget":"Professional budget (6,000 - 12,000 €/USD)","phone":"+17782337414","gender":"Male","nationality":"Filipino Canadian","country_of_residence":"Canada","languages":"English","current_occupation":"Electrician","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Snorkeling"],"certification_level":"Instructor","number_of_dives":"250+","last_dive_date":"04.08.2025","diving_environments":["Tropical Reefs","Cold water","Deep diving","Night diving","Cave/Wreck diving","Strong drift"],"buoyancy_skill":9,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","Compact camera with housing","DSLR/Mirrorless with housing","Lighting equipment","DJI mavic air 2 drone"],"filming_equipment":"Sony A7 IV,  \nSony 50mm f2.8 macro lens, \nSony 90mm f2.8 macro lens, \nSony 12-24mm f4 wide lens, \naquatica housing, \nmini port and dome port, \n2x big bkue vlt8000p lights, \n2x inon z330 strobes. \n1x MF-1 mini flash with snoot, \nsola nightsea UV light, \nOlympus TG6 with housing, \nMacBook Pro M1\niPhone 14 Pro \nSea touch max 4","planning_to_invest":"Yes, within the near future","years_experience":"3-5 years","skill_camera_settings":6,"skill_lighting":7,"skill_post_production":4,"skill_color_correction":3,"skill_storytelling":6,"skill_drone":7,"skill_over_water":3,"content_created":["Personal vacation videos","Social media content","Fish ID"],"btm_category":"ASPIRING PROFESSIONAL (Part-time professional aiming for full-time career)","involvement_level":"Hobby only","online_presence":"Active social media","income_from_filming":"No, not yet.","primary_goal":"Transform hobby into professional career","secondary_goal":"Improve content creation for social media","learning_aspects":["Camera settings and techniques","Lighting techniques","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Client relations and project management"],"content_to_create":["Personal/travel memories","Social media content","Documentary style films"],"learning_approach":["Group workshops (within a group of approx. 10 persons)","Small group workshop (within a group of approx. 4 persons)","One-on-one mentorship","Mixed approach (combination of group and individual)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior"],"time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Yes, willing to travel internationally","start_timeline":"Ready to start immediately","ultimate_vision":"I like to go critter hunt in every dive, and focus on marine life shots, rare, hard to find creatures, kinda like a nat geo style shooting, but want to learn how to improve my story telling and camera skills. \nI’ve done a few videos at my fav dive sites in Philippines and Vancouver island, from macro to big animals, pigmy seahorses and nudibranchs to packs of sea lions and orcas, They were personal vacation videos of footage I’ve collected while working at a dive shop.  I like adding music and amplify the experience of the audience, sharing to my friends and family. Other videos more about showing as many highlights of animals filmed at the time. I’ve focused lately on photography but I think I’m more a video guy. Behind the mask videos are simply the best I’ve seen and I aspire to tell stories that good! \nI want to learn as much as I can and keep growing and improving.","inspiration_to_apply":"The behind the mask videos on YouTube have convinced me it is the kind of work and style I’d like to create. From shooting to editing. I’ve invested a lot of time, money and energy into this hobby and want to take myself to a higher level.","referral_source":["YouTube"],"last_name":"Morante"}'::jsonb, '{}', '[]'::jsonb, '2025-08-19T15:39:24+00:00');
