nservation documentation"],"content_to_create":["Personal/travel memories","Social media content","Documentary style films","Commercial/advertising content","Conservation stories"],"learning_approach":["Group workshops (within a group of approx. 10 persons)","Small group workshop (within a group of approx. 4 persons)","Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","start_timeline":"Flexible/Not sure yet","ultimate_vision":"There''s a lot of film work on the gold cost and would love to get involved in working on films and general projects all over the world.","inspiration_to_apply":"I basically live in the sea all year round. So i love to show people what i get up to. I know you guys are the best in the game and,  you are the only people I''ve seen doing this kind of work.","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"I''m just interested to see what this would involve and if it''s going to work for me being in Australia."}'::jsonb, '{}', '[]'::jsonb, '2025-04-01T13:20:28+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Melina Contogiorgakis","nickname":"Mel","email":"Melinaconto@hotmail.com","online_links":"Instagram.com/ultimatripulante","age":"25-34","budget":"Advanced budget (3,000 - 6,000 €/USD)","phone":"+5491121797887","gender":"Female","nationality":"Argentina","country_of_residence":"Argentina","languages":"English, Spanish","current_occupation":"Free lance photographer","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving"],"certification_level":"Instructor","number_of_dives":"250+","last_dive_date":"30.03.2025","diving_environments":["Tropical Reefs","Cold water","Night diving","Currents","poor visibility"],"buoyancy_skill":10,"equipment_owned":["DSLR/Mirrorless with housing","Lighting equipment"],"filming_equipment":"Canon 5d mark IV, ikelite housing, ds161strobes, 8-15mm, 17-40mm, etc.","planning_to_invest":"Yes, within the next years","years_experience":"1-3 years","skill_camera_settings":6,"skill_lighting":7,"skill_post_production":6,"skill_color_correction":8,"skill_storytelling":1,"skill_drone":3,"skill_over_water":3,"content_created":["Dive shop videos/photos for guests"],"btm_category":"ASPIRING PROFESSIONAL (Part-time professional aiming for full-time career)","involvement_level":"Part-time professional","online_presence":"Active social media","income_from_filming":"Regular part-time income","primary_goal":"Document marine conservation/research","secondary_goal":"Enhance existing professional skills","learning_aspects":["Storytelling and content planning","Business aspects of underwater filming","Client relations and project management","Conservation documentation"],"content_to_create":["Documentary style films","Commercial/advertising content","Scientific/research documentation","Conservation stories"],"learning_approach":["One-on-one mentorship","Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Big marine life (sharks, whales, etc.)","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Depends on duration and location","start_timeline":"Ready to start immediately","ultimate_vision":"I have experience in underwater photography, but I want to refine my filmmaking and storytelling skills. My goal is to create powerful, compelling media that highlights this part of the world and raises awareness about marine conservation in Argentina.","inspiration_to_apply":"I admire BTM''s work and believe it will help me improve my storytelling skills. I like how you highlight the human connection and emotions tied to the ocean in your videos.","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"I would be very interested in getting trained in harsher environments (bad weather, low light, bad visibility, etc.) And not so much in pool like conditions.","anything_else":"Not really, excited to start!"}'::jsonb, '{}', '[]'::jsonb, '2025-03-31T15:40:53+00:00');
