eate":["Social media content","Documentary style films","Scientific/research documentation","Conservation stories"],"learning_approach":["One-on-one mentorship","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","start_timeline":"Within next 3 months","ultimate_vision":"I would like to use underwater filmmaking for science communication and to be part of underwater documentaries.","inspiration_to_apply":"Underwater filming gives the opportunity to share the beauty and raise awareness of this unique and important environment, which otherwise stays unseen for most people. Learning on a mentoring basis during a real project gives the most insights and overall best learning experience. I chose the BTM Academy because this is a once in a lifetime opportunity to learn from experts in their field.","referral_source":["Social Media (Instagram, Facebook, etc.)"]}'::jsonb, '{}', '[]'::jsonb, '2025-03-24T03:26:48+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Daniel R. Guerrero","nickname":"Dan","email":"diverdang2528@gmail.com","age":"54+","budget":"Advanced budget (3,000 - 6,000 €/USD)","phone":"4156482539","gender":"Male","nationality":"United States","country_of_residence":"United States","languages":"English","current_occupation":"Computer Services","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving"],"certification_level":"Open Water, Advanced Open Water, Rescue Diver, Divemaster","number_of_dives":"250+","last_dive_date":"27.02.2025","diving_environments":["Tropical Reefs","Night diving"],"buoyancy_skill":10,"equipment_owned":["DSLR/Mirrorless with housing","Lighting equipment"],"filming_equipment":"Sony A-1; Sea & Sea Housing, Keldan lights","planning_to_invest":"Yes, within the near future","years_experience":"1-3 years","skill_camera_settings":7,"skill_lighting":6,"skill_post_production":5,"skill_color_correction":5,"skill_storytelling":4,"skill_drone":1,"skill_over_water":1,"content_created":["Personal vacation videos"],"btm_category":"INDEPENDENT CREATOR (Experienced hobbyist/influencer seeking improvement)","involvement_level":"Hobby only","online_presence":"None of the above","income_from_filming":"No, thats not my goal.","primary_goal":"Learn basics of underwater filming as a hobby","secondary_goal":"Improve content creation for social media","learning_aspects":["Basic equipment setup and operation","Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing"],"content_to_create":["Personal/travel memories","Social media content","Conservation stories"],"learning_approach":["Group workshops (within a group of approx. 10 persons)","Mixed approach (combination of group and individual)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories"],"time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Yes, willing to travel internationally","start_timeline":"Flexible/Not sure yet","ultimate_vision":"I would like to understand and learn how to create high quality underwater video creation. I want to create close to the quality of Behind the Mask videos.","inspiration_to_apply":"Underwater filing is easier to tell a story than still photos. Most of things I know on taking underwater videos I learned from BTM videos","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"Just the cost. :)","anything_else":"I am frustrated with the quality of my videos and excited to learn."}'::jsonb, '{}', '[]'::jsonb, '2025-03-24T03:22:38+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Franziska Wenzel","nickname":"Franzi","email":"wenzel.f.23@gmail.com","online_links":"Personal Instagram: https://www.instagram.com/franzis_resa_/ Shared Instagram with my friend about our stories https://www.instagram.com/somewhere.sunkissed/","age":"25-34","budget":"Advanced budget (3,000 - 6,000 €/USD)","phone":"+4915223075947","gender":"Female","nationality":"German","country_of_residence":"Germany","languages":"English, German","current_occupation":"Traveling full time + PA and Social Media Manager","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling","absolved an underwater photography course recently"],"certification_level":"Open Water","number_of_dives":"51-250","last_dive_date":"19.03.2025","diving_environments":["Tropical Reefs","Cold water"],"buoyancy_skill":8,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","Looking into buying the Canon G7x inclusive housing and light setup next week!"],"filming_equipment":"Currently, the GoPro 12 Hero Black","planning_to_invest":"Yes, within the near future","years_experience":"Less than 1 year","skill_camera_settings":6,"skill_lighting":3,"skill_post_production":5,"skill_color_correction":6,"skill_storytelling":3,"skill_drone":7,"skill_over_water":2,"content_created":["Personal vacation videos","Social media content"],"btm_category":"INDEPENDENT CREATOR (Experienced hobbyist/influencer seeking improvement)","involvement_level":"Beginner but seeking to become a part-time professional","online_presence":"Active social media","income_from_filming":"No, not yet.","primary_goal":"Transform hobby into professional career","secondary_goal":"Document marine conservation/research","learning_aspects":["Camera settings and techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Conservation documentation"],"content_to_create":["Documentary style films","Commercial/advertising content","Scientific/research documentation"],"learning_approach":["Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Marine behavior","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","start_timeline":"Within next 3 months","ultimate_vision":"Ok, dream big, right? My ultimate dream aspiration in UW filming would be: part or full-time professional filmmaking while giving presence and focusing on small projects/NGO/brands that are ambassadors for the ocean AND/OR documenting on different marine species. Their migration, their behavior, struggles, threads in the up-to-date world! Withing a network like BTM! Easy, right? Showing the world and aspiring people that there is more to see, to understand and care for than everybody''s own little bubble (HA - UW referenced joke!) including my own!","inspiration_to_apply":"I choose BTM because I find your work inspiring and heavily respect all the work and ethics you put into your own company and project. The effort that goes into one single video, which is A LOT of work, especially the UW related videos. I obviously don''t know all members or even half of the personalities, BUT it seems like an open-minded, interested and very passionate team. And I think with a possibility like this, it would be amazing to exchange stories and learn from all of you. And why underwater filming? I think in this time, with climate change approaching, it is SO important to show the world what lays beneath the ocean and about single species itself! Of course, you can say the same about wildlife above the water, but I think the underwater world doesn''t get enough credit, and it''s so incredibly beautiful. It deserves to be seen and should inspire people like it does inspire me! To go out, explore, leave their comfort zones and witness and protect!","referral_source":["Found your YouTube channel a couple of years ago while searching for dive locations in Europe"],"questions_or_concerns":"Since I''m currently traveling, my plans are super flexible, but I would love to know what are the organizational aspects of the academy. Like when would it start, where would the workshops take place, would there be active projects we would be able to accompany? How many people would join one group project, etc. Thanks guys!","anything_else":"Just how incredibly cool this opportunity is!! Haha, sorry to be THIS excited, but I think UW filmmaking including the video editing afterward (which I find harder than pictures) has a steep learning curve and there are plenty of creators out there, offering their services. But it''s so cool that you guys offer this! You''ve inspired me for a long time! Okay, ramble end! Thanks guys!"}'::jsonb, '{}', '[]'::jsonb, '2025-03-24T02:49:49+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Phillip Graaf","nickname":"Phill","email":"contact@cinematograaf.com","online_links":"www.cinematograaf.com, https://www.instagram.com/cinematograaf/, https://www.youtube.com/@PhillGraaf","age":"25-34","budget":"Small budget (under 1,000 €/USD)","phone":"+61 0439004981","gender":"Male","nationality":"German","country_of_residence":"Australia","languages":"English, Spanish, German, Portuguese","current_occupation":"Freelance Filmmaker","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Divemaster","number_of_dives":"51-250","last_dive_date":"03.10.2025","diving_environments":["Tropical Reefs","Cold water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":9,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","DSLR/Mirrorless with housing"],"filming_equipment":"Sony a7III, Nimar under water housing, Keldan 4m Spectrum filter","planning_to_invest":"Yes, within the near future","years_experience":"1-3 years","skill_camera_settings":10,"skill_lighting":1,"skill_post_production":8,"skill_color_correction":7,"skill_storytelling":8,"skill_drone":9,"skill_over_water":9,"content_created":["Personal vacation videos","Social media content","Documentary style","Commercial work","Scientific/Research documentation"],"btm_category":"DEDICATED ACHIEVER (Business-focused, seeking intensive mentorship)","involvement_level":"Part-time professional","online_presence":"Active social media, Personal website, Professional portfolio","income_from_filming":"Occasionally (few projects per year)","primary_goal":"Enhance existing professional skills","secondary_goal":"Document marine conservation/research","learning_aspects":["Lighting techniques","Business aspects of underwater filming","Client relations and project management","Conservation documentation","getting the right contacts","collaborating on projects with bigger clients","building my professional UW equipment"],"content_to_create":["Documentary style films","Commercial/advertising content","Scientific/research documentation","Conservation stories","Mainly Documentary style films but would love to work on commercial work as well"],"learning_approach":["One-on-one mentorship","Mixed approach (combination of group and individual)"],"marine_subjects":["Big marine life (sharks, whales, etc.)","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Depends on duration and location","start_timeline":"Flexible/Not sure yet","ultimate_vision":"My vision is to be contracted by oragnisations and companies to shoot under water stories that captivate and inspire.\nI would love to to be financially in a position where I can afford to shoot with the right equipment that meets my needs and makes camera operation under water easier than what it is right now. I''d like to work on commercials but the dream is to take part in big-name documentaries like planet earth, natgeo or the like. My dream is to create stories that do not only captivate visually but also something good for the planet. After all being able to combine my passion for cinematography, diving and conservation would make me incredibly happy. For this reason it would be amazing to create a film e.g. that makes it into the world ocean film tour.","inspiration_to_apply":"The second I saw my first nature documentary in the IMAX Cinema when I was 6 years old I knew, that I wanted to create saomething like that. Back in the days I thought what I had to do was science, nowadays I know that cinematography is and has always been the drivign factor. I was inspired to apply because I have been following BTM for a long time and actually tried to get in touch a few times to see whether it would be possible for me to work with you one day. I appreciate your professionalism and the projects you work on as well as the content you share with the world.","referral_source":["YouTube"],"questions_or_concerns":"I guess my most important question would be how hands-on this course would be. I have been making films for almost 10 years and what I truly lack the right equipment for under water shooting as well as experience in working with the right people in the right places. I need to get the right connections, get into the right space and collaborate with the right people, since the foundation is already laid :-) My biggest struggle is how to get into the industry of wildlife filmmaking, how to be seen and how to get the right jobs.","anything_else":"I currently live in Australia but have a German citizenship. I would love to travel for something like this, it only depends on the money, as I am still in the building phase of my business here in Australia.\n\nThanks for the consideration and have a lovely day."}'::jsonb, '{}', '[]'::jsonb, '2025-03-24T01:48:45+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('filmmaking', 'reviewing', NULL, '{"first_name":"Anthony Brady","nickname":"Irish","email":"farkinrishmate@gmail.com","age":"45-54","budget":"Small budget (under 1,000 €/USD)","phone":"+6147895799","gender":"Male","nationality":"Irish","country_of_residence":"Australia","languages":"English","current_occupation":"Scuba instructor,skipper","physical_fitness":"Good - Moderately active, no major health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving"],"certification_level":"Instructor, Certified Freediver","number_of_dives":"250+","last_dive_date":"10.03.2025","diving_environments":["Tropical Reefs","Cold water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":9,"equipment_owned":["Compact camera with housing","Lighting equipment"],"filming_equipment":"Canon G7xiii fantasea housing seafrog strobes, and a few weefine wet lens''s","planning_to_invest":"Yes, within the next years","years_experience":"1-3 years","skill_camera_settings":7,"skill_lighting":7,"skill_post_production":7,"skill_color_correction":7,"skill_storytelling":6,"skill_drone":1,"skill_over_water":5,"content_created":["Social media content"],"btm_category":"INDEPENDENT CREATOR (Experienced hobbyist/influencer seeking improvement)","involvement_level":"Hobby only","online_presence":"Active social media","income_from_filming":"No, not yet.","primary_goal":"Transform hobby into professional career","secondary_goal":"Document marine conservation/research","learning_aspects":["Basic equipment setup and operation","Camera settings and techniques","Marine life behavior understanding","Storytelling and content planning","Post-production and editing","Business aspects of underwater filming","Conservation documentation"],"content_to_create":["Documentary style films","Commercial/advertising content","Scientific/research documentation"],"learning_approach":["Small group workshop (within a group of approx. 4 persons)","Mixed approach (combination of group and individual)","Project-based learning (within a BTM project)"],"marine_subjects":["Coral reefs","Big marine life (sharks, whales, etc.)","Macro subjects","Marine behavior","Conservation stories"],"time_availability":"2-3 entire weeks at a time for a workshop, aproject or individual training","travel_willingness":"Yes, willing to travel internationally","start_timeline":"Flexible/Not sure yet","ultimate_vision":"I would like to make films where David Attenborough says \"I would like to narrate that\"","inspiration_to_apply":"When I started diving I was always drawn to your videos and always wanted to make films that good","referral_source":["Social Media (Instagram, Facebook, etc.)"],"anything_else":"I have worked on the Rodney Fox and seen a lot of the best photographers and filmmakers at work so I sorta know what to do"}'::jsonb, '{}', '[]'::jsonb, '2025-03-23T22:11:07+00:00');
