INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('photography', 'reviewing', NULL, '{"first_name":"Marta","last_name":"Paris Boix","email":"Ran9waves@protonmail.com","online_links":"@hellatheviking (instagram)","age":"35-44","budget":"Moderate budget (1,000 - 3,000 €/USD)","nickname":"Marta","phone":"(+351)913088239","gender":"Female","nationality":"Spanish","country_of_residence":"Portugak","languages":"English, Spanish, French, German, Portuguese,Catalan","current_occupation":"Ux designer + cybersecurity","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Snorkeling"],"certification_level":"Open Water","number_of_dives":"0-50","last_dive_date":"18.09.2024","diving_environments":["Tropical Reefs","Mediterranean"],"buoyancy_skill":8,"equipment_owned":["Action camera (GoPro, Osmo, Insta360, etc)","Compact camera with housing","DSLR/Mirrorless with housing"],"photography_equipment":"Sony rx100 mark IV + saltwater waterhousing, gopro and also a liquid eye waterhousing for canon eos 7 mark II (unluckily I lost that camera while doing water photography)","planning_to_invest":"No immediate plans","years_experience":"1-3 years","skill_camera_settings":7,"skill_lighting":4,"skill_post_production":9,"skill_color_correction":7,"skill_composition":9,"skill_drone":1,"skill_over_water":8,"content_created":["Personal vacation photography","Social media content"],"btm_category":"INDEPENDENT CREATOR (Experienced hobbyist/influencer seeking improvement)","involvement_level":"Hobby only","online_presence":"Active social media","income_from_photography":"No, not yet.","primary_goal":"Improve content creation for social media","secondary_goal":"Document marine conservation/research","learning_aspects":["Basic equipment setup and operation","Camera settings and techniques","Lighting techniques","Marine life behavior understanding","Composition and content planning","Post-production and editing","Business aspects of underwater photography","Conservation documentation"],"content_to_create":["Personal/travel memories","Social media content","Documentary style photo series","Commercial/advertising content","Scientific/research documentation","Conservation stories"],"learning_approach":["Mixed approach (combination of group and individual)"],"marine_subjects":["Big marine life (sharks, whales, etc.)","Marine behavior","Conservation stories"],"time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Depends on duration and location","start_timeline":"Flexible/Not sure yet","ultimate_vision":"I would like to improve my underwater photography skills to produce awesome creative content either for myself or (ideally) to get clients as a side project either for conservation, commercial ...","inspiration_to_apply":"I saw the involved staff on it whom zi already admire and follow through social media due to their skills, and felt motivated to learn to achieve their level (one day)","referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"Understand better marine life and its environment , to be able not only to produce good content but also to respect the boundaries or animals without stressing them nor put myself in danger.","anything_else":"All has been said so far :)"}'::jsonb, '{}', '[]'::jsonb, '2026-04-04T14:30:45+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Maximilian","last_name":"Schneider","email":"maxlued@web.de","phone":"016091605487","age":"29","gender":"Male","nationality":"German","country_of_residence":"Germany","languages":"English, German","azores_ties":"No, I haven''t.","current_occupation":"I work for an event agency that organizes marathon events in the logistics and fleet department","education_level":"Bachelor''s degree","field_of_study":"Eventmanagement- technical","recent_activities":"I studied until the summer of 2024 and have now been working fulltime for a year. However, activities such as underwater rugby and scuba diving have taken up most of my time over the years.","filmmaking_experience":"At first, I recorded underwater videos with a GoPro Hero Black 5 and a small gimbal. Therefore, I don''t have much experience in underwater filming. However, I recently purchased an underwater camera housing from Isotta for my Sony A7 III, including video lights from Keldan (Samyang 35mm and Zeiss 55mm lenses). Photography has been another hobby of mine for 8 years. Until now, my only underwater subjects have been my underwater rugby teammates and a pike.","filming_equipment":"Sony a7 III, Zeiss 55mm lens, Samyang 35mm lens, Isotta Housing, buoyancy arms, Makroport M67, 2 KeldanLights 10000 lm","content_created":["Underwater photography"],"inspiration_to_apply":"In fact, in 2020, I wanted to do an internship at Behind the Mask while I was studying. I even took part in your call for submissions, where you collected video material from your community to create a video that you presented at Boot. I saw the video live at Boot. Unfortunately, none of my clips were included, which I can totally understand in hindsight - they were terrible.  Unfortunately, there were no internships advertised at the time, and I didn''t dare to apply on my own initiative, which I actually regret very much. But last weekend I was at Boot and saw the Ocean Hub and your presentation of South Alor, and afterwards I just wanted to check your website out of interest to see if there were any job vacancies. Then I saw the “Internship” blog with the “apply now” button and immediately thought to myself, I have to go for it now, because I won''t get another chance. And that was ultimately my motivation for applying here.","ultimate_vision":"I want to take as many pictures and films as possible underwater and show them to people who have no connection to the underwater world, who have an unfounded fear of it, and who therefore convey a negative image of this fascinating world. Some people simply don''t know any better, but that''s exactly why I want to reach people with my films, so that they can get to know the real underwater world as it is - simply beautiful.","hoped_gains":"My main focus is on becoming a better underwater videographer so that I can concentrate on the actual goal - filming another world that is worth fighting for and worth showing to the public. But I also want to gain experience in organizing these kind of projects and designing the concepts. I want to get a clear picture of what goes into productions like this, learn about the actual planning and implementation and find out at the end whether the project was successful.","why_good_candidate":"Because I am convinced by the idea and concept behind your foundation. I am already a diver and have seen several dive sites around the world. I love the ocean and all the creatures that live in it, and I already have experience with photography. I am also very familiar with the event industry. I know what it means to work overtime, to respond to every customer request to ensure their satisfaction and to still be able to focus on the task and the goal despite all the stress. Therefore, I believe that I am a good candidate for the internship.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Advanced Open Water, DOSB - Trainer License, GDL Freediving Indoor Specialty (AK Apnoe 1), Dry Suit Diver","number_of_dives":"51-250","last_dive_date":"08.10.2025","diving_environments":["Tropical Reefs","Open water","Cold water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":8,"referral_source":["Online search"],"questions_or_concerns":"What i would like to know is the duration of the internship, when it will begin and will there also be a separate mini-project that I will supervise myself?","anything_else":"That''s it. I look forward to hearing from you!"}'::jsonb, '{}', '[]'::jsonb, '2026-01-21T21:03:43+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Francisco","last_name":"Amorim","nickname":"Chico","email":"francisco.n.amorim.9@gmail.com","phone":"+1 (250) 615-9732","age":"30","gender":"Male","nationality":"Portuguese","country_of_residence":"Canada (until May)","languages":"English, Spanish, Portuguese","online_links":"instagram.com/francisco_n_amorim\ninstagram.com/oceandumplings","azores_ties":"I can probably find connections. No friends currently living there, but possibly friends of friends.","current_occupation":"Educational Assistant at a school / Scuba Instructor","education_level":"Bachelor''s degree","field_of_study":"Tourism management. PADI and SSI instructor since 2019 (currently taking a break from it)","recent_activities":"Lots of scuba diving, both as a hobby and a job, freediving, underwater GoPro filming (amateur), rock climbing, volleyball, wood chopping. Last year I spent it travelling, doing Workaways, to learn new skills and meet awesome people :)","filmmaking_experience":"Everytime I fun dive, I take my GoPro with me and try to take cool videos. I´ve created some Instagram reels, using DaVinci, but what I really like is trying to capture the moments underwater.","filming_equipment":"GoPro Hero 11 Black (trying to sell it to get something much more professional)\nDJI Mini 4 Pro (drone)","content_created":["Personal vacation videos","Social media content"],"inspiration_to_apply":"I  have been thinking about investing in proper training to learn underwater filming, for a while now. The moment never seemed right and the funds were low. Last year I decided to take a step back from the diving industry, to really think about what I would love to do with my life. The conclusion was always the same. I grew up watching wildlife documentaries and have always been fascinated by them. A few years after I started scuba diving, I randomly found an action camera, during a dive and since then, every time I go fun diving, I take my camera with me. I just love trying to get close to marine life and capture their soul (without disturbing them too much of course). About 4 years ago, I heard a talk from Nuno Sá (Portuguese underwater videographer), that really inspired me and made me realise that with some effort and luck I could potentially turn this hobby into a dream job. Since then I''ve been practicing and I think now is the right time for me to seriously invest some time and money into this. Why BTM Academy? I''d been trying to find underwater filming courses for a few weeks but somehow I hadn''t realised BTM had their own courses. Today my girlfriend sent me a link for this page. I have been watching your videos for years now. You guys are sensational. \"This is it\". I''m ready to make my dream reality.","ultimate_vision":"My ultimate goal would be to work as an underwater cameraman for big productions, like BBC wildlife documentaries. Working with a team, trying to capture the images to tell stories of the underwater world. Making people fall in love with the ocean and all it''s wonders and inspiring them to protect it (which we desperately need).","hoped_gains":"I completely lack the technical knowledge of anything camera related. I need to learn that. What equipment should be used and how to use it. I''d love to learn not only how to take beautiful videos, but more importantly, how to turn them into stories that will captivate and inspire people. Aside from that, understanding how a big, professional, underwater filming team works, would be incredible. Seeing all it''s beauties and it''s challenges and trying to understand what is needed to make it in the business.","why_good_candidate":"I truly think I''d be a good candidate for this internship. I''ve worked in many different teams, in different jobs, in different countries and I''ve always heard the same thing. People mostly really like working with me and being around me. Not because I''m the best at what I''m doing (far from it), but because I have a good, serious work ethic. I work hard, I''m humble and I always try to make people around me enjoy their time while being alongside me. I really think I''d be a good addition to help you in your Açores expedition. Someone nice, smiley, hard-working, passionate, very eager to learn, serious about making a career out of it and with quite a bit of experience in diving. I know this is not a job application, but I believe lots of the same things apply. I''d love to learn with the best :)","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving"],"certification_level":"Instructor, Not a certified freediver","number_of_dives":"250+","last_dive_date":"15.05.2025","diving_environments":["Tropical Reefs","Open water","Cold water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":10,"referral_source":["Youtube"],"questions_or_concerns":"I''m currently under a working contract in Canada that will finish in May 2026. Afterwards, I''m heading to the Maldives on a diving trip for 8 days. After that, I''m ready to work hard and learn. Just so you know my time frame...","anything_else":"My girlfriend, Bella is also very much an underwater lover. A diver, filming enthusiast, who has currently applied for a masters in Science Communication in one of the best universities in the world. Our goal would be to one day work together, sharing our passion and educating people about conservation. We''re very serious about turning this into our careers."}'::jsonb, '{}', '[]'::jsonb, '2026-01-22T07:00:13+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Thomas","last_name":"Hunt","nickname":"Tom","email":"tomhunttravels@gmail.com","phone":"+447599043002","age":"25","gender":"Male","nationality":"UK","country_of_residence":"UK","languages":"English","online_links":"Instagram- https://www.instagram.com/tom_underwater_?igsh=eDk3aDZkeTRyNDY0&utm_source=qr\n\nTikTok-\nhttps://www.tiktok.com/@thomas_hunt_?_r=1&_t=ZN-93KmSC0Y9Ic","azores_ties":"No","current_occupation":"Content creator","education_level":"Master''s degree","field_of_study":"Marine Biology","recent_activities":"Scuba diving (becoming and working as a divemaster), Freediving, Travelling full time running travel+diving/marine biology social media accounts, Whale watching tour guide and deckhand","filmmaking_experience":"Spent the past 2 years filming with only GoPro''s and insta360s travelling and diving mainly around SE Asia, however the past few months I''ve upgraded to a TG7 and Sony A7s iii. I use the videos to create social media content (mainly short form content) from 10-20 second reels to 2 minutes. Ranging from educational content to short trending videos. Now wanting to make the next step into Short films and long form YouTube content.","filming_equipment":"Sony A7S iii, OM TG7, GoPro 12, Insta 360 x4","content_created":["Personal vacation videos","Social media content","Scientific/Research documentation","Underwater photography"],"inspiration_to_apply":"Heavily inspired by a lot of your YouTube videos, from the super helpful videos from Vanessa to the stunning short films!","ultimate_vision":"As a marine biologist, I believe one of the major areas we''re lacking is science communication! It''s all good and well us researching and creating lots of scientific papers, however non of the public see or even know about what''s truly happening. As a result, in this day and age I truly believe social media to be the greatest tool in reaching the public, especially on a day to day basis. That''s why I''m extremely keen to learn underwater filmmaking to be another voice for our oceans, hopefully igniting curiosity, inspiring change and ultimately educating the public, as you cannot protect what you don''t know about.","hoped_gains":"Better knowledge and skills of both filming and post procedures, such as colour grading and sound design, as well as a greater understanding of the industry and knowing how to navigate and plan projects start to finish.","why_good_candidate":"I''m a fast learner and someone very keen to learn as well. I''m accustomed to working very long hours with physical and stressful work as well as travelling far to remote regions. I hold myself to a very high standard, reaching goals and targets not only set by my employer but by myself too, combined with my lust for perfectionism, I''ll keep trying only until I''m satisfied with the results. I also love to work independently or as a team. From growing up as an only child and solo travelling the world for the past 2 years, I''ve become very independent and great at time management/organisation. Additionally, I also thrive working in teams, ranging from adopting a leadership role to carrying any tasks out required of me without any issues.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Divemaster","number_of_dives":"250+","last_dive_date":"13.01.2026","diving_environments":["Tropical Reefs","Open water","Cold water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":10,"referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"Mainly just how the internship works overall from itinerary to costs and if there''s also any possible chances for projects in the future afterwards?"}'::jsonb, '{}', '[]'::jsonb, '2026-01-24T08:05:09+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Henning","last_name":"Becker","nickname":"Hen","email":"beckerhenning@aol.com","phone":"+491704918922","age":"27","gender":"Male","nationality":"german","country_of_residence":"Germany","languages":"English, Spanish, German, French is not fluent but more a means of getting along","online_links":"https://beckerhenning.myportfolio.com/\nhttps://www.instagram.com/henning_bk/\nhttps://www.instagram.com/henlikesitwet/","azores_ties":"Not yet","current_occupation":"Science Communicator at Leibniz ZMT, Student at University of Bremen","education_level":"Bachelor''s degree","field_of_study":"International Studies of Aquatic Tropical Ecology, Science Communication","recent_activities":"Primarily my studies in marine tropical ecology, but on the side my education as a european scientific diver, and working as an instructor in the recreational scuba industry. During that time I am taking photos on scuba / freediving, learning about gear and techniques as well as post-processing of photos. Currently working on my social media presence and have recently launched a dedicated public marine photography instagram. I am also working at the Centre for Tropical Marine Research of the Leibniz Association in public outreach, internal and external communication, working with scientific results, marine policy and management.","filmmaking_experience":"Handheld video filming and editing on scuba and apnea for videos for personal use and documenting my scientific diving training. Some shots are seen on my Instagram profiles. I am currently more into photos but have a high interest in improving video skills.","filming_equipment":"Olympus TG-7 with one video light and a tray","content_created":["Personal vacation videos","Social media content","Overwater photography","Underwater photography"],"inspiration_to_apply":"I have many friends and contacts in the scuba and scientific community and have seen you at the Boot and online.","ultimate_vision":"My ultimate dream would be to stand both in front and behind the camera, sharing engaging educational and entertaining content. This could be on television or online, independently or with a team. I would love to see my work on a big screen and even though I have a science/research background, I believe that my true call is to get knowledge in a fun, digestible way out into the world. I want to write my own stories and inspire others, forming ocean literacy and interest.","hoped_gains":"I want to see the workflow of professionals, learn where I can optimize my own, and see how and what preparation is done, because I feel this is where I lack the most crucial expertise. Also, I am sure that through this internet I will make connections that I can profit from in manifold ways.","why_good_candidate":"I bring solid diving skills, together with a scientific background and good general understanding of the ocean and its inhabitants through my studies. I enjoy writing and discussing my own ideas and can see myself as part of your team, bringing fresh ideas above the surface and executing them below.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Instructor","number_of_dives":"250+","last_dive_date":"17.01.2026","diving_environments":["Tropical Reefs","Open water","Cold water","Deep diving","Night diving"],"buoyancy_skill":9,"referral_source":["Diving community"],"questions_or_concerns":"I would need to know when the internship can take place, as I will be on a research excursion of multiple months this year.","anything_else":"Thank you for your consideration."}'::jsonb, '{}', '[]'::jsonb, '2026-01-24T13:08:21+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Lena","last_name":"Schaffeld","nickname":"leni","email":"lena.schaffeld01@gmail.com","phone":"+491736151504","age":"24","gender":"Female","nationality":"German","country_of_residence":"Spain","languages":"English, Spanish, German","online_links":"lena_schaffeld","azores_ties":"yes, I have worked on the islands the past two summers as a Marine Biologist","current_occupation":"Marine Biologist Freelancer","education_level":"Master''s degree","field_of_study":"Marine Biology","recent_activities":"sailing (did a 6 weeks voyage), scuba- and freediving, surfing, languages courses, non-profit work (still doing that), analog photography","filmmaking_experience":"I have very little experience, only taking some photos and images with my GoPro","filming_equipment":"GoPro 11","content_created":["Personal vacation videos","Social media content"],"inspiration_to_apply":"As a marine biologist, I am fortunate to spend a lot of time underwater - often witnessing incredible beauty, but also the harsh reality of human impact, such as plastic pollution. I want to be able to capture both: the awe-inspiring biodiversity and the “ugliness” that threatens it, and turn these moments into powerful visuals that can educate, move, and inspire people who may never see the underwater world themselves.\n\nI previously conducted research in the Azores, and its rich biodiversity and dramatic seascapes left a lasting impression on me. It feels like the perfect setting to learn how to translate science and emotion into compelling underwater imagery. BTM Academy stood out to me because it combines professional-level training with real-world ocean experiences. I see it as the ideal place to bridge my scientific background with creative storytelling and to begin building the skills I need to communicate ocean issues through film.","ultimate_vision":"My ultimate vision is to integrate underwater filming as a core, complementary part of my career as a marine biologist. I believe that images and films can reach people on an emotional level in a way that scientific papers alone often cannot. By combining rigorous science with strong visuals, I want to help make the ocean “real” for those who have never looked beneath the surface.\n\nEven though I am only at the beginning of my filming journey, I dream of one day contributing to impactful documentaries focused on shark and ray conservation and on the reality of microplastic pollution in our oceans. I hope to create stories that not only inform but also empower viewers to care, change behavior, and support conservation efforts. In the long term, I would like my work to sit at the intersection of research, storytelling, and advocacy - using underwater filming as a tool to protect marine ecosystems and the species I work with.","hoped_gains":"From this internship, I hope to gain a solid foundation in the full process of underwater storytelling - from capturing images to crafting a narrative. This includes learning how to handle cameras and equipment underwater, how to compose and light shots in a challenging environment, and how to edit footage into a cohesive, emotionally engaging story. \n\nI also want to understand the technical side in depth: gear maintenance, dive logistics for filming, workflow for post-production, and best practices for working ethically with wildlife. Beyond the hard skills, I hope to meet and learn from people who share my passion for the ocean and visual storytelling. Building a network of mentors and peers in underwater filmmaking would be incredibly valuable as I continue to develop my own voice and carve out a path that connects marine science and film.","why_good_candidate":"Although my experience in (underwater) photography and filming is still limited, my commitment to the ocean runs very deep. I have made it my life’s mission to protect marine ecosystems, and this mission drives me to work hard, to learn quickly, and to push myself outside my comfort zone when it is in service of the ocean.\n\nI am very comfortable in the water, with extensive experience diving and conducting research at sea. My background as a marine biologist gives me a strong understanding of marine life, animal behavior, and ecosystems, which can be an invaluable asset when planning and capturing meaningful underwater stories. I also already engage in science communication and education, so I understand how to translate complex topics into accessible messages.\n\nWhat I may lack in technical filmmaking experience, I make up for in motivation, resilience, and a genuine passion for using storytelling to protect the ocean. I would bring curiosity, a strong work ethic, and a conservation-focused perspective to the BTM Academy team, and I am ready to fully commit to making the most of this opportunity.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Advanced Open Water","number_of_dives":"51-250","last_dive_date":"08.03.2025","diving_environments":["Tropical Reefs","Open water","Cold water","Cave/Wreck diving"],"buoyancy_skill":7,"referral_source":["Diving community"],"anything_else":"I will be back in the Azores in summer 2026. I plan to do my divemaster and work again as an expedition leader for the non-profit Sail and Explore Association, in collaboration with Okeanos Research Institute."}'::jsonb, '{}', '[]'::jsonb, '2026-01-27T10:35:45+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Rémi","last_name":"Conte","nickname":"Rémi Conte","email":"remi.conte1@gmail.com","phone":"+33 7 86 28 36 15","age":"27","gender":"Male","nationality":"French","country_of_residence":"France","languages":"English, French","online_links":"https://www.instagram.com/remi__photo/\nwww.remiconte.com","azores_ties":"No, I don''t","current_occupation":"Freelance underwater photographer / visual storyteller","education_level":"Master''s degree","field_of_study":"Marine Biology and Underwater Photography","recent_activities":"Over the past few years, I have mainly focused on working and developing projects related to the ocean and marine environments.\nI worked as a marine guide and naturalist in French Polynesia, spending extensive time in the field, underwater and in close contact with marine ecosystems.\nI also gained experience as a marine naturalist guide in Madagascar (Nosy Be), contributing to education and awareness around marine biodiversity.\nIn parallel, I have been actively developing my skills and personal projects in underwater photography and video, focusing on improving my technical abilities, visual composition and storytelling.\nThrough self-directed projects, exhibitions and field experience, I am continuously working to grow as a visual storyteller, combining science, art and ocean conservation.","filmmaking_experience":"My experience in underwater filmmaking is mainly based on field practice and self-directed projects.\nI have filmed underwater sequences during scientific, exploratory and personal projects, focusing on marine life, environments and human interaction with the ocean.\nSo far, my work has been more oriented toward underwater photography, but I am actively integrating video into my projects, aiming to improve my filming techniques, storytelling, camera movement and post-production skills.","filming_equipment":"Sony Alpha 6000\nUnderwater housing (Seafrogs SaltedLine)\nLightweight Aluminium Tray\nSea Frogs V6 Dome Ports\nPhare BigBlue CB 15000P\nStandard flat port\nGoPro HERO11\nDJI Mini 2 Drone","content_created":["Personal vacation videos","Social media content","Scientific/Research documentation","Overwater photography","Underwater photography"],"inspiration_to_apply":"I have always been drawn to the underwater world through science, fieldwork and image-making.\nWith a background in marine biology and a strong practice in underwater photography, I developed a deep interest in visual storytelling below the surface.\nOver time, I became increasingly interested in underwater filmmaking as a complementary medium, allowing me to explore movement, behavior and atmosphere, while continuing to refine my photographic approach.\nI chose BTM Academy because of its hands-on, mentorship-based approach, where photography and filmmaking are both considered essential tools for telling meaningful underwater stories.\nThe philosophy of BTM, combining creativity, technical skills and respect for the marine environment, strongly resonates with my desire to grow as a visual storyteller, both in photography and video.","ultimate_vision":"My long-term vision is to build a solid path in underwater imagery, combining photography and film in the service of strong, ocean-related stories. I aim to develop visual projects that portray the marine world with sensitivity and depth, finding a balance between an artistic approach to imagery and a deep understanding of the living world.\n\nMy goal is, over time, to create underwater wildlife documentaries conceived as immersive works, allowing space for observation and storytelling. I want to work on long-term projects focused on behavior, interactions and the raw beauty of the underwater world, using a visual language inspired by major wildlife documentaries.\n\nThrough these projects, I primarily seek to convey emotion and a sense of wonder for the living world, convinced that the beauty and poetry of the underwater realm are, in themselves, powerful drivers of awareness.\n\nIn this perspective, I am also eager to discover and understand teamwork, the demands of professional production, and the realities of working in the field.","hoped_gains":"Through this internship, I hope to gain a concrete and formative experience in the field of underwater imagery. I want to improve my technical skills in both photography and filmmaking, particularly in terms of camera work, camera movement, light reading and the overall visual coherence of a project.\n\nI also see this internship as a rich field experience, allowing me to work in real conditions, spend time in the water, observe marine life and adapt to the natural and logistical constraints specific to the marine environment.\n\nI would like to learn how to conceive and develop underwater visual projects in a more professional way, from the initial intent to the final outcome, by understanding the different stages of preparation, filming and post-production.\n\nBeyond technical aspects, I want to discover how a production team operates, learn to work within a demanding collaborative environment, and benefit from mentorship and feedback from experienced professionals. This internship represents a key step for me to gain rigor, confidence and clarity in my underwater visual journey.","why_good_candidate":"I believe I am a strong candidate for this internship because I combine solid field experience in marine environments with a committed practice of underwater imagery. My background in marine biology, along with my experience as a lifeguard and marine naturalist guide, has allowed me to develop a strong understanding of ecosystems, animal behavior and environmental conditions, as well as a high level of comfort in the water.\n\nI am also a certified professional diver (CAH IB), which enables me to operate safely and efficiently underwater, including in demanding conditions.\n\nIn parallel, I have been developing personal projects in underwater photography and imagery for several years, with an autonomous, serious and constantly evolving approach. I am used to learning in the field, observing carefully, adapting to situations and critically questioning my own work.\n\nI am a motivated, committed and curious person, with a strong ability to work as part of a team and to integrate into demanding environments. This internship represents a major opportunity for learning and growth, and I am ready to fully invest myself with seriousness, rigor and enthusiasm.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling","Scientific Scuba diving"],"certification_level":"CMAS 3 Diver (French Level 3 – Autonomous diver)","number_of_dives":"250+","last_dive_date":"10.12.2025","diving_environments":["Tropical Reefs","Open water","Night diving","Cave/Wreck diving"],"buoyancy_skill":8,"referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"I do not have any specific concerns at this stage.\nI would be interested in learning more about how the internship is structured on a day-to-day basis, and how interns typically contribute to ongoing projects within the Academy.\nI am also curious to understand how mentorship and feedback are integrated throughout the internship experience."}'::jsonb, '{}', '[]'::jsonb, '2026-01-27T14:02:36+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Yevheniia","last_name":"Rehush","nickname":"Jenny","email":"jrehushuw@gmail.com","phone":"+971 50 592 0884","age":"36","gender":"Female","nationality":"Ukrainian","country_of_residence":"Ukraine","languages":"English, Ukrainian Russian","online_links":"https://www.instagram.com/underwater.visuals?igsh=MXBkdDBuNnpqenF4OA%3D%3D&utm_source=qr","azores_ties":"No","current_occupation":"Underwater photographer and videographer, freediving instructor","education_level":"Master''s degree","field_of_study":"Master of Philology; Bachelor of Design; CMAS certified underwater photographer; AIDA freediving instructor","recent_activities":"Four years works with a freediving school as underwater photographer, and freediving coach","filmmaking_experience":"CMAS certified photographer. Three years Official underwater photographed and videographer for Apnea Pirates AIDA CUP, official underwater photographer for AIDA World championship 2024, official underwater photographer for Malaysia Apnea Warrior Championship 2026. Filming commercial for Atlantis, Huawei. Video editor at Deep Dive Dubai. Home underwater photographer and videographer for freediving school Freediving UAE. Personal underwater photoshoot for mermaids and cosplay.","filming_equipment":"Sony A7R V, lens 16–35mm GM II. DJI Osmo Action 6, Insta 360 X5","content_created":["Social media content","Documentary style","Commercial work","Scientific/Research documentation","Underwater photography","Freediving competition","personal underwater photo shoot (maternity, flying dress, cosplay, Mermaid"],"inspiration_to_apply":"Before I started filming underwater, I was never really interested in shooting on land. After mastering my freediving skills and discovering the beauty of modeling underwater — both in freediving and scuba modes — I realized that I wanted to move to the other side of the camera and become an underwater photographer.\n\nI’m grateful that I had a mentor and a supportive community back in my home country, Ukraine, who helped me take my first steps and make this dream real. I truly enjoy learning new skills, practicing consistently, and developing them to a professional level. \nOver the past four years, I’ve worked with freediving schools and created personal underwater photoshoots for clients and bloggers.\nI’ve always loved having a human presence in my frames, but now I feel ready to explore a new direction where Maureen inhabitant I will be in the first place. As a first step, I completed a marine conservation course and started working with the Atlantis Conservation Program in Dubai, supporting shark and ray release initiatives.\nI’m still a student of the ocean. I’m always looking for new expeditions, new challenges, and new mentors — just like when I first started freediving and photography. When I found BTM Academy and the people behind this project, it felt like the right environment for me: a place with the same vision of respecting and protecting the ocean while creating meaningful stories beneath the surface.","ultimate_vision":"I was born in a seaside town and have always lived close to the sea or the ocean. But I know that many people don’t have this connection. That’s why I believe it’s important to show the beauty of the ocean — and also to show how even people who live far from the sea can still affect it, sometimes harming it from thousands of kilometers away.\n\nEspecially today, when we are all connected through social media, we have a powerful opportunity to show this reality directly to people. Even short-form content can make an impact. I truly believe that underwater photographers and videographers can influence awareness about ocean health and help people understand how deeply the ocean matters — not just for those who live near it, but for the entire planet.","hoped_gains":"In my professional life, I’ve completely changed my career direction three times. Each time was challenging and sometimes scary, but I actually love that feeling — seeing myself move through uncertainty and grow into a more skilled professional than I was before.\n\nNow, I feel like I’ve found the direction of my professional life that truly fits me and could stay with me long-term. I’m really excited about this internship and hopeful that it will once again change my life in a meaningful way.","why_good_candidate":"When I look back at who I was before I started scuba diving, freediving, and underwater filmmaking, I sometimes wonder how I ever lived without it. Back then, I was a “land person.” I saw the sea as something that simply existed. Once I began to truly understand the ocean, everything changed. It’s no longer just a place for me; it’s a world I want to keep exploring, learning from, and respecting. I can’t imagine my life without diving deeper into this connection.\n\nNow, I feel ready to become a student of the ocean again. I’m looking for a strong mentor and the right environment to grow. I truly believe that the BTM Academy internship has come into my life at the right time — as a chance to learn more, to challenge myself, and to deepen my understanding of the ocean.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Advanced Open Water, Rescue Diver, Certified Freediver, specify level below, AIDA instructor","number_of_dives":"51-250","last_dive_date":"24.07.2023","diving_environments":["Underwater modeling. Last four years","I focus only on freediving mode."],"buoyancy_skill":8,"referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"From the social media, I learn about the mentor but it less information about how internship look like where and when. And most important part for me the financial aspect."}'::jsonb, '{}', '[]'::jsonb, '2026-01-31T07:37:15+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Olivia","last_name":"Grubenmann","nickname":"Oli","email":"olivia.grubenmann@gmail.com","phone":"0793281618","age":"30","gender":"Female","nationality":"Swiss","country_of_residence":"Switzerland","languages":"English, German","online_links":"Website: www.oliviagrubenmann.com, Instagram: @oliviagrubenmann","azores_ties":"No, unfortunately not. Only know some people on Sao Miguel, Azores","current_occupation":"Channel manager at SRF Impact, and communications & content creation at rrreefs","education_level":"Master''s degree","field_of_study":"Bachelor in communications and philosophy, Master in marine conservation","recent_activities":"- redirecting my career to marine conservation and ocean literacy\n- scuba diving (conservation divemaster with Indo Ocean Project in Nusa Penida)\n- freediving\n- yoga (incl. yoga teacher  training)\n- supporting a friend with his scuba dive record attempt ''Across Maldives''\n- creating the ''Roots to Reefs'' social media account, together with 3 female friends, where we hope to share free or los cost opportunities in ocean conservation with other young people\n- mobile film-making and video editing for the Swiss hiking trails organisation\n- writing and publishing a travel guide about Zurich\n- raising awareness on ocean conservation in Switzerland","filmmaking_experience":"Mostly self-taught, playing around with my TG7 and GoPro, watching tutorials, learning from photography friends, taking a basic one-day SSI underwater photography course","filming_equipment":"TG7 + housing and a GoPro Hero11 + dome port","content_created":["Personal vacation videos","Social media content","Commercial work","Scientific/Research documentation","Overwater photography","Underwater photography"],"inspiration_to_apply":"I fell in love with scuba diving and realised that I like those dives the most where I can observe marine life for a long time and can find different ways, angles and moments to capture something. I realised that my underwater content was also very inspiring for others to see on social media, because many within my circle don’t have a lot of touchpoints with the ocean, living in land-locked Switzerland. My young cousin of 13 years old even decided to write his final paper for high school about ocean protection after having been inspired by my content on Instagram, and others told me they took up scuba diving or felt inspired to learn more about the ocean and especially coral reefs. Thinking how with even just my laienhafter content I could already inspire some people, I feel motivated that by getting more professional at underwater filmmaking, photography, storytelling and editing, I can inspire even more people to respect and protect the ocean.\n\nI chose BTM for my journey because you communicate too clearly, powerfully and without finger-pointing. Exactly what I want to do. I have seen a lot of incredible scientific progress and knowledge in marine conservation, but the message often gets stuck between overly scientific terms and overcomplicated and complex messaging. Ocean conservation needs to be simple, powerful and emotional to reach as many people as possible. And what I see from BTM is exactly that, which is why I dearly hope to learn from you.","ultimate_vision":"I feel called that by bringing the beautiful sides of the underwater world and its importance even to life on land to as many people in Switzerland as possible on one hand, and also showing the increasing threats the ocean is facing on the other. I want to learn how to take stronger footage, learn how to tell a story in a powerful way so that it sticks with people and inspires emotions, and to then also make the most out of the pictures with proper editing.\n\nI have a ton of motivation and determination, and I’ve got to see a lot of fascinating stories. Now I want to become more professional at capturing all the stories I see around me, to amplify my impact in ocean conservation and contribute to making marine science and marine conservation get more and more into the mainstream. I hope to also reach people who didn’t have a lot of touchpoints with the ocean so far, as well as decision makers like politicians and business owners, who need clear and strong messages and strong imagery to bring the ocean onto their agenda.\n\nI hope I can do this on the one hand by creating regular and strong content for the (for the moment Instagram-only) platform “Roots to Reefs” to support other young people find their way into ocean conservation, and by helping projects such as the ''Across Maldives'' dive expedition to get as much media and political attention as possible and inspire regulatory and behavioural changes.","hoped_gains":"I hope to become more proficient at storytelling, professional in handling underwater filming equipment and choosing proper settings, so that I can translate what I see underwater into clear, emotional and memorable narratives. I also hope to learn how to plan a shoot most effectively, work with light, and professionalise my post-production skills.","why_good_candidate":"I am an incredibly motivated and determined person and I love learning. Once I set my mind to something, I put in all the energy and time needed to get to where I need to be, which for me is helping to bring the ocean into the hearts and minds and onto the agendas of as many people as possible, and make it more mainstream, getting the important messages outside of the bubble of ocean lovers, marine scientists and scuba divers. I would also be a good candidate because I don’t mind long days, hard work, keeping deadlines, and I am a very organised, solutions-oriented, and reliable person.\n\nAnd I also think I am very adaptable to new situations, having lived in different parts of the world for several weeks and months, and I love being around new people, exchanging knowledge and skills. I do what I do with all my heart, and I want to not only learn and profit from the internship, but also bring my experience in marine conservation and communications and my drive and energy to the team. :)","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Divemaster, Certified Freediver, specify level below, Level AIDA2","number_of_dives":"51-250","last_dive_date":"31.01.2026","diving_environments":["Tropical Reefs","Open water","Cold water","Night diving","Working underwater (marine surveys, ID dives, coral restoration, BRUV,...)"],"buoyancy_skill":8,"referral_source":["Vanessa reached out to me via LinkedIn which is how I found out about Behind the Mask and Reef Patrol Film Production. I then saw a post about the BTM Academy on social media and felt it was exaclty what I was looking for"],"questions_or_concerns":"- What''s the duration of the internship?\n- Does it focus on film-making only or also touch on photography?\n- Financial aspects","anything_else":"Thank you for your time and I''m excited to hear from you :)"}'::jsonb, '{}', '[]'::jsonb, '2026-02-02T02:55:22+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Natalie","last_name":"Lichtenbert","email":"natalielynn.lichtenbert@gmail.com","phone":"847-340-9994","age":"54","gender":"Female","nationality":"Caucasian","country_of_residence":"USA","languages":"English","online_links":"Instagram @naturewithnatalielynn","azores_ties":"no","current_occupation":"Conservation Leader","education_level":"Master''s degree","field_of_study":"Biology","recent_activities":"gym, work, wildlife conservation including my non-profit","filmmaking_experience":"You''ve seen it","filming_equipment":"Panasonic GH-5 in Ikelite, Go Pro, Insta 360","content_created":["Social media content","Documentary style","Overwater photography","Underwater photography"],"inspiration_to_apply":"So very few people are fortunate enough to be able to get under the water.  Yet our water is one of the most important ecosystems in the world.  My goal in life has always been to save animal lives and the only way for me to do so, is to share all that there is via film.  Of course, you know why I would choose BTM Academy for not only has Behind the Mask emulated top notch quality from the very beginning, but I have also grown to love and call them my family.  My life restarted when I joined the first time and my soul said yes, this is the path for you to be on, your dream path.  I will also mention that I am looking to learn freedive dance with Julie this year, hopefully sooner rather than later.  I am just in love with everything.","ultimate_vision":"After having gone through the Academy through the Filmmaking option, I am in need of learning more about production as well, growing my skills even further and solidifying those skills already acquired.  My goal this year is to create a few mini films to submit to film festivals while also still promoting my own work as a cinematographer and my non profit Green Dolphin Project Global.","hoped_gains":"By being part of the Behind the Mask internship, I hope to gain hands-on experience in conservation-driven underwater filmmaking by working side by side with them from concept to execution. I am eager to learn how powerful visual storytelling can be used to raise awareness, inspire empathy, and drive action for marine and underwater ecosystems. Through close mentorship, I hope to deepen my understanding of how to responsibly document wildlife, translate scientific and conservation messages into compelling narratives, and produce films that not only captivate audiences but also contribute meaningfully to conservation outcomes.","why_good_candidate":"I am an excellent candidate for the Behind the Mask internship because I bring a rare combination of conservation knowledge, storytelling experience, and deep respect for the responsibility that comes with documenting underwater ecosystems. I understand that conservation filmmaking is not just about capturing beautiful imagery, but about telling accurate, ethical stories that inspire awareness and action.\n\nI am highly motivated, adaptable, and comfortable working in dynamic, unpredictable environments—qualities essential for underwater and field-based projects. I approach every project with curiosity, professionalism, and a willingness to learn, and I value close mentorship as an opportunity to grow quickly while contributing meaningfully. Most importantly, I am genuinely committed to conservation and see filmmaking as a powerful tool to protect marine life and amplify important environmental messages, making me fully aligned with the mission of Behind the Mask.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Rescue Diver, Certified Freediver, specify level below, PADI Freediver (don''t laugh!)  LOL","number_of_dives":"51-250","last_dive_date":"02.12.2025","diving_environments":["Tropical Reefs","Open water","Cold water","Deep diving","Night diving"],"buoyancy_skill":8,"referral_source":["I refilled this out because Vanessa sent it to me just in case.  I honestly want to continue being a part of the Academy in every capacity because it feels like home to me."]}'::jsonb, '{}', '[]'::jsonb, '2026-02-02T16:50:05+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Felipe","last_name":"Vasquinho","nickname":"Felipe","email":"felipevasquinho11@gmail.com","phone":"+5511996161308","age":"26","gender":"Male","nationality":"Brazilian","country_of_residence":"Brazil","languages":"English, Portuguese","online_links":"@fevasquinho https://harpyvisual.myportfolio.com/work","azores_ties":"No","current_occupation":"Comercial Photographer (I have a degree on Biology)","education_level":"Bachelor''s degree","field_of_study":"Photography","recent_activities":"Been photographing comercial stuff like products, restaurants, events, and animals for passion and fun. As a Biologist my passion is to photograph the wildlife of our planet. I shoot commercial photos/videos for living.","filmmaking_experience":"I’ve only used a gopro underwater so far, but I’ll buy a housing for my sony a7cr next month.","filming_equipment":"Sony a7cr, gopro hero 12.","content_created":["Social media content","Documentary style","Commercial work","Scientific/Research documentation","Overwater photography","Underwater photography"],"inspiration_to_apply":"As a biologist, I grew up watching every nature documentary possible. After getting my degree,  I started to teach young kids about conservation in some schools around São Paulo, but I knew my truly passion was to document whats left of our fauna and bring beautifull images to inspire people to protect our planet. I think BTM is the most complete and didatic channel about UW shooting, I’ve watched every youtube and Instagram videos and learned so much already! I think I would reach the “next step” if I could be part of the Academy. Would really be a game changer and primarily a life changer event.","ultimate_vision":"My ultimate goal is to bring light on misunderstood species such as sharks, whales and every sea animal facing real danger. My “style” would be documentary shooting.","hoped_gains":"A lot of game changing knowledge, unforgettable memories and connection with extreme skilles professionals.","why_good_candidate":"I think my prior overwater knowledge and experience will be a positive aspect to learn UW filming, although I know there are huge differences between them. I believe my biology knowledge can help a lot specially with sharks and rays (I have done scientific research and symposium presentations and volunteering underwater conservation jobs). Also I scubadive a lot (rescue diver) and study UW content every single day.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Rescue Diver","number_of_dives":"51-250","last_dive_date":"05.01.2026","diving_environments":["Tropical Reefs","Open water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":7,"referral_source":["Social Media (Instagram, Facebook, etc.)"]}'::jsonb, '{}', '[]'::jsonb, '2026-02-03T00:21:00+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Uber","last_name":"Mancin","email":"ubermancin@gmail.com","phone":"+393284151363","age":"43","gender":"Male","nationality":"italian","country_of_residence":"italy","languages":"English, Spanish, French, portuguese","online_links":"www.ubermancin.it","azores_ties":"no","current_occupation":"DOP - Cinematographer","education_level":"Bachelor''s degree","field_of_study":"documentary and video production","recent_activities":"jobs and interests","filmmaking_experience":"filming dives at baja california and clients for a diving center","filming_equipment":"gopro 12 , fuji xt4 with lenses, dji air 3","content_created":["Social media content","Documentary style","Commercial work","Scientific/Research documentation","Overwater photography"],"inspiration_to_apply":"My interest in underwater filming comes from a natural progression of my work as a cinematographer in challenging environments, such as mountains and remote locations, where safety, precision, and teamwork are essential. As a PADI Divemaster with a strong safety-focused background, I am motivated to combine my cinematic experience with professional underwater skills. I chose BTM Academy because of its reputation for high-level training, real-world production approach, and strong emphasis on safety, which I see as the ideal environment to grow into a competent and responsible underwater filmmaker and safety diver.","ultimate_vision":"My long-term vision is to become a well-rounded underwater filmmaker who combines strong cinematic storytelling with the highest safety standards. I aim to work on international film and documentary productions in challenging environments, contributing both creatively and operationally, while continuing to grow as a safety diver. Ultimately, I want to be part of teams that tell meaningful stories underwater with professionalism, responsibility, and respect for both people and the environment.","hoped_gains":"Through this internship, I hope to gain hands-on experience in real underwater film productions, learning directly from experienced professionals in both filming and safety operations. My goal is to deepen my technical underwater skills, better understand on-set workflows, and develop the discipline and decision-making required in complex environments. I also see this internship as an opportunity to grow as a team member, contribute actively, and build a solid foundation for a long-term career in underwater cinematography and safety diving.","why_good_candidate":"I believe I am a strong candidate because I bring together professional cinematography experience, a solid safety-oriented mindset, and certified diving skills as a PADI Divemaster. I am used to working in demanding environments, where preparation, adaptability, and teamwork are essential. Combined with my international experience, flexibility, and strong motivation to learn, I am confident I can contribute positively while growing within a professional underwater film team.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Divemaster","number_of_dives":"250+","last_dive_date":"22.09.2025","diving_environments":["Tropical Reefs","Open water","Cold water","Deep diving","Night diving"],"buoyancy_skill":10,"referral_source":["Online search"],"anything_else":"I am a professional cinematographer with strong experience in above-water productions and in challenging environments, where safety, planning, and teamwork are essential. I am a PADI Divemaster, used to working in international and multicultural teams, and I am highly motivated to develop my career in underwater filmmaking with a strong focus on safety and professionalism. In addition, I am a volunteer with Sea Shepherd Italy, and marine and ocean conservation is a core value in my work and personal motivation."}'::jsonb, '{}', '[]'::jsonb, '2026-02-06T11:53:09+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Ali","last_name":"Alabyadh","email":"ali.abdullah.alabyadh@gmail.com","phone":"+966531923094","age":"31","gender":"Male","nationality":"Saudi","country_of_residence":"Saudi Arabia","languages":"English, Arabic, and Intermediate Spanish, Beginner Portugese","online_links":"https://www.instagram.com/ali_de_la_isla/, https://www.alialabyadh.com/","azores_ties":"No","current_occupation":"PhD Candidate","education_level":"Master''s degree","field_of_study":"Marine Science, Geology","recent_activities":"Petroleum Geology Engineering 2019-2021, Studying marine biology from 2021 to present","filmmaking_experience":"Over the past four years, I have gained hands-on experience in underwater photography and filmmaking through field-based conservation and research work. I regularly film coral reefs, restoration activities, and marine life while leading a divers team during my PhD, which has strengthened my buoyancy, situational awareness, and ability to operate calmly in dynamic conditions. I have developed a decent post-production workflow using Lightroom and Premiere Pro to enhance visual storytelling. My experience has been shaped largely through practice, peer learning, and self-critique, driving a strong desire for structured mentorship and professional feedback.","filming_equipment":"I own a Sony a6400, Sigma 16mm, 16-50mm kit lens, Two Inon s220 strobes, Two LetonPower Turbo S Pro video lights, SaltedLine Underwater Housing and arms and clamps. I have also SmallRig cage, External monitor, ShotGun Microphone, Extra batteries. Two tripods. Traveling Case.","content_created":["Social media content","Scientific/Research documentation","Underwater photography"],"inspiration_to_apply":"The underwater world has always fascinated me, from massive coral formations to harmonic schools of fish and encounters with megafauna. I believe underwater filming is a powerful way to bring these experiences to people who may never witness them firsthand.\n\nA defining moment that reshaped how I approach underwater photography occurred when I photographed and filmed the complete mortality of coral reefs near my university. In the winter of 2024, we out-planted corals onto MARRS Reef Stars with optimism. By the following summer, extreme heat stress had killed those corals along with much of the surrounding reef. Returning to document reefs I once photographed as vibrant and flourishing was devastating, and it strengthened my commitment to documenting restoration, not only to support recovery, but to record what is at stake.\n\nIn the summer of 2025, witnessing and filming coral spawning during fieldwork restored a sense of hope: a new life cycle beginning and a reminder that resilience, though fragile, remains possible. I created a one-minute video using that spawning footage and shared it during the United Nations Ocean Conference in Nice 2025. The response came mainly from other early-career ocean professionals, which showed me the power of sharing these stories, but the process also revealed my own hesitancy to fully put myself out there creatively, particularly through voice and narrative presence.\n\nI am drawn specifically to Behind the Mask Academy because its values closely align with mine. BTM’s emphasis on observing, listening, documenting with transparency, and telling stories that are both respectful and engaging reflects how I aspire to work as a filmmaker. While I am proud of what I have achieved independently, I believe that structured learning, mentorship, and feedback within a community like BTM are what I need to grow to the next level.","ultimate_vision":"My vision is to become a hybrid conservation storyteller, combining scientific understanding with cinematic storytelling. I aim to bring the Red Sea to global audiences, not only showcasing its extraordinary beauty, but also highlighting the restoration and conservation efforts working to preserve it.\nI want to produce films that support science communication, advocacy, and long-term monitoring by returning to the same reefs over time and documenting change, recovery, and resilience. Through this work, I hope to create emotionally compelling, scientifically grounded stories that help audiences and stakeholders better understand what is being protected and why it matters.","hoped_gains":"Through watching BTM tutorials, I have already learned skills that noticeably improved my filming. Through this internship, I hope to refine those skills through structured professional training, hands-on experience,  continuous feedback and fruitful friendly discussions.\nFor me, success from this internship looks like becoming a scientist who produces wildlife documentaries that are both cinematic and scientifically sound. \nI am particularly interested in developing my ability to work with ambient light in challenging conditions, refine my technical decision-making underwater and topside, and improve color grading and editing for emotional impact. Most importantly, I want to strengthen my ability to translate scientific work into stories that are accurate and engaging without compromising integrity.","why_good_candidate":"Over the past four years, I have developed strong technical skills in underwater photography, filming, and post-production. Alongside this, I have been a lead diver in my lab for the past three years, responsible for dive planning, supervising daily operations, and ensuring long-term restoration objectives are met safely and efficiently.\nThis role has strengthened my adaptability, communication, and decision-making under variable environmental conditions, particularly while leading multinational teams with diverse technical backgrounds. With around 400 dives, I have developed strong buoyancy control, situational awareness, and problem-solving skills underwater which are all essential for effective filmmaking in dynamic environments.\nMy work in coral restoration has also required extensive logistical planning, including budgeting, procurement, material fabrication, storage, and training personnel. These experiences have made me resourceful, organized, and comfortable working in complex, real-world conditions.\nI see this internship as a step toward becoming a scientist who produces wildlife documentaries that are cinematic and scientifically rigorous  and I believe my background in research, diving leadership, and visual storytelling, positions me well to contribute meaningfully to the BTM Academy while continuing to grow within it in this internship.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Scientific Diving"],"certification_level":"Rescue Diver, AAUS Scientific Diver, Lead Diver","number_of_dives":"250+","last_dive_date":"07.02.2026","diving_environments":["Tropical Reefs"],"buoyancy_skill":9,"referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"How would BTM academy support participants in developing long term voice and direction in wildlife filmmaking beyond the period of the internship?"}'::jsonb, '{}', '[]'::jsonb, '2026-02-10T13:08:14+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Kyle","last_name":"Massie","email":"kyle@963filmgroup.com","phone":"7573103339","age":"32","gender":"Male","nationality":"American","country_of_residence":"USA","languages":"English","online_links":"@thalosfilms","azores_ties":"none","current_occupation":"Producer","education_level":"Bachelor''s degree","field_of_study":"Marine Science","recent_activities":"Video Production","filmmaking_experience":"2 seasons.","filming_equipment":"fx3 ikelight kraken 250000 sony g-master set","content_created":["Personal vacation videos","Social media content","Documentary style","Commercial work","Scientific/Research documentation","Overwater photography","Underwater photography"],"inspiration_to_apply":"looking for connections","ultimate_vision":"Marine Science based doc work","hoped_gains":"connections","why_good_candidate":"possibly.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Snorkeling"],"certification_level":"Advanced Open Water","number_of_dives":"0-50","last_dive_date":"16.08.2025","diving_environments":["Tropical Reefs","Open water","Night diving","Cave/Wreck diving"],"buoyancy_skill":8,"referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"none currently","anything_else":"I own Thalosfilms.com and 963nco.com"}'::jsonb, '{}', '[]'::jsonb, '2026-02-11T10:09:47+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Erell","last_name":"Guihard","nickname":"Ell","email":"erellguihard@gmail.com","phone":"+33685983535","age":"26","gender":"Female","nationality":"French","country_of_residence":"Malta","languages":"English, Spanish, French","online_links":"Youtube- https://www.youtube.com/@Sea_Tales\nInstagram- https://www.instagram.com/dandyblondie/","azores_ties":"No","current_occupation":"Underwater photographer, videographer and content cfreator","education_level":"Bachelor''s degree","field_of_study":"Literature, history and cinema","recent_activities":"Underwater photography, videography, content creation (2022-present) + teaching diving (2021-2025)","filmmaking_experience":"I started making short documentary reels on instagram 4 years ago, then kept on going with this for while! \nI then filmed \"To Each its Role on Living Reefs\" which was my first film! I published it in film festival and it got recognised and even won first prize in a festival in France.\n\nI then started a series called \"The Sea Tales\" on Youtube, with the first episode out \"Dazzling Gardians\" in 2025.\n\nSince then I''ve been making content for the dive center I work for, and have made their ads and marketing movies (used in dive shows)","filming_equipment":"Sony A6700\nNauticam NA-6700\nWide angle WWL-C Nauticam\nOrcatorch D910V x 2","content_created":["Social media content","Documentary style","Commercial work","Scientific/Research documentation","Overwater photography","Underwater photography"],"inspiration_to_apply":"I used to be terrified of the ocean, but ever since I was a child I knew that we fear the unknown. I educated myself through documentaries and many books and over the years my fear disappeared. Getting over my fear of the ocean made me see the beauty in it; making me want to protect it. \nThe more I learned, the more I realised that my fears mostly came from how the media portrayed the ocean; many representations are inaccurate and dramatised to create buzz and get attention for headlines. \nThis creates a general fear of the ocean which delays efforts for ocean conservation - understandably so: why protect something that you are scared of? This further disconnects today''s society and the sea. \n\nThis is why I got into underwater filming - I want to help guide others to take the same journey as I did in the hope that it will help conservation efforts and bridge the gap between us and the ocean. \n\nI''m mostly self taught so I had to find reliable and professional sources to learn from: that is how I found Behind the mask''s Youtube channel 4 years ago. I very often come back to this channel to refresh my skills and find inspiration for shots: which is why I am applying to this internship with you.","ultimate_vision":"I grew up watching \"The undersea world journal of Jacques Cousteau\", and I want to be able to recreate the wonder and magic that I felt in these moments. This series that Cousteau made was my version of Disney movies, they were my fairy tales. \nThey show how incredible the ocean is and made my heart pound out of my chest. \n\nMy dream in underwater film making is to be able to put to life a project that I hold very dear: a series of tales to rewrite the narrative that the oceans have been put through over the years by the media. \nI want to be able to create fairy tales out of the seas.","hoped_gains":"I''m mostly self taught and I know I am lacking in many aspects to create films, my knowledge is good but still too general to my taste: I want to master the basics, really understand the principles of filmmaking and photography.\n\nI would also love to see how professionals direct a film: from the planning of shots on land, to how they move underwater, how they direct a crew and how they communicate. I especially want to learn the post production side of film making and really understand how colour correction works.","why_good_candidate":"I think I would be a good candidate for the internship because I have a lot of diving experience under my belt (~3000 dives); I have been diving for 18 years and have been a professional since 2021. I am very diligent about safety and technique which allows me to learn fast underwater. \n\nI also have some experience in the film and photography industry: I was the photographer for The Jetlagged (film makers) when they were filming the ads for the launch of the new Suunto dive computer series (Nautic series). I got to see how they worked but only superficially as I had to focus on my own tasks.\n\nAlso, I am the photographer, videographer and content creator for a dive center in Malta,  which allows me to regularly use my camera, keeping my skills sharp and practice as much as possible.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Snorkeling"],"certification_level":"Instructor","number_of_dives":"250+","last_dive_date":"10.02.2026","diving_environments":["Tropical Reefs","Open water","Cold water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":10,"referral_source":["Online search"],"questions_or_concerns":"I was wondering how long the internship was, and if there was a possibility of improving in both photography and film making; as I love doing both.","anything_else":"It would be an incredible opportunity for me to learn from you at Behind the Mask, and I would love to be able to create the visions I have in mind in film making - with your mentoring I know I would be able to!"}'::jsonb, '{}', '[]'::jsonb, '2026-02-12T21:02:39+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Faisal Farooq","last_name":"Moosajee","nickname":"Faisal","email":"Faisal.moosajee@icloud.com","phone":"009607954444","age":"45","gender":"Male","nationality":"British","country_of_residence":"Maldives","languages":"English","online_links":"instagram.com/scubalicious.co","azores_ties":"No","current_occupation":"Scuba Dive Instructor","education_level":"High school diploma","field_of_study":"Business Information Technology","recent_activities":"Mainly teaching  scuba diving and working on underwater photo and video skills","filmmaking_experience":"I have spent time filming mantas and whale sharks in Hanifaru bay on point to shoot cameras .","filming_equipment":"Sony a7 r v , 16 - 35 mm lens and 100 mm macro lens","content_created":["Personal vacation videos","Underwater photography"],"inspiration_to_apply":"I have been following BTM for a while and I really like the way they present a video and the story telling of the marine animals.","ultimate_vision":"Since I started scuba diving 10 years ago I fell I love with it. I got my instructor certification and then started training people to scuba dive so people can realise how beautiful the underwater world is and we need to preserve it .","hoped_gains":"I need to learn more about the underwater photography and videography and educate my students about it .","why_good_candidate":"I believe that I have access to pass on what I learn and educate other people.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving"],"certification_level":"Instructor","number_of_dives":"250+","last_dive_date":"16.02.2026","diving_environments":["Tropical Reefs","Open water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":10,"referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"How long would the internship be ?"}'::jsonb, '{}', '[]'::jsonb, '2026-02-25T17:35:24+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Matteo","last_name":"Baratella","nickname":"Matt","email":"matteo.baratella@outlook.com","phone":"+393465238946","age":"30","gender":"Male","nationality":"Italian","country_of_residence":"Norway - Spain","languages":"English, Spanish, French, mother tongue Italian, basics of Norwegian and German","online_links":"https://matteobaratella.com/","azores_ties":"Yes, I do have connections in Faial, Azores. I spent a month living in Horta, Faial during the summer of 2025, while my girlfriend was working with Okeanos on marine conservation research programs. I actually arrived in the Azores that summer by sailing from Nice, France, a three-week journey across the Mediterranean and the Atlantic, where I had the chance to film fin whales with drone here is the video https://www.instagram.com/reel/DLYJOimMJoc/?utm_source=ig_web_copy_link&igsh=MzRlODBiNWFlZA==.\n\nThe previous summer, in 2024, I worked as an onboard photo reporter on the Portuguese schooner Santa Maria Manuela, creating marketing content for their expeditions. We sailed between several islands, exploring Faial, São Miguel, and Terceira.\n\nBefore joining the ship, I had been living in Maia, on the island of São Miguel, at a free camping site offered by a local firefighter named Eduardo. After the voyage, I spent time on the island of São Jorge, landing in Velas and hitchhiking to Topo with the help of the wonderfully generous local people.","current_occupation":"Audiovisual media and graphic design teacher in art schools. Video and photo freelancer. Visual Arts and Education Master degree student. Free diving student.","education_level":"Master''s degree","field_of_study":"Audiovisual Media double Master degree from Germany (Kiel) and Norway (Volda)","recent_activities":"Documentary filmmaking, documenting ocean-related (scientific) expeditions, teaching photo/video/design in arts schools, visual arts and education master’s studies in Granada, audiovisual arts teacher internship in private arts school in Granada, seasonal audiovisual arts teacher in Norway, sailing and freediving training, international travel, outdoor living, coastal camping, surfing, snorkeling, swimming. \n\nOver the past few years I have:\nStudied a master’s in Visual Arts and Education at the University of Granada.\nTaught photography, video, and design in art and audiovisual schools.\nWorked seasonally as audiovisual teacher in Norway from September to December each year.\nDeveloped documentary projects on maritime and coastal culture, including La Costa Habla and other ocean-related media.\nProduced media on sailing and scientific expeditions (photography, video, editing, social media, educational outreach).\nSpent extended periods sailing and living around the ocean, such as the One Ocean Expedition on Statsraad Lehmkuhl in 2025 or Darwin200 in Cape Verde in 2023.\nInvested significant time in freediving and apnea training, connecting it with audiovisual content creation.\nTraveled and lived abroad in several countries while maintaining an outdoor, ocean-centered lifestyle.","filmmaking_experience":"I’m about to kickstart my underwater photo/video experience by getting a Seafrogs housing for my Sony A7R V to shoot key sequences for the documentary I’m developing in Andalucía. I am planning to invest in housing and accessories out of my own pocket to build experience for my projects.\n\nAfter working closely as a marketing content creator for a dive center on Inishmore, Galway Bay, in team with a friend who was responsible for underwater shots during my diving training there in 2024, I’ve been overviewing her method to properly seal an aluminum housing for the Sony A7R IV, understanding on a theoretical level the mechanics and risks of floods.\n\nI have knowledge about problems involved with buoyancy, light behavior, and the main challenges of underwater photo and video.\n\nUp to now, most of my practical underwater footage has been shot with a GoPro while freediving and snorkeling in Italy, the Azores, and La Herradura (Granada), which gave me a solid first contact with framing and movement underwater.","filming_equipment":"Sony A7rV\n10mm f1.4 GM sony lens\n70-200mm f2.4 sony lens\n28-70mm f3.5 sony lens\n85mm 1.4 GM sony lens\n\nDJI Mavic 3 drone\n\nShotgun microphone Rode\nlavalier radio microphone \n\nNikon small travel tripod\n\nVintage photo flash\nRollei analog camera\nCanon analog camera\nPentax analog camera \n\nOwn hard drives for archive\nMacBook pro 16-inch - 64GB RAM\nAdobe CC cloud subscription\nDaVinci Resolve","content_created":["Social media content","Documentary style","Scientific/Research documentation","Overwater photography","drone photo and video making","marketing","customers testimonials"],"inspiration_to_apply":"I am more and more drawn to continue in ocean storytelling and media; this feels like a life path for me, and getting an internship in this environment would be a huge boost in both knowledge and networking. I am also increasingly interested in moving to islands like the Azores, Madeira, or the Canary Islands, as my work is getting more connected to dive centers, sailing, scientific expeditions. And the opportunity to tell stories about these wonderful places is perfectly fitting my future path. \n\nA friend of mine sent me your website first saying this fits you perfectly! And I can confirm this! I want to deepen my craft in underwater storytelling and surround myself with people who live and work in the ocean media world every day. The academy sits exactly where I want to be: between filmmaking, marine environments, and a community of professionals who can challenge and guide me. Joining this context would accelerate my learning curve and open doors that are hard to reach on my own from a purely freelance and academic path.\n\nI started getting drawn into underwater filming while learning to dive and experimenting with a GoPro in places like the Azores and the Andalusian coast; being under the surface made me realize how many stories are invisible from land. Over time, my documentary work and my time on expeditions pushed me toward the idea that my future is in creating ocean stories that connect communities, science, and culture. I chose BTM Academy because it offers structured, hands-on training with people who already work in this field, and because it feels like the right bridge between my current experience and a more professional, long-term career in ocean media.","ultimate_vision":"I want to gain these skills first out of a very personal interest, and then put them at the service of a wider, global audience. When I see strong underwater and ocean images, I feel how powerful they are: how much they communicate without a single word, just by looking.  Inspiring younger and older generations through ocean media has become a personal mission for me, after my experiences at sea, working on board as a documenter and doing science communication. I can see how important this work is for the future of the world and of people.\n\nA turning point for me was my first trip on the traditional lugger Grayhound from Pasaia in northern Spain to Gloucester in 2024. That voyage created a “before and after” in my life: it put my life on land into perspective and opened a completely new world for me. Communicating this change, and how positively it affected my mental health and sense of purpose, is a fundamental part of my ocean media projects. I want to show nature and the sea not only as something to protect, but as a powerful tool for personal well-being and connection.\n\nMy ultimate vision is to become a filmmaker who uses underwater images to connect people emotionally with the ocean, its cultures, and its hidden stories. I want to live close to the sea, ideally on islands like the Azores, Madeira, or the Canary Islands, and build long-term projects that document both marine life and the communities that live with it.  \n\nOver time, I imagine a body of work made of documentaries, short films, and educational pieces that travel internationally, used in schools, museums, and on board sailing ships. Through these projects, I want to promote ocean literacy, mental well-being through contact with nature, and a sense of global responsibility towards the sea.","hoped_gains":"I hope to gain three things from this internship.  \n\nFirst, I want to solidify my technical and narrative skills in underwater and ocean-focused storytelling, working alongside people who already do this every day and learning their workflows, safety culture, and creative processes. \n\nSecond, I want to understand how a professional ocean media project is built from the inside: from concept to logistics, fieldwork, post-production, and distribution, so I can better structure my own long-term projects on islands and coastal communities.\n\nThird, I am looking to build real relationships and a network in this field, connecting with mentors and collaborators who share the same mission of using ocean media to inspire and educate people of different generations around the world.\n\nSo in a sense technical and soft skills.","why_good_candidate":"I think I am a good candidate because my path has already been moving steadily into ocean storytelling, and the timing is right after several formative sea and media experiences. I have a solid base in documentary filmmaking, from camera work and sound to editing and storytelling, and I am now specializing more and more in ocean-related projects and kickstarting underwater images.\n\nI am used to working in challenging conditions at sea, adapting quickly, and taking responsibility for both technical gear and the people I am filming with. My experiences on sailing ships, expeditions, and coastal communities have given me maturity, teamwork skills, and a calm attitude under pressure.\n\nAt the same time, I bring genuine curiosity, empathy with the people I film, and a long-term commitment to using ocean media to inspire others, not just as a short adventure. I am ready to learn, to contribute creatively and practically, and to fully dedicate this phase of my life to growing inside this field.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Open Water","number_of_dives":"0-50","last_dive_date":"15.08.2024","diving_environments":["Open water","Cold water","shipwreck in Sao Miguel","cold water in Irish summer 13-6 degrees"],"buoyancy_skill":8,"referral_source":["Word of mouth"],"questions_or_concerns":"I would like to know more about the kind of projects interns get involved in: are we mostly assisting on existing productions, or is there space to develop small personal pieces under mentorship?\n\nI’m also curious about the balance between fieldwork and post-production/learning time, and whether there are any possibilities to stay connected or collaborate after the internship period ends, especially for long-term ocean storytelling projects.","anything_else":"I would like to add that I am currently a finalist for the Ocean Culture Life storytelling grant with my documentary project “La Costa Habla” (“The Coast Speaks”), which I am developing in Andalusia. This project is focused on coastal communities, traditional fishing culture, and our changing relationship with the sea, and I see it as the first step in a much longer journey in ocean media. \n\nLink to trailer https://youtu.be/zIi7-Jnq_i0\n\nI am fully committed to walking this path for the long term, and I see your internship as a key moment to grow, to give my best, and to connect my ongoing projects with a professional environment that shares the same values.\n\nI will now save this application text as a PDF and send it over to you via email with my CV and Portfolio in PDF formats also. \n\nThank you very much for what you are doing, it''s really awesome and inspiring and I am really excited to apply for this internship."}'::jsonb, '{}', '[]'::jsonb, '2026-02-27T11:38:03+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Annik","last_name":"Schlatter","email":"annik@schlatterfamily.ch","phone":"+41783411313","age":"21","gender":"Female","nationality":"Switzerland","country_of_residence":"Switzerland","languages":"English, German","current_occupation":"Divemaster and Whalewatching Guide","education_level":"High school diploma","field_of_study":"Outdoor Sports and Tourism connected with mountains and ocean","recent_activities":"After finishing high school, I started my Divemaster internship in Madeira. During the 2024/25 winter season, I worked as a ski instructor in Switzerland. Currently, I am back in Madeira, working as a Divemaster, skipper, whale-watching guide, and content creator for the company.\nAlongside this, I run my own jewellery business.","filmmaking_experience":"Shooting and cutting short reels for the company","filming_equipment":"GoPro","content_created":["Personal vacation videos","Social media content"],"inspiration_to_apply":"I love the ocean and diving. I enjoy creating videos and taking photos, although I know I still have a lot to improve. I want to show people how beautiful the ocean is and why it is worth protecting. That’s why I’m eager to develop my skills further, so I can truly capture and share the beauty of the ocean.","ultimate_vision":"I’m just getting started, but I want to show people the magical places our planet has to offer under the surface and inspire them to protect them.","hoped_gains":"I hope to gain knowledge about cameras and how to use them properly. I also hope to learn something about editing and cut the material afterwards.","why_good_candidate":"I am motivated, reliable, and curious, with a strong passion for the ocean. As a confident and experienced diver, I feel comfortable underwater and able to focus on learning and improving my photography/videography skills. I work well in teams, am open to feedback, and eager to learn — qualities that I believe make me a good candidate for this internship.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Divemaster","number_of_dives":"250+","last_dive_date":"28.02.2026","diving_environments":["Open water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":9,"referral_source":["Diving community"]}'::jsonb, '{}', '[]'::jsonb, '2026-02-28T22:34:37+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Sarah","last_name":"Abdelhamid","email":"We.sarah@gmail.com","phone":"+201226138428","age":"34","gender":"Female","nationality":"German","country_of_residence":"Egypt","languages":"English, German","online_links":"Wildsearenity","azores_ties":"No","current_occupation":"Freediving instructor","education_level":"Master''s degree","field_of_study":"Marine zoology","recent_activities":"Sustainability, marine conservation, freediving","filmmaking_experience":"Only as a model","filming_equipment":"iPhone 14pro with divevolk","content_created":["Social media content"],"inspiration_to_apply":"Would love to learn and gain experience in underwater filmmaking","ultimate_vision":"Making the unseen seen with an eye to details","hoped_gains":"Experience in filmmaking, storyline and capturing the beauty and threats of the ocean from micro to macro","why_good_candidate":"I’m a scientist and water person. I’m a scuba, freediving and mermaid instructor and specialized in coral reef ecosystems. The sea is my passion, it’s my home","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Instructor, Certified Freediver, specify level below, Aida and SSI advanced freediving instructor","number_of_dives":"250+","last_dive_date":"03.03.2026","diving_environments":["Tropical Reefs","Open water","Cold water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":10,"referral_source":["Boot Germany 2026"]}'::jsonb, '{}', '[]'::jsonb, '2026-03-04T07:19:18+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Kyla","last_name":"McLay","email":"kylamclayphoto@gmail.com","phone":"3109409505","age":"23","gender":"Female","nationality":"USA","country_of_residence":"United States","languages":"English","online_links":"https://www.instagram.com/kylamclay","azores_ties":"I don’t currently have accommodation or connections on Faial, and I’ve never been to the Azores before. I would be very excited to experience the area.","current_occupation":"Ocean Photographer and content creator","education_level":"High school diploma","field_of_study":"Marine biology (incomplete studies), ocean photography, and freediving. I originally studied marine biology before shifting my focus toward visual storytelling and ocean photography. My goal has been to use photography as a way to help people connect with marine life and the ocean. Now I’m hoping to expand that work into underwater filmmaking and learn how to tell these stories through motion and film.","recent_activities":"Over the past few years most of my time has been focused on ocean photography, freediving, and spending as much time in the water as possible documenting marine life. I grew up sailing and later worked as a sailing coach, which gave me a strong foundation being in and around the ocean from a young age. I’m also a Wave 3 freediver and a PADI Rescue Diver, which has helped me work safely in the water while photographing wildlife.\n\nAlong the way I’ve supported myself through ocean related work including ecotourism, guiding, and expedition opportunities. Those experiences have given me a lot of time in the field around marine wildlife while continuing to build my photography portfolio.\n\nIn the past few years I’ve focused on growing as an ocean photographer, building my portfolio, and sharing my work with a wider audience. My goal has always been to create images that help people feel connected to the ocean and the animals that live there.\n\nWhile photography has been the foundation of my work, I’m really interested in expanding into film. I see underwater filmmaking as the next step for turning my perspective as a photographer into deeper stories about the ocean and the wildlife I spend time documenting.","filmmaking_experience":"Most of my experience so far has been in underwater photography rather than filmmaking. I’ve spent a lot of time in the water photographing marine wildlife while freediving and working around animals like whales, dolphins, sharks, and rays. I’ve only just started getting into video recently and have barely begun learning DaVinci Resolve, so I’m still very new to the filmmaking side of things. That’s a big part of why this opportunity interests me. I’d love to learn how to turn the way I already see and photograph the ocean into stronger storytelling through film.","filming_equipment":"Underwater:\nCanon R5 Mark II\nRF 15–35mm f/2.8L IS USM\nSeaFrogs aluminum housing\n230mm glass dome port\nExternal monitor\nSeaFrogs video lights\n\nTopside:\nCanon R7\nRF 24–105mm\nRF 100–500mm f/4.5–7.1L IS USM\nDJI Mini 3 Pro drone","content_created":["Personal vacation videos","Social media content","Commercial work","Scientific/Research documentation","Overwater photography","Underwater photography"],"inspiration_to_apply":"I’ve spent the last several years focused on ocean photography, documenting marine wildlife and building a body of work around the ocean. Photography has been the foundation of how I share these experiences, but lately I’ve been feeling a pull to take my work beyond still images and social media and start telling deeper stories through film.\n\nWhen I was little I was completely obsessed with ocean documentaries like National Geographic and BBC Blue Planet (still am). I remember watching them and thinking that one day I wanted to be the person behind the camera filming those moments. That feeling has never really gone away.\n\nI’ve realized that if I want to move in that direction, it’s time for me to actually learn filmmaking. I have a lot of experience with photography and feel very comfortable working in the water with a camera, but video still feels like a completely different world to me. That’s a big reason why a mentorship like this is so appealing.\n\nBTM Academy stood out to me because it seems very focused on real experience in the ocean and learning alongside people who are actively working in underwater filmmaking. Being able to develop those skills in an environment centered around ocean storytelling would be an incredible next step for me.","ultimate_vision":"My long term goal is to create work that helps people feel connected to the ocean and the animals that live there. Through photography I’ve seen how powerful imagery can be in making people care about places and species they may never experience themselves, and I think film has the potential to take that even further.\n\nI know I’m still at the beginning of the filmmaking side of things, but an ultimate dream of mine would be to work on real ocean documentaries, the kind of films I grew up watching on National Geographic or BBC’s Blue Planet. Being part of a team documenting wildlife and telling meaningful stories about the ocean would be incredible.\n\nFor now my focus is on learning the craft of underwater filmmaking and building the skills needed to tell those kinds of stories. Photography has been my foundation, and I see filmmaking as the next step in growing as a storyteller in the ocean.","hoped_gains":"Right now I feel very comfortable working in the ocean with a camera through photography, but filmmaking is still really new for me. One of the main things I’d love to gain from this internship is learning the technical side of underwater videography. Things like camera settings for video, filming techniques underwater, color grading, and how to actually edit footage together.\n\nI’m also really interested in learning how to build a story through film. With photography I’m used to capturing individual moments, but film is a completely different way of thinking and I’d love to understand how to turn footage into something that actually tells a story.\n\nAnd if there’s any chance to learn a bit about the professional side of underwater filmmaking too, like how people turn this kind of work into a career or collaborate on bigger projects, that would be incredibly valuable.","why_good_candidate":"I think I’d be a good candidate because I’m at a point in my life where I’m fully committed to pursuing this path. I’m 23 and all in on building a career around the ocean and visual storytelling.\n\nOver the past few years I’ve worked really hard to grow my photography portfolio, build an audience of over 400k across platforms, and support myself through my work in ocean photography. That process has taken a lot of persistence and has made me even more motivated to keep pushing forward.\n\nI’m eager to keep learning and excited to start taking the next step in my career. My schedule is flexible and I’m ready to fully commit the time and energy needed if selected.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Rescue Diver, Certified Freediver, specify level below, Molchanovs wave 3 certified","number_of_dives":"51-250","last_dive_date":"03.03.2026","diving_environments":["Tropical Reefs","Open water","Cold water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":8,"referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"Thank you for your time. I’d love the opportunity to learn more about the internship and what it involves, and I look forward to hearing from you."}'::jsonb, '{}', '[]'::jsonb, '2026-03-13T11:55:32+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Raquel","last_name":"Sousa","nickname":"@tastola","email":"raquel.alexssousa@gmail.com","phone":"+351 931 822 914","age":"24 years old","gender":"Female","nationality":"Portuguese","country_of_residence":"Portugal","languages":"English, Spanish, Português","online_links":"https://www.youtube.com/@CANALB612\nhttps://santosproducoes.my.canva.site/\nhttps://www.instagram.com/tastola/","azores_ties":"Yes","current_occupation":"Photographer & Social media manager","education_level":"High school diploma","field_of_study":"Audiovisual & Multimedia","recent_activities":"Photography and social media","filmmaking_experience":"I used to be a profissional swimmer, dedicating all my time and life to that but as I got older I feel in life with photography and I think this is the best opportunity to combine my two passions","filming_equipment":"A 6400 Sony and GoPro 9","content_created":["Social media content","Documentary style","Overwater photography"],"inspiration_to_apply":"I’ve been following your work for the past two years, and since the very first day your company was recommended to me, I’ve recognized your vision and quality. I share the same love for the ocean and marine life.\nSince I was very young, I’ve had a deep passion for the aquatic environment, and although I swam professionally until I was 17, I believe the skills I developed now allow me to pursue new opportunities, such as becoming part of your team with both quality and genuine enthusiasm.\nI’ve always taken photographs, but at 15 I decided to share my vision with the world.\n\nI believe your work not only inspires people to discover the ocean, but also plays an important role in promoting respect for it, something I strive to reflect in my own work as well.","ultimate_vision":"What I’ve always sought is to tell stories, to create imaginary worlds in my mind and bring them to life. I believe there is great importance in imagination, and although my success has come from documentary photography, something less imaginary and more “real”, the ocean holds that ancestral quality of being something we can visualize without ever having a fixed “setting.”Its very existence offers the freedom to see beyond what is in front of us. Even as we grow familiar with it, we still feel the need to frame it within a greater meaning, to give it purpose. \n\nIn a way, I find myself crossing into this universe with the belief that I can be part of its story, by documenting it, respecting it, and helping to share it with others, creating a cycle of awareness that both the ocean and we, as people, deeply need.","hoped_gains":"Good friendships, meaningful time spent in the ocean, and of course, great footage, this is what I believe to be the beginning of another journey.","why_good_candidate":"Being young is not always synonymous with experience or professionalism when working as part of a team. However, I believe I am someone essential when it comes to materializing ideas, shaping them, framing them, and bringing them to life.I was born with a strong need to bring color into life, and although my sense of aesthetics is something inherent to who I am, \nI find the ocean at a moment in my life where I seek to learn more and fall in love with it all over again.","physical_fitness":"Good - Moderately active, no major health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Snorkeling","Neither","but interested in learning"],"certification_level":"No certification yet","number_of_dives":"0-50","last_dive_date":"09.03.2026","diving_environments":["Tropical Reefs"],"buoyancy_skill":1,"referral_source":["Diving community"],"questions_or_concerns":"I would like to know how long the internship is expected to last, and if there is anything I should have or prepare, should there be a possibility of joining you.","anything_else":"At the moment, in addition to continuing my work as a photographer and in social media, I feel a strong need to move forward with purposeful documentaries, work that carries more depth. \nI’m applying for this internship because, above all, you inspire me to pursue that path.I hope to see you soon,\nRaquel"}'::jsonb, '{}', '[]'::jsonb, '2026-03-17T10:41:20+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Rui Alexanre","last_name":"Gaspar Santos","nickname":"Nicas","email":"gaspar.nicas@gmail.com","phone":"+351 924 048 227","age":"25","gender":"Male","nationality":"Portuguese","country_of_residence":"Portugal","languages":"English, português","online_links":"http://www.youtube.com/@CANALB612","azores_ties":"Yeas, with Paulo and Lisa","current_occupation":"Artist and photographer/videographer","education_level":"High school diploma","field_of_study":"economics and communication","recent_activities":"Diving, cooking, photography and music","filmmaking_experience":"I have always been passionate about underwater photography, mainly because I am a freediver who has never spearfished, so my rewards have always been based on the beautiful pictures I capture. Even though I didn’t have the best equipment, I have always tried to make the most of what I had, using my GoPro and borrowing equipment whenever I could. I also love being on camera, and when I used to work on a liveaboard, I would always put on a show for the scuba diving clients.","filming_equipment":"Sony A6400, Sony A7II, GoPo 13 and some anolog cameras","content_created":["Personal vacation videos","Documentary style","Overwater photography"],"inspiration_to_apply":"I have worked directly with BTM, and I was deeply inspired by them. They were living my dream—being able to dive and document the underwater world from their own perspective.\nThe BTM Academy is a great opportunity for me to expand my knowledge, and I believe it would be great to bring my own style and artistic approach to the team. I want to learn, but also to contribute with different perspectives, grow as a creator, and go beyond my current limits. My ambitions are high, and that’s why I believe the BTM Academy is my next big step.","ultimate_vision":"As a freediver, you always want to go further and beyond your limits—that’s what I feel about underwater photography. I’ve been lucky enough to live in Portugal and to have a strong connection with the Azores. I’ve seen many beautiful things, and sometimes I feel a bit lonely because most people can’t truly feel what I feel underwater.\nWith photography, my ambition isn’t just to take the best picture in the underwater photography world. I want to go deeper and bring the ocean to people who don’t even dive—to show a world that only a few can reach, experience, and truly connect with.\nI would love to work with film photography underwater. It’s challenging and quite rare, but analog photography has been my passion since I was 17, when I started documenting teenage life. Now that I’m older and have developed a deep love for the ocean, I want to combine freediving with analog photography—to tell stories that only images can tell.","hoped_gains":"I believe this internship would be a great opportunity not only to develop my photography skills but also to gain a deeper understanding of this world. I want to learn more about the business side of underwater photography and explore new perspectives and ideas.\n\nIt’s not just about taking pictures underwater—it’s much more than that. It’s about real-world connections and goes far beyond social media. Anyone can be an underwater influencer, but only a few can become truly artistic directors and bring human creativity into the beautiful world of ocean life.","why_good_candidate":"As I mentioned before, I want to learn everything I can, but I also want to bring new perspectives to the table. I want to grow personally while feeling that I am making a real difference.\nI’m young, but I have already had the opportunity to work directly with BTM, and I believe I can be part of the team. Over the past four years, I have learned a lot about boats, the diving industry, and what people are truly looking for when they call themselves divers.\nIt’s impossible not to connect with the ocean; Some people just take a little more time. I want to bring the ocean to those who don’t dive. I want to share the feeling of peace I experience underwater with someone sitting next to me who has never dived before.\nThat, to me, is the most meaningful thing I can do as an artist—not just to observe art, but to become part of it. To connect deeply with nature and bring that connection outward, expressing what I believe is part of the true purpose of life.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Open Water, Certified Freediver, specify level below, FreeDiver AIDA Level 2","number_of_dives":"51-250","last_dive_date":"09.03.2026","diving_environments":["Tropical Reefs","Open water","Deep diving","Cave/Wreck diving"],"buoyancy_skill":7,"referral_source":["Diving community"],"questions_or_concerns":"no","anything_else":"You’ve seen me as a logistics manager, both on land and on a boat, and you’ve seen me as a cook. Now, I would like to show you what I can do as a freediving photographer."}'::jsonb, '{}', '[]'::jsonb, '2026-03-18T19:04:07+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Chloé","last_name":"Longère","email":"chloe.lngr@gmail.com","phone":"693885856","age":"22","gender":"Female","nationality":"French","country_of_residence":"Faial - Azores - Portugal","languages":"English, French","azores_ties":"I''m currently living in the Azores","current_occupation":"I am currently completing my Master’s thesis internship at the OKEANOS Institute of Marine Sciences (University of the Azores), based in Faial, where I study the population structure of whale sharks.","education_level":"Bachelor''s degree","field_of_study":"I am doing studies in marine ecology and I am currently finishing my Master’s degree in Biodiversity, Biology and Ecology, with a specialization in Tropical, Aquatic, Coastal and Island ecosystems.","recent_activities":"Over the past few years, I have mainly focused on my studies, while dedicating my free time to diving and hiking. During my Master’s, I lived on Reunion Island, where I regularly went scuba diving, snorkeling, and freediving with friends on weekends and holidays. I also spent time exploring the island by hiking and camping in the mountains.","filmmaking_experience":"Through my studies, I have gained experience in underwater filming, mainly for scientific data collection purposes. For example, I filmed whale sharks while freediving to later conduct photo-identification analyses, and recorded coral reef footage while snorkeling to assess coral cover at different sites.\nI also completed a professional scientific diving certification (CAH1B), during which I was trained to capture video data and to use underwater lighting effectively to improve image quality.\nBeyond academic work, I regularly film during my dives, snorkeling, or freediving.","filming_equipment":"I have a dji osmo action 6 camera","content_created":["Personal vacation videos","Scientific/Research documentation"],"inspiration_to_apply":"I have always been drawn to underwater videos, whether showing marine animals, habitats, or scenery. Every time I am in the water, I am amazed by what I see, and I want to be able to capture these moments. I am particularly motivated to improve my technical skills, both in filming and post-production, to create quality footage.\nBeyond the visual aspect, I see underwater filmmaking as a powerful tool for  outreach. Sharing what I have the opportunity to witness underwater is very important to me, and I believe it can raise awareness and encourage people to better understand and protect marine ecosystems.\n\nWhen I met Dada and she explained what she was doing, I was amazed because it was similar to the job I had dreamed of when I was little. I was also already familiar with some of Behind the Mask’s work that I had seen on Instagram while researching the Azores, which reinforced my interest in your projects.\nAlthough I chose to pursue a path in marine science, this opportunity feels like the chance to step into the field of underwater filmmaking and connect my studies to my creative side. \nI am motivated by the opportunity to contribute to sharing the underwater world with people who don’t necessarily have access to it and have little knowledge of it. In particular, I would like to help change the negative perception of sharks by showing them in their natural environment, in situations where they are not portrayed as evil, and by highlighting their ecological importance, which I believe can support their conservation.","ultimate_vision":"I have an academic background focused on marine research and conservation, and I am looking to learn new skills and explore new ways of engaging with the underwater world.\nMy long-term goal is to build a career that contributes to the conservation of tropical marine ecosystems through both scientific research and outreach. I would like to connect these two fields by integrating underwater filmmaking into my work, for example, by documenting research expeditions, daily fieldwork, and the realities of working in marine science.\nThrough this, I would like to make science more accessible and share the beauty, fragility, and importance of marine ecosystems, to encourage people to engage in marine protection.","hoped_gains":"I believe this internship would allow me to gain valuable hands-on experience and develop practical skills in underwater filmmaking. It would also be the opportunity to better understand the different parameters that influence underwater footage, and learn how to use them effectively to produce high-quality images within a production project.\nI also see this as a unique opportunity to learn from professionals with diverse backgrounds and experiences, but with a common interest in the underwater world. Building connections in this field would also be valuable for my future career.\n\nOverall, this internship would help me become more polyvalent by combining my scientific background with creative and technical skills, and it would be an important step toward achieving my goals.","why_good_candidate":"I think I could be a good candidate because of my background in marine ecology and my practical experience in the field. My knowledge of marine megafauna allows me to better understand animal behavior, habitats, and how to approach them respectfully, which I see as useful for underwater filming.\nIn addition, I have specific knowledge of the Azores, particularly regarding whale shark populations, which could be valuable in a local context.\nMy diving certifications and my freediving experiences, have made me very comfortable in the water. This allows me to stay focused on filming while remaining aware of my surroundings. \nI am also really motivated to learn, to be involved in real productions, and to contribute to your projects.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Technical Scuba diving","Professional scientific diving"],"certification_level":"Advanced Open Water, Rescue Diver, Divemaster, I have french certifications and I don''t really know the equivalent in PADI but I think it''s the close to a divemaster (that''s what the Dive Azores company told me). I''m a CMAS 3 star diver (autonomous diver to 60m) and I have the CAH1B (scientific diving to 30m)","number_of_dives":"51-250","last_dive_date":"15.10.2025","diving_environments":["Tropical Reefs","Open water","Cold water","Deep diving","Night diving"],"buoyancy_skill":9,"referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"As I’m currently doing my internship, I’m only available during the weekends and the holiday days. I was wondering whether it would still be possible to take part in the program with this schedule.","anything_else":"I’m already living in Faial (Horta) and I’m staying until the end of July."}'::jsonb, '{}', '[]'::jsonb, '2026-03-22T23:12:35+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Menna","last_name":"Khater","email":"mennakhater11@hotmail.com","phone":"+0201276599393","age":"41","gender":"Female","nationality":"Egyptian","country_of_residence":"Egypt","languages":"English, German, Arabic","azores_ties":"No","current_occupation":"Entrepreneur","education_level":"Bachelor''s degree","field_of_study":"Business Administration","recent_activities":"My past job as head of operations and general manager","filmmaking_experience":"No experience","filming_equipment":"No equipment","content_created":["None yet","excited to start"],"inspiration_to_apply":"I love diving and am a certified diver and I want to know more about this field","ultimate_vision":"To show how amazing and wonderful this is and help save this beautiful world alive and healthy","hoped_gains":"Skills and knowledge that could help me evolve and create great awareness within me and the world","why_good_candidate":"I just want to","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving"],"certification_level":"Advanced Open Water","number_of_dives":"51-250","last_dive_date":"01.08.2025","diving_environments":["Tropical Reefs","Open water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":7,"referral_source":["Social media"]}'::jsonb, '{}', '[]'::jsonb, '2026-03-24T21:59:24+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Lucia","last_name":"Tuzinska","nickname":"Lusea","email":"tuzenska@gmail.com","phone":"+421918396626","age":"38","gender":"Female","nationality":"Slovak","country_of_residence":"Prievidza","languages":"English, Spanish","online_links":"@tuzenska - www.svetlu.sk/home - www.lutu.photos","azores_ties":"not yet","current_occupation":"Freelancer","education_level":"Master''s degree","field_of_study":"Tourism and Intercultural Communication","recent_activities":"Sailing diving somatic workshops photography wriring a book maling reels","filmmaking_experience":"Just go pro unfortunately","filming_equipment":"Nikon Z - Nikkor 20-35-50-85 1.8s Gimbal Rs3","content_created":["Social media content","Documentary style","Commercial work","Overwater photography"],"inspiration_to_apply":"I feel strong urge to documents aliveness around the world, for others to notice what matters and I do believe and am told often that my perspective is unique.","ultimate_vision":"To tell stories from the underwater environment, it is necessary to perfect the craft of how to become natural with gear underwater and becoming the field. What attracts me the most is simplicity of being one with ocean, encountering life underwater in its pure form and working on meaningful projects with like-hearted people to be ambassador for this huge mystery on Earth.","hoped_gains":"Finally walking towards what my heart calls me to do. Feeling more comfortable with the gear underwater, learning those who are further on the path that I envision for myself and also future collaborations.","why_good_candidate":"I am very dedicated, reliable, fun and highly empathetic. And I do feel a lot of resonance with Behind the mask content and vision.","physical_fitness":"Good - Moderately active, no major health concerns","health_conditions":"Yes, but cleared by doctor for diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Open Water, Advanced Open Water, Certified Freediver, specify level below, Aida 2","number_of_dives":"51-250","last_dive_date":"25.03.2024","diving_environments":["Tropical Reefs","Open water","Deep diving","Night diving","Cave/Wreck diving"],"buoyancy_skill":8,"referral_source":["Social Media (Instagram, Facebook, etc.)"],"questions_or_concerns":"It was not clear for how long is the internship, so maybe that would be a question:)","anything_else":"I am also interested about options and conditions to cooperate with you guys and open to different forms in the future if Internship would not be the fit. Also interested if you could send me information regarding Zoe workshop!"}'::jsonb, '{}', '[]'::jsonb, '2026-03-25T06:09:55+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Rosa","last_name":"Tuiran","nickname":"Rosa","email":"tuiran.ra@gmail.com","phone":"+19172164365","age":"36","gender":"Female","nationality":"Mexico/U.S","country_of_residence":"United States","languages":"English, Spanish, French","online_links":"www.rosaamandatuiran.com","azores_ties":"No","current_occupation":"Journalist/Producer/Filmmaker","education_level":"Master''s degree","field_of_study":"Producer/Filmmaker","recent_activities":"Mostly the work I do as a producer and filmmaker, but also working on my scuba skills the past couple of years, getting my dive master, getting my underwater housing and camera.","filmmaking_experience":"I have mostly just filmed personal stuff, clips, etc on my own, on vacation, etc. I have filmed a few clips for a PBS Digital Studio piece about kelp forests, as well as the work I have done on board of a submersible with OceanX","filming_equipment":"Sony A7siii, Nauticam Housing with monitor (ultra 5HD), 90mm lens with macro port and Nauticam WWL-1B Wet Wide Lens with Float Collar with a Sony FE 28-60mm f/4-5.6 Lens","content_created":["Personal vacation videos","Documentary style","Scientific/Research documentation","Overwater photography","Underwater photography"],"inspiration_to_apply":"As a filmmaker and journalist, I’ve learned that storytelling is one of the most powerful tools we have to connect people to places, ideas, and information. My journey as a journalist began in the ocean. I remember being underwater for the first time when all of a sudden it all clicked for me. In that moment, I realized the immense privilege of experiencing a world so few ever get to see and how this incredible world needed to be seen, appreciated and protected. And from acknowledging that privilege, I’ve brought my passion to shine a light on the ocean and the people who depend on it. \n\nTo so many, the ocean is a distant, almost otherworldly place, a place that hides its most fascinating stories beneath. The ocean is our nourishment, protection, livelihood, and the air we breathe.","ultimate_vision":"My vision is to direct short and feature documentaries and work with outlets like PBS Nature, the BBC Natural History Unit, National Geographic, The New York Times, etc,  or emerging platforms where I can pitch, film, and produce stories about the intersection of people and the natural world. I also want to build a career as a freelance underwater cinematographer and photographer, with a particular focus on elevating stories from Mexico and Latin America and supporting Spanish-speaking filmmakers trying to find their footing in this space.\n\nAt the heart of it all is the ocean, the animals that inhabit it and the communities that depend on it. My goal is to produce incredibly rich work that communicates the urgent need for ocean conservation and everyone connected to it.The underwater world gave me my sense of purpose as a storyteller. This program would help me build the skills to fully pursue it.","hoped_gains":"I would love to see how professionals work in the industry, be mentored, see what works, what doesn''t, ask questions and learn about this field as much as possible. I think being out in the field is the best place to learn and its rare that opportunities like these exists. I want to be able to operate a camera underwater, assist if possible and get better at filming underwater. I want to leave with a much stronger foundation behind the underwater camera and a clearer sense of the professional standards this field demands. I also hope to be mentored. I''m at a stage in my career where having access to people who know how the industry work is the best way to make a career for myself and collaborate along the way.","why_good_candidate":"I think I am a good candidate for this internship because I am a storyteller and filmmaker above all. I''ve been telling stories for the past seven years, but I want to be able to film them underwater. I know how to identify a good story, how to build trust with people, and how to think about images with intention. I''m now at the point in my career where I want to bring all of that into the underwater space, and I''m really committed to putting in the work to get there. I am still willing to learn how to tell stories, and I want to learn from people and connect with others in the same field. I think this is an incredible opportunity and it would be incredible to have the chance to be a part of it.","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Freediving","Snorkeling"],"certification_level":"Divemaster, Certified Freediver, specify level below, PFI Certification","number_of_dives":"51-250","last_dive_date":"26.01.2026","diving_environments":["Tropical Reefs","Open water","Cold water","Night diving","Cave/Wreck diving"],"buoyancy_skill":7,"referral_source":["Word of mouth"]}'::jsonb, '{}', '[]'::jsonb, '2026-03-25T19:09:49+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('internship', 'reviewing', NULL, '{"first_name":"Nidhi","last_name":"Raj","email":"nidhiraj96@gmail.com","phone":"+393716737671","age":"29","gender":"Female","nationality":"Indian","country_of_residence":"India/Italy","languages":"English, Basic Italian","online_links":"Instagram- nidhiraj96","azores_ties":"No","current_occupation":"Filmmaker, video editor","education_level":"Master''s degree","field_of_study":"I just completed my master''s in Global studies for international cooperation. But by profession I''m into photography, videography and video editing.","recent_activities":"Freelancing, and my master''s degree in Italy.","filmmaking_experience":"I don''t have much underwater filmmaking experience other than shooting some videos from my GoPro while scuba diving and snorkeling. I have an open water scuba diving certificate.","filming_equipment":"Sony A7iii with 24-105mm lens which I use for my regular photo/video work. \nGoPro Hero 10","content_created":["Personal vacation videos","Social media content","Documentary style","Commercial work","Scientific/Research documentation"],"inspiration_to_apply":"Ever since I was a teenager, I''ve been fascinated by underwater photography and filming. At that time there were not many people who filmed underwater especially from India. I wanted to be the first indian female underwater photographer but I missed that boat. I finally got a chance to do my open water course in 2023 and I was mind blown. That''s when I decided I want to continue diving but in an intention way. I want to get into marine conservation, research and documentation (something that I studied during Master''s)","ultimate_vision":"Documentaries and storytelling is my passion. I want to bring less know/untold stories about the ocean to the masses. I also want to contribute in marine protection and conservation and I want to do that my visual documentation of the underwater.","hoped_gains":"I''m hoping to gain perspective and knowledge about this field and get hands on experience about uw filming.","why_good_candidate":"I am highly adaptable, a quick learner. I always find myself making myself useful wherever I am.","physical_fitness":"Good - Moderately active, no major health concerns","health_conditions":"No health conditions affecting diving","diving_types":["Recreational Scuba diving","Snorkeling"],"certification_level":"Open Water","number_of_dives":"0-50","last_dive_date":"24.08.2025","diving_environments":["Open water"],"buoyancy_skill":5,"referral_source":["Social Media (Instagram, Facebook, etc.)"],"anything_else":"Short films & Documentary:\n\nhttps://youtube.com/playlist?list=PLR82_ZyKDcpSIYOMqzgjn1SNKGLH-0IPq\n\nAd films and social campaign videos:\n\nhttps://drive.google.com/file/d/1vtxU5HszRKe8JMEIWzrq9QQovX9RL1Wn/view?usp=sharin\ng\nhttps://drive.google.com/file/d/1ybLYkQ-iQwiGv6G1XZiLfYGdsnQnOn57/view?usp=drive_lin\nk\nhttps://drive.google.com/file/d/1EeUcx-g8LzzvLoOJWvGtQse8O6QvRHM_/view?usp=drive_l\nink"}'::jsonb, '{}', '[]'::jsonb, '2026-04-02T04:15:13+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('freediving', 'reviewing', NULL, '{"first_name":"Donata","last_name":"Kidikaite","email":"d.kidikaite@gmail.com","phone":"+447403152557","age":"35-44","gender":"Female","nationality":"Lithuanian","country_of_residence":"Egypt","languages":"English","current_occupation":"Freediving instructor","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting freediving","certification_level":"Freediving Instructor","number_of_sessions":"250+","practice_duration":"> 2 years","last_session_date":"30.01.2026","comfortable_max_depth":"55","breath_hold_time":"4:00","personal_best":"4:30","diving_environments":["Tropical Reefs","Open water","Pool","Deep pool","Deep diving"],"performance_experience":"Less than 1 year","land_movement_sports":"Yoga","choreography_experience":"No","filmed_underwater":"Yes, little experience","comfort_without_dive_line":10,"comfort_without_fins":8,"comfort_without_mask":8,"freediving_equipment":"Full equipment","btm_category":"INDEPENDENT CREATOR (Experienced hobbyist/influencer seeking improvement)","online_presence":"Active social media","online_links":"IG - donata.kid","primary_goal":"Improve content creation for social media","secondary_goal":"Enhance existing professional skills","learning_aspects":["Body awareness","Soul-body connection","Marine life behavior understanding","Techniques for expressive underwater movement","Creating individual movements sequences and choreography","Creative self-expression","Business aspects of underwater performance"],"learning_approach":"Mixed approach (combination of group and individual)","professional_material_purpose":"Yes, for commercial purposes","time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Depends on duration and location","budget":"Very limited budget. I basically have no financial means to be spent on this.","start_timeline":"Flexible/Not sure yet","ultimate_vision":"As a freediving instructor I wish to inspire others to connect with water and marine life","inspiration_to_apply":"Because BTM is so inspiring and eye opening to what is possible.","referral_source":["Social Media (Instagram, Facebook, etc.)"]}'::jsonb, '{}', '[]'::jsonb, '2026-02-01T06:20:17+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('freediving', 'reviewing', NULL, '{"first_name":"Anna","last_name":"Romańczuk","nickname":"Ania","email":"romanczuk.an@gmail.com","phone":"+48 513439898","age":"25-34","gender":"Female","nationality":"Polish","country_of_residence":"Poland","languages":"English, Spanish","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting freediving","certification_level":"AIDA 3 or equivalent, SSI level 2","number_of_sessions":"51-250","practice_duration":"> 2 years","last_session_date":"05.12.2025","comfortable_max_depth":"My PB is 35, currently my comfortable max depth would be around 30m","breath_hold_time":"My PB (static) is 4 minutes. Currently comfortable breath-hold time (static) would be around 3 minutes","personal_best":"Static breath hold - 4 minutes. Depth - 35 meters","diving_environments":["Tropical Reefs","Open water","Pool","Deep pool","Deep diving","Night diving"],"performance_experience":"1-3 years","land_movement_sports":"All of the above :)","choreography_experience":"Yes, extended experience","filmed_underwater":"Yes, extended experience","comfort_without_dive_line":10,"comfort_without_fins":10,"comfort_without_mask":10,"freediving_equipment":"Freediving: masks, snorkel, nose clip, belt with weights, fins. Scuba diving: mask, snorkel, fins, wetsuit (short 3mm, long 5mm)","btm_category":"INDEPENDENT CREATOR (Experienced hobbyist/influencer seeking improvement)","online_presence":"Active social media, Professional portfolio","online_links":"instagram.com/a.nnkya\ninstagram.com/romanczuk.waterart","primary_goal":"Enhance existing professional skills","secondary_goal":"Enjoy the community, network and socialise with likeminded people","learning_aspects":["Body awareness","Marine life behavior understanding","Sensitive marine wildlife interactions","Techniques for expressive underwater movement","Creating individual movements sequences and choreography","Creative self-expression","Business aspects of underwater performance"],"learning_approach":"Group workshops (within a group of approx. 10 persons), Small group workshop (within a group of approx. 4 persons), One-on-one mentorship, Mixed approach (combination of group and individual), Project-based learning (within a BTM project)","professional_material_purpose":"Yes, for personal/travel memories","time_availability":"2-3 entire weeks at a time for a workshop, a project or individual training","travel_willingness":"Yes, willing to travel internationally","budget":"Advanced budget (3,000 - 6,000 €/USD)","start_timeline":"Flexible/Not sure yet","ultimate_vision":"I love water in any form. My life was always focused on it - I sail, I''m a lifeguard, I love diving both as scuba and as freediver. Being under water gives me this amazing feeling of calmness and being in the right place. Experiencing it while dancing and moving under water makes me feel for a second, like I''m a natural part of this environment. \nI not only want to experience it by myself, but I want to share it with people and show how amazing, unrevealed environment oceans are. That it''s something worth preserving and discovering in a friendly, non-destructive way.","inspiration_to_apply":"Dance and movement was always a part of my reality. When I discovered freediving, it all combined together naturally.\nBTM seems like a place where I can learn so much, but also offer my engagement and full dedication. When I do something, I do it with 100% dedication and I love to be around people who feels the same :) \nSaying that, I also can guarantee that I''ll do my best to meet your requirements and if my PBs are not enough, I''ll put my full attention on catching up :)","referral_source":["Social Media (Instagram, Facebook, etc.)"],"anything_else":"My husband applied to the underwater photography program, and it would be great if we could share this adventure together :)"}'::jsonb, '{}', '[]'::jsonb, '2026-02-02T22:06:26+00:00');
INSERT INTO applications (program, status, user_id, answers, tags, admin_notes, submitted_at) VALUES ('freediving', 'reviewing', NULL, '{"first_name":"Stephanie","last_name":"Suciu","email":"Stephanie.suciu@gmail.com","phone":"+351914892298","age":"35-44","gender":"Female","nationality":"Belgium","country_of_residence":"Portugal","languages":"English, French","current_occupation":"PhD in marine biology","physical_fitness":"Excellent - Regular exercise, no health concerns","health_conditions":"No health conditions affecting freediving","certification_level":"AIDA 2 or equivalent","number_of_sessions":"51-250","practice_duration":"> 5 years","last_session_date":"10.01.2026","comfortable_max_depth":"-20","breath_hold_time":"3min static / 50m dynamic","personal_best":"3:35min static / 65m dynamic","diving_environments":["Tropical Reefs","Open water","Pool","Deep pool","Cold water"],"performance_experience":"3-5 years","land_movement_sports":"Yoga","choreography_experience":"Yes, little experience","filmed_underwater":"Yes, little experience","comfort_without_dive_line":9,"comfort_without_fins":9,"comfort_without_mask":6,"freediving_equipment":"Cressi fins, from 2mm Ripcurl spring suit to 5mm wetsuit, cressi nanomask, belt","btm_category":"INDEPENDENT CREATOR (Experienced hobbyist/influencer seeking improvement)","online_presence":"Active social media, Personal website","online_links":"Instagram: @stevanille and @moniceph.azores\nWebsite: i have just created my association “Ocean Breath” (conservation, and awareness through art and well being) so a website is under creation","primary_goal":"Transform hobby into professional career","secondary_goal":"Enjoy the community, network and socialise with likeminded people","learning_aspects":["Techniques for expressive underwater movement","Creating individual movements sequences and choreography","Creative self-expression","Business aspects of underwater performance"],"learning_approach":"Small group workshop (within a group of approx. 4 persons), Mixed approach (combination of group and individual), Project-based learning (within a BTM project)","professional_material_purpose":"Yes, for personal/travel memories","time_availability":"1 week to 10 days for a workshop, a project or individual training","travel_willingness":"Depends on duration and location","budget":"Moderate budget (1,000 - 3,000 €/USD)","start_timeline":"Flexible/Not sure yet","ultimate_vision":"I have worked on and in the water as a biologist, and I am also a yoga teacher, i love mouvements and expression. Water is my safe space. I would love to merge my both worlds to create new projects, communicate or integrate it in ocean conservation and environmental awareness.","inspiration_to_apply":"I love water, mouvements and art. I have a scientific background but I’m also very sensitive and curious.","referral_source":["Julie Gauthier"],"anything_else":"Offering something in the Azores or Nemo 33 (Brussels) would be lovely:)"}'::jsonb, '{}', '[]'::jsonb, '2026-02-03T21:38:14+00:00');
